import React, { useState } from 'react';
import { useGame } from '../../../context/GameContext';
import DialogueBox from '../../DialogueBox';
import { Store, Heart } from 'lucide-react';
import { getAssetUrl } from '../../../utils';
import { useShop } from './hooks/useShop';

// Sub-components
import { ShopSign } from './ui/ShopSign';
import { AnimatedMercenary } from '../../common/ui/AnimatedMercenary';
import { CustomerHUD } from './ui/CustomerHUD';
import { ShopQueueBadge } from './ui/ShopQueueBadge';
import { ShopClosedOverlay } from './ui/ShopClosedOverlay';
import { InstanceSelectorPopup } from './ui/InstanceSelectorPopup';

interface ShopTabProps {
    onNavigate: (tab: any) => void;
}

const ShopTab: React.FC<ShopTabProps> = ({ onNavigate }) => {
  const { state, actions } = useGame();
  const shop = useShop();
  const [counterImgError, setCounterImgError] = useState(false);

  // 튜토리얼 중 상점 열기 단계인지 확인
  const isOpeningStep = state.tutorialStep === 'OPEN_SHOP_SIGN_GUIDE';

  // MainGameLayout에서 글로벌로 처리하는 튜토리얼 대화 단계인지 확인 (Shop 인트로만 해당)
  const isGlobalTutorialDialogue = state.tutorialStep === 'SHOP_INTRO_DIALOG';

  return (
    <div className="relative h-full w-full bg-stone-900 overflow-hidden flex flex-col items-center justify-center">
        {/* Background Layer */}
        <div className="absolute inset-0 z-0">
            <img 
                src={getAssetUrl('shop_bg.jpeg', 'bg')} 
                className="absolute top-0 opacity-60 w-full h-full object-cover"
                onError={(e) => { e.currentTarget.style.display = 'none'; e.currentTarget.parentElement!.style.background = 'linear-gradient(to bottom, #292524, #1c1917)'; }}
            />
        </div>

        {/* Floating Sign */}
        <ShopSign 
            isOpen={shop.isShopOpen} 
            onToggle={shop.handlers.handleToggleShop} 
            disabled={shop.isTutorialActive && !isOpeningStep}
        />

        {/* UI Elements: Queue & HUD */}
        {shop.isShopOpen && shop.dialogueState && (
            <>
                <ShopQueueBadge count={shop.shopQueue.length} />
                {shop.activeCustomer && (
                    <CustomerHUD 
                        mercenary={shop.activeCustomer.mercenary} 
                        refusalReaction={shop.refusalReaction} 
                    />
                )}
            </>
        )}

        {/* Character Stage - Anchored to bottom of ShopTab */}
        <div className="absolute inset-0 z-10 w-full h-full flex flex-col items-center justify-end pointer-events-none">
        {shop.isShopOpen && shop.activeCustomer && shop.dialogueState && (
            <div className="relative flex justify-center items-end w-full h-full animate-in fade-in zoom-in-95 duration-700 ease-out">
                <div className="relative w-full h-[80%] flex items-end justify-center">
                    {shop.floatingHearts.map((heart) => (
                    <Heart
                        key={heart.id}
                        className="absolute animate-heart fill-pink-500 text-pink-400 drop-shadow-[0_0_12px_rgba(236,72,153,0.8)] z-0"
                        style={{
                        left: `${heart.left}%`,
                        bottom: '40%',
                        width: heart.size,
                        height: heart.size,
                        animationDelay: `${heart.delay}s`,
                        '--wobble': `${(Math.random() - 0.5) * 60}px`,
                        } as React.CSSProperties}
                    />
                    ))}

                    <AnimatedMercenary
                        mercenary={shop.activeCustomer.mercenary}
                        className={`h-full w-auto object-contain object-bottom filter drop-shadow-[0_0_100px_rgba(0,0,0,0.95)] transition-all duration-500 relative z-10 ${
                            shop.refusalReaction === 'ANGRY' ? 'brightness-50 sepia-50' : ''
                        }`}
                    />

                    <div className="absolute bottom-10 left-1/2 -translate-x-1/2 w-80 h-16 bg-black/60 blur-3xl rounded-full -z-10"></div>
                </div>
            </div>
        )}
        </div>

        {/* Shop Counter */}
        <div className="absolute bottom-0 w-full h-[35dvh] md:h-64 z-20 flex items-end justify-center pointer-events-none">
            {!counterImgError ? (
                <img 
                    src={getAssetUrl('shop_counter.png', 'bg')} 
                    className="w-full h-full object-cover object-top filter drop-shadow-[0_-30px_50px_rgba(0,0,0,0.8)]"
                    onError={() => setCounterImgError(true)}
                />
            ) : (
                <div className="w-full h-full bg-[#3f2e22] border-t-2 md:border-t-[8px] border-[#5d4037] shadow-[0_-40px_60px_rgba(0,0,0,0.85)] relative overflow-hidden">
                    <div className="absolute inset-0 opacity-20" style={{ backgroundImage: 'repeating-linear-gradient(45deg, transparent, transparent 10px, #000 10px, #000 12px)' }}></div>
                </div>
            )}
        </div>

        {/* Dialogue Box Container - Unified 표준 규격 적용 */}
        <div className="absolute bottom-6 md:bottom-12 left-1/2 -translate-x-1/2 w-[92vw] md:w-[85vw] max-w-5xl z-50 flex flex-col items-center pointer-events-auto">
            {/* 튜토리얼 전역 대화창이 떠있을 때는 로컬 대화창을 숨김 */}
            {shop.isShopOpen && shop.dialogueState && !isGlobalTutorialDialogue && (
                 <DialogueBox 
                    speaker={shop.dialogueState.speaker}
                    text={shop.dialogueState.text}
                    options={shop.dialogueState.options}
                    highlightTerm={(shop.dialogueState as any).highlightTerm}
                    itemDetail={(shop.dialogueState as any).itemDetail}
                    className="w-full relative pointer-events-auto"
                />
            )}
        </div>

        {/* Modals & Overlays */}
        <InstanceSelectorPopup 
            show={shop.showInstanceSelector}
            onClose={() => shop.handlers.setShowInstanceSelector(false)}
            matchingItems={shop.matchingItems}
            selectedInstance={shop.selectedInstance}
            onSelect={shop.handlers.setSelectedInstance}
            onSell={shop.handlers.executeSell}
            onToggleLock={(id) => actions.toggleLockItem(id)}
            customerMarkup={shop.activeCustomer?.request.markup || 1.25}
        />

        <ShopClosedOverlay 
            isOpen={shop.isShopOpen}
            onNavigate={onNavigate}
        />

        {shop.isShopOpen && !shop.activeCustomer && (
            <div className="absolute inset-0 z-20 flex flex-col items-center justify-center pointer-events-none pb-20">
                <div className="text-center animate-in fade-in zoom-in duration-1000">
                    <div className="w-20 h-20 md:w-28 md:h-28 bg-black/40 rounded-full flex items-center justify-center mx-auto mb-4 border border-white/10 backdrop-blur-xl shadow-inner">
                        <Store className="w-10 h-10 md:w-12 md:h-12 text-stone-700 animate-pulse" />
                    </div>
                    <h3 className="text-lg md:text-2xl font-black text-stone-500 uppercase tracking-[0.3em] opacity-40">Awaiting Customers</h3>
                </div>
            </div>
        )}
    </div>
  );
};

export default ShopTab;

import React, { useState } from 'react';
import { Save, Upload, Volume2, VolumeX, LogOut, X, Settings, Layout, Check, Music, Zap } from 'lucide-react';
import { useGame } from '../../context/GameContext';
import SaveLoadModal from './SaveLoadModal';
import { loadFromSlot } from '../../utils/saveSystem';
import ConfirmationModal from './ConfirmationModal';
import { SfxButton } from '../common/ui/SfxButton';

interface SettingsModalProps {
    isOpen: boolean;
    onClose: () => void;
    onQuit?: () => void;
    onLoadRequest?: (data: any, depth: number) => void;
    isTitleView?: boolean;
}

const SettingsModal: React.FC<SettingsModalProps> = ({ isOpen, onClose, onQuit, onLoadRequest, isTitleView = false }) => {
    const { state, actions } = useGame();
    const [slModal, setSlModal] = useState<{ isOpen: boolean, mode: 'SAVE' | 'LOAD' }>({ isOpen: false, mode: 'SAVE' });
    const [loadConfirm, setLoadConfirm] = useState<{ isOpen: boolean, data: any, index: number | null }>({
        isOpen: false,
        data: null,
        index: null
    });

    const APP_VERSION = "0.1.43a";
    if (!isOpen) return null;

    const audio = state.settings.audio;

    const handleSlotAction = (slotIndex: number) => {
        if (slModal.mode === 'SAVE') {
            actions.saveGame(slotIndex);
        } else {
            const data = loadFromSlot(slotIndex);
            if (data) {
                if (data.version !== APP_VERSION) {
                    actions.showToast(`Load Failed: Version mismatch.`);
                    return;
                }
                setLoadConfirm({ isOpen: true, data, index: slotIndex });
            }
        }
    };

    const VolumeSlider = ({ label, value, icon: Icon, onChange, disabled }: { label: string, value: number, icon: any, onChange: (v: number) => void, disabled?: boolean }) => (
        <div className={`flex flex-col gap-1.5 p-3 rounded-xl border transition-all w-full ${disabled ? 'bg-stone-900/40 border-stone-800/50 opacity-40 grayscale' : 'bg-stone-800/40 border-stone-700/50'}`}>
            <div className="flex justify-between items-center">
                <div className="flex items-center gap-2">
                    <Icon className={`w-3.5 h-3.5 ${!disabled && value > 0 ? 'text-amber-500' : 'text-stone-600'}`} />
                    <span className="text-[9px] font-black text-stone-400 uppercase tracking-widest">{label}</span>
                </div>
                <span className="text-[9px] font-mono font-bold text-stone-500">{Math.round(value * 100)}%</span>
            </div>
            <input 
                type="range" min="0" max="1" step="0.01" 
                value={value} 
                disabled={disabled}
                onChange={(e) => !disabled && onChange(parseFloat(e.target.value))}
                className={`w-full h-2.5 bg-stone-900 rounded-lg appearance-none cursor-pointer accent-amber-600 ${disabled ? 'cursor-not-allowed' : ''}`}
            />
        </div>
    );

    return (
        <>
            <div className="fixed inset-0 z-[1500] flex items-center justify-center bg-black/90 backdrop-blur-md px-[10%] py-[15%] animate-in fade-in duration-200 overflow-hidden">
                <div className="bg-stone-900 border-2 border-stone-700 rounded-3xl w-[90vw] max-w-[420px] h-fit max-h-full min-h-[200px] min-w-[280px] shadow-2xl flex flex-col overflow-hidden animate-in zoom-in-95 duration-200 mx-auto text-left">

                    <div className="flex items-center justify-between p-5 border-b border-stone-800 bg-stone-850 shrink-0">
                        <div className="flex items-center gap-3">
                            <Settings className="w-6 h-6 text-amber-500 animate-spin-slow" />
                            <h3 className="font-bold font-serif uppercase tracking-widest text-base text-stone-100">System Menu</h3>
                        </div>
                        <SfxButton onClick={onClose} className="p-1.5 hover:bg-stone-800 rounded-full text-stone-500 transition-colors"><X className="w-6 h-6" /></SfxButton>
                    </div>

                    <div className="flex-1 p-5 space-y-6 overflow-y-auto custom-scrollbar">
                        {!isTitleView && (
                            <div className="space-y-2">
                                <h4 className="text-[9px] font-black text-stone-500 uppercase tracking-widest px-1">Persistence</h4>
                                <div className="flex flex-col gap-2.5">
                                    <SfxButton onClick={() => setSlModal({ isOpen: true, mode: 'SAVE' })} className="w-full flex items-center gap-4 p-4 rounded-xl border border-stone-700 bg-stone-800 hover:border-amber-500 hover:bg-stone-750 text-stone-300 transition-all shadow-md active:scale-95">
                                        <Save className="w-5 h-5 text-amber-500" /><div className="flex flex-col items-start leading-none"><span className="font-black text-[11px] uppercase tracking-widest">Manual Save</span><span className="text-[8px] text-stone-500 uppercase font-bold mt-1">Record progress</span></div>
                                    </SfxButton>
                                    <SfxButton onClick={() => setSlModal({ isOpen: true, mode: 'LOAD' })} className="w-full flex items-center gap-4 p-4 rounded-xl border border-stone-700 bg-stone-800 hover:border-stone-500 hover:bg-stone-750 text-stone-300 transition-all shadow-md active:scale-95">
                                        <Upload className="w-5 h-5 text-indigo-400" /><div className="flex flex-col items-start leading-none"><span className="font-black text-[11px] uppercase tracking-widest">Restore Data</span><span className="text-[8px] text-stone-500 uppercase font-bold mt-1">Load records</span></div>
                                    </SfxButton>
                                </div>
                            </div>
                        )}

                        <div className="space-y-3">
                            <div className="flex items-center justify-between px-1">
                                <h4 className="text-[9px] font-black text-stone-500 uppercase tracking-widest">Audio Engine</h4>
                                <SfxButton sfx="switch" className="flex items-center gap-2" onClick={() => actions.updateSettings({ audio: { ...audio, masterEnabled: !audio.masterEnabled } })}>
                                    <span className="text-[8px] font-black text-stone-600 uppercase">{audio.masterEnabled ? 'ENABLED' : 'MUTED'}</span>
                                    <div className={`w-8 h-4 rounded-full p-0.5 transition-all duration-300 ${audio.masterEnabled ? 'bg-amber-600' : 'bg-stone-800'}`}><div className={`w-3 h-3 bg-white rounded-full transition-all duration-300 ${audio.masterEnabled ? 'translate-x-4' : 'translate-x-0'}`} /></div>
                                </SfxButton>
                            </div>
                            <div className="flex flex-col gap-2.5">
                                <VolumeSlider label="Master Output" value={audio.masterVolume} disabled={!audio.masterEnabled} icon={audio.masterEnabled && audio.masterVolume > 0 ? Volume2 : VolumeX} onChange={(v) => actions.updateSettings({ audio: { ...audio, masterVolume: v, masterEnabled: v > 0 } })} />
                                <VolumeSlider label="Music Tracks" value={audio.musicVolume} disabled={!audio.masterEnabled} icon={Music} onChange={(v) => actions.updateSettings({ audio: { ...audio, musicVolume: v, musicEnabled: v > 0 } })} />
                                <VolumeSlider label="Sound Effects" value={audio.sfxVolume} disabled={!audio.masterEnabled} icon={Zap} onChange={(v) => actions.updateSettings({ audio: { ...audio, sfxVolume: v, sfxEnabled: v > 0 } })} />
                            </div>
                        </div>

                        <div className="space-y-2">
                            <h4 className="text-[9px] font-black text-stone-500 uppercase tracking-widest px-1">Interface</h4>
                            <SfxButton sfx="switch" className="w-full bg-stone-800/60 border border-stone-700 rounded-xl p-4 flex items-center justify-between group" onClick={() => actions.updateSettings({ showLogTicker: !state.settings.showLogTicker })}>
                                <div className="flex items-center gap-3"><Layout className="w-5 h-5 text-indigo-400" /><div className="flex flex-col items-start"><span className="font-black text-xs uppercase tracking-widest text-stone-200">Header Logs</span><span className="text-[9px] text-stone-500 uppercase font-bold">Show/Hide Log Ticker</span></div></div>
                                <div className={`w-10 h-6 rounded-full p-1 transition-all duration-300 ${state.settings.showLogTicker ? 'bg-amber-600' : 'bg-stone-900 border border-stone-700'}`}><div className={`w-4 h-4 bg-white rounded-full shadow-md transition-all duration-300 ${state.settings.showLogTicker ? 'translate-x-4' : 'translate-x-0'}`} /></div>
                            </SfxButton>
                        </div>

                        {!isTitleView && onQuit && (
                            <div className="pt-2 pb-4">
                                <SfxButton onClick={onQuit} className="w-full flex items-center gap-4 p-4 rounded-xl border border-stone-700 bg-red-950/10 hover:border-red-500 hover:bg-red-950/20 text-red-400 transition-all">
                                    <div className="text-red-500"><LogOut className="w-5 h-5" /></div><span className="font-black text-xs uppercase tracking-widest">Quit to Title</span>
                                </SfxButton>
                            </div>
                        )}
                    </div>

                    <div className="p-3 bg-stone-950 text-center border-t border-stone-800 shrink-0"><span className="text-[10px] text-stone-600 font-mono uppercase tracking-[0.2em]">Build v{APP_VERSION}</span></div>
                </div>
            </div>

            <SaveLoadModal isOpen={slModal.isOpen} mode={slModal.mode} onClose={() => setSlModal({ ...slModal, isOpen: false })} onAction={handleSlotAction} />

            <ConfirmationModal 
                isOpen={loadConfirm.isOpen} 
                title="Overwrite Progress?" 
                message="Loading will discard unsaved progress." 
                onConfirm={() => { setLoadConfirm({ ...loadConfirm, isOpen: false }); setSlModal({ ...slModal, isOpen: false }); onClose(); if(onLoadRequest) onLoadRequest(loadConfirm.data, loadConfirm.index!); }} 
                onCancel={() => setLoadConfirm({ ...loadConfirm, isOpen: false })} 
            />
        </>
    );
};

export default SettingsModal;

import React, { useState, useEffect, useCallback } from 'react';
import { Anvil, Play, Upload, User, Info, FastForward, X, Settings } from 'lucide-react';
import { getAssetUrl } from '../utils';
import { getLatestSaveInfo, getSaveMetadataList, loadFromSlot } from '../utils/saveSystem';
import SaveLoadModal from './modals/SaveLoadModal';
import SettingsModal from './modals/SettingsModal';
import { SfxButton } from './common/ui/SfxButton';

interface TitleScreenProps {
    onNewGame: () => void;
    onLoadGame: (data: any, slotIndex: number) => void;
}

const TitleScreen: React.FC<TitleScreenProps> = ({ onNewGame, onLoadGame }) => {
    const [showCredits, setShowCredits] = useState(false);
    const [showLoadModal, setShowLoadModal] = useState(false);
    const [showSettings, setShowSettings] = useState(false);
    const [hasSaves, setHasSaves] = useState(false);
    const VERSION = "0.1.43a";

    const checkSaves = useCallback(() => {
        const metadata = getSaveMetadataList();
        setHasSaves(metadata.length > 0);
    }, []);

    useEffect(() => {
        checkSaves();
    }, [checkSaves]);

    useEffect(() => {
        if (!showLoadModal) {
            checkSaves();
        }
    }, [showLoadModal, checkSaves]);

    const handleContinue = () => {
        const info = getLatestSaveInfo();
        if (info) {
            if (info.data.version !== VERSION) {
                alert(`Cannot load: Version mismatch.\n\nSave: v${info.data.version || '0.1.36'}\nApp: v${VERSION}`);
                return;
            }
            onLoadGame(info.data, info.index);
        }
    };

    const handleLoadFromSlot = (index: number) => {
        const data = loadFromSlot(index);
        if (data) {
            if (data.version !== VERSION) {
                alert(`Cannot load: Version mismatch.\n\nSave: v${data.version || '0.1.36'}\nApp: v${VERSION}`);
                return;
            }
            onLoadGame(data, index);
            setShowLoadModal(false);
        }
    };

    return (
            <div className="relative h-[100dvh] w-full bg-stone-950 overflow-hidden flex flex-col items-center justify-center">
                <div className="absolute inset-0 z-0">
                    <img 
                        src={getAssetUrl('forge_bg.jpeg', 'bg')} 
                        className="w-full h-full object-cover opacity-30 blur-sm scale-105"
                        alt="Background"
                    />
                    <div className="absolute inset-0 bg-black/40"></div>
                </div>

                <div className="relative z-10 flex flex-col items-center animate-in fade-in zoom-in duration-1000 p-4 md:p-6 w-full max-h-full overflow-hidden px-safe">
                    <div className="mb-[2dvh] md:mb-12 text-center shrink-0">
                        <div className="w-[clamp(60px,15dvh,120px)] h-[clamp(60px,15dvh,120px)] md:w-32 md:h-32 bg-amber-900/20 rounded-full flex items-center justify-center border-2 md:border-4 border-amber-700/50 mb-[1.5dvh] md:mb-6 mx-auto shadow-[0_0_50px_rgba(180,83,9,0.3)]">
                            <Anvil className="w-[50%] h-[50%] text-amber-50 drop-shadow-lg" />
                        </div>
                        <h1 className="text-[clamp(24px,6dvh,64px)] md:text-8xl font-black text-transparent bg-clip-text bg-gradient-to-b from-amber-400 to-amber-700 font-serif tracking-tighter drop-shadow-sm leading-[1.1]">
                            LOCKHART'S<br/>FORGE
                        </h1>
                        <div className="h-0.5 md:h-1 w-16 md:w-32 bg-amber-800 mx-auto mt-[1dvh] md:mt-4 rounded-full"></div>
                        <p className="mt-[0.5dvh] md:mt-4 text-stone-500 font-sans tracking-[0.3em] text-[clamp(10px,1.2dvh,14px)] md:text-sm uppercase font-bold">The Ember of Retribution</p>
                        <p className="mt-1 text-stone-600 font-mono text-[9px] md:text-xs">Build v{VERSION}</p>
                    </div>

                    <div className="flex flex-col gap-1.5 md:gap-4 w-48 md:w-64 shrink-0">
                        {hasSaves && (
                            <SfxButton 
                                onClick={handleContinue}
                                className="group relative px-4 md:px-8 py-1.5 md:py-4 bg-amber-700/20 border border-amber-500 hover:bg-amber-600 transition-all rounded-lg shadow-xl animate-pulse hover:animate-none"
                            >
                                <div className="flex items-center justify-center gap-2 md:gap-3">
                                    <FastForward className="w-3 h-3 md:w-5 md:h-5 text-amber-400" />
                                    <span className="font-serif font-black text-amber-50 tracking-wide text-[10px] md:text-base">CONTINUE</span>
                                </div>
                            </SfxButton>
                        )}

                        <SfxButton 
                            onClick={onNewGame}
                            className="group relative px-4 md:px-8 py-1.5 md:py-4 bg-stone-900/80 border border-stone-700 hover:border-amber-500 rounded-lg overflow-hidden transition-all hover:bg-stone-800 shadow-lg"
                        >
                            <div className="absolute inset-0 w-1 bg-amber-500 transition-all group-hover:w-full opacity-10"></div>
                            <div className="flex items-center justify-center gap-2 md:gap-3">
                                <Play className="w-3 h-3 md:w-5 md:h-5 text-amber-500 group-hover:scale-110 transition-transform" />
                                <span className="font-serif font-black text-stone-200 tracking-wide text-[10px] md:text-base">NEW GAME</span>
                            </div>
                        </SfxButton>

                        <SfxButton 
                            sfx="switch"
                            onClick={() => setShowLoadModal(true)}
                            className={`group px-4 md:px-8 py-1.5 md:py-4 border rounded-lg transition-all flex items-center justify-center gap-2 md:gap-3 bg-stone-900/80 border-stone-700 hover:border-stone-500 hover:bg-stone-800 text-stone-300`}
                        >
                            <div className="flex items-center justify-center gap-2 md:gap-3">
                                <Upload className="w-3 h-3 md:w-5 md:h-5" />
                                <span className="font-serif font-black tracking-wide text-[10px] md:text-base">LOAD GAME</span>
                            </div>
                        </SfxButton>

                        <SfxButton 
                            sfx="switch"
                            onClick={() => setShowSettings(true)}
                            className="group px-4 md:px-8 py-1.5 md:py-4 bg-stone-900/80 border border-stone-700 hover:border-stone-500 rounded-lg transition-all hover:bg-stone-800 text-stone-300 flex items-center justify-center gap-2 md:gap-3"
                        >
                            <div className="flex items-center justify-center gap-2 md:gap-3">
                                <Settings className="w-3 h-3 md:w-5 md:h-5" />
                                <span className="font-serif font-black tracking-wide text-[10px] md:text-base">SETTINGS</span>
                            </div>
                        </SfxButton>

                        <SfxButton 
                            onClick={() => setShowCredits(true)}
                            className="px-6 py-1 md:py-2 mt-0.5 md:mt-4 text-stone-600 hover:text-amber-600 text-[8px] md:text-xs font-black tracking-widest transition-colors flex items-center justify-center gap-2 font-sans"
                        >
                            <User className="w-2.5 h-2.5" /> CREDITS
                        </SfxButton>
                    </div>
                </div>

                <SaveLoadModal 
                    isOpen={showLoadModal} 
                    mode="LOAD" 
                    onClose={() => setShowLoadModal(false)} 
                    onAction={handleLoadFromSlot} 
                />

                <SettingsModal 
                    isOpen={showSettings}
                    onClose={() => setShowSettings(false)}
                    isTitleView={true}
                />

                {showCredits && (
                    <div className="absolute inset-0 z-50 flex items-center justify-center bg-black/90 backdrop-blur-md p-4 animate-in fade-in">
                        <div className="max-w-md w-full bg-stone-900 border border-stone-700 p-6 md:p-8 rounded-xl text-center relative shadow-2xl">
                            <SfxButton sfx="switch" onClick={() => setShowCredits(false)} className="absolute top-4 right-4 text-stone-500 hover:text-stone-300">
                                <X className="w-5 h-5" />
                            </SfxButton>
                            <h2 className="text-xl md:text-2xl font-bold text-amber-50 mb-6 font-serif">Credits</h2>
                            <div className="space-y-4 text-stone-300 text-left">
