import React, { useRef, useState, useEffect, useCallback } from 'react';

interface CustomSliderProps {
    value: number; // 0 to 1
    onChange: (value: number) => void;
    disabled?: boolean;
    className?: string;
}

/**
 * CustomSlider
 * A high-performance slider that tracks the pointer instantaneously.
 * CSS transitions are disabled during dragging to prevent lag.
 */
export const CustomSlider: React.FC<CustomSliderProps> = ({ 
    value, 
    onChange, 
    disabled = false,
    className = ""
}) => {
    const containerRef = useRef<HTMLDivElement>(null);
    const [isDragging, setIsDragging] = useState(false);

    const updateValue = useCallback((clientX: number) => {
        if (!containerRef.current || disabled) return;

        const rect = containerRef.current.getBoundingClientRect();
        const relativeX = clientX - rect.left;
        const percentage = Math.max(0, Math.min(1, relativeX / rect.width));

        onChange(percentage);
    }, [disabled, onChange]);

    const handleMouseDown = (e: React.MouseEvent) => {
        if (disabled) return;
        // Prevent focus and other default behaviors
        e.preventDefault();
        setIsDragging(true);
        updateValue(e.clientX);
    };

    const handleTouchStart = (e: React.TouchEvent) => {
        if (disabled) return;
        // Start dragging immediately on touch
        setIsDragging(true);
        updateValue(e.touches[0].clientX);
    };

    useEffect(() => {
        if (!isDragging) return;

        const handleMouseMove = (e: MouseEvent) => {
            updateValue(e.clientX);
        };

        const handleTouchMove = (e: TouchEvent) => {
            // Prevent scrolling while adjusting volume on mobile
            if (e.cancelable) e.preventDefault();
            updateValue(e.touches[0].clientX);
        };

        const handleEnd = () => {
            setIsDragging(false);
        };

        // Bind to window to handle fast movements outside the container
        window.addEventListener('mousemove', handleMouseMove, { passive: true });
        window.addEventListener('mouseup', handleEnd);
        window.addEventListener('touchmove', handleTouchMove, { passive: false });
        window.addEventListener('touchend', handleEnd);

        return () => {
            window.removeEventListener('mousemove', handleMouseMove);
            window.removeEventListener('mouseup', handleEnd);
            window.removeEventListener('touchmove', handleTouchMove);
            window.removeEventListener('touchend', handleEnd);
        };
    }, [isDragging, updateValue]);

    return (
        <div 
            ref={containerRef}
            onMouseDown={handleMouseDown}
            onTouchStart={handleTouchStart}
            className={`relative h-8 flex items-center cursor-pointer select-none group touch-none ${disabled ? 'cursor-not-allowed opacity-50 grayscale' : ''} ${className}`}
        >
            {/* Track Background */}
            <div className="absolute w-full h-2.5 bg-stone-950 rounded-full border border-stone-800 shadow-inner overflow-hidden">
                {/* Active Fill */}
                <div 
                    className={`h-full bg-gradient-to-r from-amber-800 via-amber-600 to-amber-400 shadow-[0_0_10px_rgba(245,158,11,0.3)] ${isDragging ? 'transition-none' : 'transition-all duration-200'}`}
                    style={{ width: `${value * 100}%` }}
                />
            </div>

            {/* Handle (Thumb) */}
            <div 
                className={`absolute w-6 h-6 bg-stone-100 rounded-full border-2 border-amber-600 shadow-xl flex items-center justify-center ${isDragging ? 'transition-none scale-110 bg-white ring-4 ring-amber-500/20' : 'transition-all duration-200 group-hover:scale-105'}`}
                style={{ 
                    left: `${value * 100}%`,
                    transform: 'translateX(-50%)',
                    zIndex: 10
                }}
            >
                <div className="w-1.5 h-1.5 rounded-full bg-amber-600"></div>

                {/* Active Aura during drag */}
                {isDragging && (
                    <div className="absolute inset-[-8px] rounded-full bg-amber-500/10 animate-pulse"></div>
                )}
            </div>
        </div>
    );
};

