import { GameAction } from './actions';

// Import Handlers
import { handleRepairWork } from './reducer/repair';
import { handleSleep, handleConfirmSleep } from './reducer/sleep';
import { handleTriggerEvent, handleCloseEvent, handleToggleJournal } from './reducer/events';
import { handleAcquireItem, handlePayCost, handleBuyMarketItems, handleInstallFurnace, handleSellItem, handleUseItem, handleToggleLockItem, handleApplySkillScroll } from './reducer/inventory';
import { handleStartCrafting, handleCancelCrafting, handleFinishCrafting, handleSetCrafting, handleUpdateForgeStatus } from './reducer/crafting';
import { handleToggleShop, handleEnqueueCustomer, handleNextCustomer, handleDismissCustomer, handleRefuseCustomer } from './reducer/shop';
import { handleAddKnownMercenary, handleScoutMercenary, handleHireMercenary, handleFireMercenary, handleAllocateStat, handleUpdateMercenaryStats, handleGiveGift, handleTalkMercenary } from './reducer/mercenary';
import { handleStartExpedition, handleCompleteExpedition, handleClaimExpedition, handleAbortExpedition, handleDismissDungeonResult } from './reducer/expedition';
import { handleEquipItem, handleUnequipItem } from './reducer/equipment';
import { handleStartManualDungeon, handleMoveManualDungeon, handleFinishManualDungeon, handleRescueNPC, handleRetreatManualDungeon, handleStartCombatManual, handleResolveCombatManual, handleProceedToNextFloorManual } from './reducer/manualDungeon';
import { handleTalkGarrick, handleGiftGarrick } from './reducer/market-affinity';
import { handleResearchCombination } from './reducer/research';

export const gameReducer = (state: GameState, action: GameAction): GameState => {
  switch (action.type) {
    // Save & Load
    case 'LOAD_GAME': return action.payload;

    // Repair
    case 'REPAIR_WORK': return handleRepairWork(state);

    // Sleep
    case 'SLEEP': return handleSleep(state);
    case 'CONFIRM_SLEEP': return handleConfirmSleep(state);
    case 'CLOSE_SLEEP_MODAL': return { ...state, showSleepModal: false };

    // Events
    case 'TRIGGER_EVENT': return handleTriggerEvent(state, action.payload);
    case 'CLOSE_EVENT': return handleCloseEvent(state);
    case 'TOGGLE_JOURNAL': return handleToggleJournal(state);

    // Inventory & Market
    case 'ACQUIRE_ITEM': return handleAcquireItem(state, action.payload);
    case 'PAY_COST': return handlePayCost(state, action.payload);
    case 'BUY_MARKET_ITEMS': return handleBuyMarketItems(state, action.payload);
    case 'INSTALL_FURNACE': return handleInstallFurnace(state);
    case 'SELL_ITEM': return handleSellItem(state, action.payload);
    case 'USE_ITEM': return handleUseItem(state, action.payload);
    case 'APPLY_SKILL_SCROLL': return handleApplySkillScroll(state, action.payload);
    case 'TOGGLE_LOCK_ITEM': return handleToggleLockItem(state, action.payload);

    // Crafting
    case 'START_CRAFTING': return handleStartCrafting(state, action.payload);
    case 'CANCEL_CRAFTING': return handleCancelCrafting(state, action.payload);
    case 'FINISH_CRAFTING': return handleFinishCrafting(state, action.payload);
    case 'DISMISS_CRAFTING_RESULT': return { ...state, lastCraftedItem: null };
    case 'DISMISS_TIER_UNLOCK': return { ...state, unlockedTierPopup: null };
    case 'SET_CRAFTING': return handleSetCrafting(state, action.payload);
    case 'SET_RESEARCH_OPEN': return { ...state, isResearchOpen: action.payload };
    case 'UPDATE_FORGE_STATUS': return handleUpdateForgeStatus(state, action.payload);

    // Shop
    case 'TOGGLE_SHOP': return handleToggleShop(state);
    case 'ENQUEUE_CUSTOMER': return handleEnqueueCustomer(state, action.payload);
    case 'NEXT_CUSTOMER': return handleNextCustomer(state);
    case 'DISMISS_CUSTOMER': return handleDismissCustomer(state);
    case 'REFUSE_CUSTOMER': return handleRefuseCustomer(state, action.payload);

    // Mercenaries
    case 'ADD_KNOWN_MERCENARY': return handleAddKnownMercenary(state, action.payload);
    case 'SCOUT_MERCENARY': return handleScoutMercenary(state, action.payload);
    case 'HIRE_MERCENARY': return handleHireMercenary(state, action.payload);
    case 'FIRE_MERCENARY': return handleFireMercenary(state, action.payload);
    case 'GIVE_GIFT': return handleGiveGift(state, action.payload);
    case 'TALK_MERCENARY': return handleTalkMercenary(state, action.payload);
    case 'ALLOCATE_STAT': return handleAllocateStat(state, action.payload);
    case 'UPDATE_MERCENARY_STATS': return handleUpdateMercenaryStats(state, action.payload);

    // Garrick Market
    case 'TALK_GARRICK': return handleTalkGarrick(state);
    case 'GIFT_GARRICK': return handleGiftGarrick(state, action.payload);

    // Research
    case 'RESEARCH_COMBINATION': return handleResearchCombination(state, action.payload);

    // Expedition
    case 'START_EXPEDITION': return handleStartExpedition(state, action.payload);
    case 'COMPLETE_EXPEDITION': return handleCompleteExpedition(state, action.payload);
    case 'CLAIM_EXPEDITION': return handleClaimExpedition(state, action.payload);
    case 'ABORT_EXPEDITION': return handleAbortExpedition(state, action.payload);
    case 'DISMISS_DUNGEON_RESULT': return handleDismissDungeonResult(state);

    // Equipment
    case 'EQUIP_ITEM': return handleEquipItem(state, action.payload);
    case 'UNEQUIP_ITEM': return handleUnequipItem(state, action.payload);

    // Manual Dungeon
    case 'START_MANUAL_DUNGEON': return handleStartManualDungeon(state, action.payload);
    case 'MOVE_MANUAL_DUNGEON': return handleMoveManualDungeon(state, action.payload);
    case 'FINISH_MANUAL_DUNGEON': return handleFinishManualDungeon(state);
    case 'RESCUE_NPC': return handleRescueNPC(state, action.payload);
    case 'RETREAT_MANUAL_DUNGEON': return handleRetreatManualDungeon(state);
    case 'START_COMBAT_MANUAL': return handleStartCombatManual(state);
    case 'RESOLVE_COMBAT_MANUAL': return handleResolveCombatManual(state, action.payload);
    case 'PROCEED_TO_NEXT_FLOOR_MANUAL': return handleProceedToNextFloorManual(state);

    // Tutorial & Prologue
    case 'SET_TUTORIAL_STEP': return { ...state, tutorialStep: action.payload };
    case 'SET_ACTIVE_TUTORIAL_SCENE': return { ...state, activeTutorialScene: action.payload };
    case 'COMPLETE_PROLOGUE': 
        return { 
            ...state, 
            hasCompletedPrologue: true,
            activeTutorialScene: null,
            tutorialStep: 'MARKET_GUIDE' 
        };
    case 'COMPLETE_TUTORIAL':
        const finalTabs = ['FORGE', 'MARKET', 'INVENTORY', 'SHOP', 'TAVERN', 'DUNGEON', 'SIMULATION'];
        return {
            ...state,
            tutorialStep: null,
            activeTutorialScene: null,
            unlockedTabs: finalTabs,
            stats: {
                ...state.stats,
                tierLevel: Math.max(state.stats.tierLevel, 1) 
            },
            forge: { ...state.forge, hasFurnace: true }, 
            showTutorialCompleteModal: true,
            logs: ["Tutorial completed. Lockhart's Forge is fully operational.", ...state.logs]
        };
    case 'DISMISS_TUTORIAL_COMPLETE':
        return { ...state, showTutorialCompleteModal: false };

    // User Preferences
    case 'UPDATE_SETTINGS':
        return {
            ...state,
            settings: { ...state.settings, ...action.payload }
        };

    // Toast Notifications
    case 'SHOW_TOAST':
        // 현재 노출 중인 메시지와 동일하면 무시
        if (state.toast?.visible && state.toast.message === action.payload) {
            return state;
        }
        // 큐의 마지막 메시지와 동일하면 무시
        if (state.toastQueue.length > 0 && state.toastQueue[state.toastQueue.length - 1] === action.payload) {
            return state;
        }
        return {
            ...state,
            toastQueue: [...state.toastQueue, action.payload]
        };

    case 'POP_NEXT_TOAST':
        if (state.toastQueue.length === 0) return state;
        const [nextMessage, ...remainingQueue] = state.toastQueue;
        return {
            ...state,
            toast: { message: nextMessage, visible: true },
            toastQueue: remainingQueue
        };

    case 'HIDE_TOAST':
        return {
            ...state,
            toast: state.toast ? { ...state.toast, visible: false } : null
        };

    // UI Effects
    case 'SET_UI_EFFECT':
        return {
            ...state,
            uiEffects: {
                ...state.uiEffects,
                [action.payload.effect]: action.payload.value
            }
        };

    default:
      return state;
  }
};

import { GameState, InventoryItem } from '../../types/index';
import { materials } from '../../data/materials';
import { Mercenary } from '../../models/Mercenary';
import { DUNGEON_CONFIG } from '../../config/dungeon-config';
import { SKILLS } from '../../data/skills';

export const handleAcquireItem = (state: GameState, payload: { id: string; quantity: number }): GameState => {
    const { id, quantity } = payload;
    const itemDef = (materials as any)[id];
    if (!itemDef) return state;

    const existingItem = state.inventory.find(i => i.id === id);
    const newInventory = existingItem
    ? state.inventory.map(i => i.id === id ? { ...i, quantity: i.quantity + quantity } : i)
    : [...state.inventory, { ...itemDef, quantity } as InventoryItem];

    return {
    ...state,
    inventory: newInventory,
    logs: [`Acquired ${itemDef.name} x${quantity}.`, ...state.logs],
    };
};

export const handlePayCost = (state: GameState, payload: { gold?: number; items?: { id: string; count: number }[] }): GameState => {
    const { gold, items } = payload;
    let newGold = state.stats.gold;
    let newInventory = [...state.inventory];

    if (gold) newGold -= gold;
    if (items) {
        items.forEach(costItem => {
            newInventory = newInventory.map(invItem => {
                if (invItem.id === costItem.id) {
                    return { ...invItem, quantity: invItem.quantity - costItem.count };
                }
                return invItem;
            }).filter(i => i.quantity > 0);
        });
    }
    return {
        ...state,
        stats: { ...state.stats, gold: newGold },
        inventory: newInventory
    };
};

export const handleBuyMarketItems = (state: GameState, payload: { items: { id: string; count: number }[]; totalCost: number }): GameState => {
    const { items, totalCost } = payload;

    const newGold = state.stats.gold - totalCost;
    if (newGold < 0) return state; 

    let newInventory = [...state.inventory];
    let newTierLevel = state.stats.tierLevel;
    let newForgeState = { ...state.forge };
    let logUpdates: string[] = [`Bought supplies for ${totalCost} Gold.`];
    let newMarketStock = { ...state.marketStock };
    let newUnlockedTabs = [...state.unlockedTabs];

    if (!newUnlockedTabs.includes('INVENTORY')) {
        newUnlockedTabs.push('INVENTORY');
        logUpdates.unshift("Access granted: Inventory facility is now operational.");
    }

    items.forEach(buyItem => {
            // Update stock
            newMarketStock[buyItem.id] = Math.max(0, (newMarketStock[buyItem.id] || 0) - buyItem.count);

            if (buyItem.id === 'scroll_t2') {
                newTierLevel = Math.max(newTierLevel, 2);
                logUpdates.unshift('Upgrade Complete: Market Tier 2 Unlocked!');
                return; 
            }
            if (buyItem.id === 'scroll_t3') {
                newTierLevel = Math.max(newTierLevel, 3);
                logUpdates.unshift('Upgrade Complete: Market Tier 3 Unlocked!');
                return; 
            }
            if (buyItem.id === 'furnace') {
                newForgeState.hasFurnace = true;
                if (newTierLevel === 0) newTierLevel = 1; 
                logUpdates.unshift('Furnace acquired! The restoration process has begun.');
                return; 
            }
            if (buyItem.id === 'workbench') {
                newForgeState.hasWorkbench = true;
                logUpdates.unshift('Workbench installed! You can now craft leather and wood equipment.');
                return;
            }
            if (buyItem.id === 'research_table') {
                newForgeState.hasResearchTable = true;
                if (!newUnlockedTabs.includes('RESEARCH')) {
                    newUnlockedTabs.push('RESEARCH');
                }
                logUpdates.unshift('Research Table installed! You can now experiment with materials to find lost blueprints.');
                return;
            }
            const itemDef = (materials as any)[buyItem.id];
            if (itemDef) {
                const existingItem = newInventory.find(i => i.id === buyItem.id);
                if (existingItem) {
                    newInventory = newInventory.map(i => i.id === buyItem.id ? { ...i, quantity: i.quantity + buyItem.count } : i);
                } else {
                    newInventory.push({ ...itemDef, quantity: buyItem.count } as InventoryItem);
                }
            }
    });

    return {
        ...state,
        stats: { 
            ...state.stats, 
            gold: newGold, 
            tierLevel: newTierLevel,
            dailyFinancials: {
                ...state.stats.dailyFinancials,
                expenseMarket: state.stats.dailyFinancials.expenseMarket + totalCost
            }
        },
        forge: newForgeState,
        inventory: newInventory,
        marketStock: newMarketStock,
        unlockedTabs: newUnlockedTabs,
        logs: [...logUpdates, ...state.logs]
    };
};

/**
 * handleInstallFurnace
 * Sets the forge status to indicate a furnace is installed.
 */
export const handleInstallFurnace = (state: GameState): GameState => {
    return {
        ...state,
        forge: {
            ...state.forge,
            hasFurnace: true
        },
        logs: ["The furnace has been installed and is ready for use.", ...state.logs]
    };
};

export const handleSellItem = (state: GameState, payload: { itemId: string; count: number; price: number; equipmentInstanceId?: string; customer?: Mercenary }): GameState => {
    const { itemId, count, price, equipmentInstanceId, customer } = payload;

    let newInventory = [...state.inventory];
    let itemName = 'Item';
    let newKnownMercenaries = [...state.knownMercenaries];
    let logMessage = '';
    let newTutorialStep = state.tutorialStep;
    let newActiveCustomer = state.activeCustomer;
    let qualityBonus = 0;

    const isShopSale = !!customer;

    if (equipmentInstanceId) {
        const itemIndex = newInventory.findIndex(i => i.id === equipmentInstanceId);
        if (itemIndex > -1) {
            if (newInventory[itemIndex].isLocked) return state;

            const targetItem = newInventory[itemIndex];
            itemName = targetItem.name;

            // 품질 보너스 계산
            if (targetItem.equipmentData) {
                const q = targetItem.equipmentData.quality;
                if (q > 100) qualityBonus = 2; // 명품 보너스
                else if (q < 80) qualityBonus = -1; // 하급품 패널티
            }

            newInventory.splice(itemIndex, 1);
        }
    } else {
        const itemIndex = newInventory.findIndex(i => i.id === itemId);
        if (itemIndex > -1) {
            if (newInventory[itemIndex].isLocked) return state;
        }

        newInventory = newInventory.map(item => {
            if (item.id === itemId) {
                itemName = item.name;
                return { ...item, quantity: item.quantity - count };
            }
            return item;
        }).filter(i => i.quantity > 0);
    }

    if (customer) {
        const existingMercIdx = newKnownMercenaries.findIndex(m => m.id === customer.id);
        const isPipTutorial = newTutorialStep === 'SELL_ITEM_GUIDE' && customer.id === 'pip_green';

        // 최종 호감도 상승량 결정 (기본 2 + 품질 보너스)
        const baseAffinityGain = isPipTutorial ? 10 : 2;
        const finalAffinityGain = Math.max(1, baseAffinityGain + qualityBonus);

        if (existingMercIdx > -1) {
            const merc = { ...newKnownMercenaries[existingMercIdx] };
            merc.affinity = Math.min(100, (merc.affinity || 0) + finalAffinityGain); 
            merc.visitCount = (merc.visitCount || 0) + 1;
            merc.lastVisitDay = state.stats.day;
            newKnownMercenaries[existingMercIdx] = merc;

            const qualityNote = qualityBonus > 0 ? " (Masterwork Bonus!)" : qualityBonus < 0 ? " (Poor Quality Penalty)" : "";
            logMessage = `Sold ${itemName} to ${customer.name}. Affinity rose by ${finalAffinityGain}${qualityNote}.`;
        } else {
            const newMerc: Mercenary = {
                ...customer,
                affinity: finalAffinityGain,
                visitCount: 1,
                lastVisitDay: state.stats.day,
                expeditionEnergy: DUNGEON_CONFIG.MAX_EXPEDITION_ENERGY,
                currentXp: 0,
                xpToNextLevel: 100,
                status: 'VISITOR'
            };
            newKnownMercenaries.push(newMerc);
            logMessage = `Sold ${itemName} to ${customer.name}. (New Contact, Affinity +${finalAffinityGain})`;
        }

        if (newActiveCustomer && newActiveCustomer.mercenary.id === customer.id) {
            newActiveCustomer = {
                ...newActiveCustomer,
                mercenary: {
                    ...newActiveCustomer.mercenary,
                    affinity: Math.min(100, (newActiveCustomer.mercenary.affinity || 0) + finalAffinityGain)
                }
            };
        }

        if (isPipTutorial) {
            newTutorialStep = 'PIP_PRAISE_DIALOG';
        }
    } else {
        logMessage = `Sold ${itemName} for ${price} Gold.`;
    }

    return {
        ...state,
        inventory: newInventory,
        stats: { 
            ...state.stats, 
            gold: state.stats.gold + price,
            dailyFinancials: {
                ...state.stats.dailyFinancials,
                incomeShop: state.stats.dailyFinancials.incomeShop + (isShopSale ? price : 0),
                incomeInventory: state.stats.dailyFinancials.incomeInventory + (!isShopSale ? price : 0)
            }
        },
        knownMercenaries: newKnownMercenaries,
        activeCustomer: newActiveCustomer,
        tutorialStep: newTutorialStep,
        logs: [logMessage, ...state.logs]
    };
};

const POTION_EFFECTS: Record<string, Record<string, number | 'FULL'>> = {
    health: { small: 50, medium: 150, large: 400, huge: 'FULL' },
    mana: { small: 30, medium: 100, large: 250, huge: 'FULL' },
    stamina: { small: 25, medium: 50, large: 75, huge: 100 },
    energy: { small: 20, medium: 45, large: 75, huge: 100 }
};

export const handleUseItem = (state: GameState, payload: { itemId: string; mercenaryId?: string }): GameState => {
    const { itemId, mercenaryId } = payload;
    const inventoryItem = state.inventory.find(i => i.id === itemId);

    if (!inventoryItem || inventoryItem.quantity <= 0) return state;

    let newStats = { ...state.stats };
    let newUnlockedRecipes = [...(state.unlockedRecipes || [])];
    let newKnownMercenaries = [...state.knownMercenaries];
    let logMsg = '';
    let itemUsed = false;

    // --- Skill Scroll System ---
    // Scrolls are not consumed here; they are handled via APPLY_SKILL_SCROLL after UI selection.
    if (inventoryItem.type === 'SKILL_SCROLL') {
        return state;
    }

    // --- Skill Book System ---
    if (inventoryItem.type === 'SKILL_BOOK' && inventoryItem.skillId && mercenaryId) {
        const mercIdx = newKnownMercenaries.findIndex(m => m.id === mercenaryId);
        if (mercIdx > -1) {
            const merc = { ...newKnownMercenaries[mercIdx] };
            const skill = SKILLS[inventoryItem.skillId];
            if (!skill) return state;

            // Check if already learned
            if (merc.skillIds?.includes(inventoryItem.skillId)) {
                return { ...state, toastQueue: [...state.toastQueue, `${merc.name} already knows ${skill.name}.`] };
            }

            // Check job compatibility (empty job list means universal)
            const isCompatible = skill.job.length === 0 || skill.job.includes(merc.job);
            if (!isCompatible) {
                return { ...state, toastQueue: [...state.toastQueue, `${merc.name} is not compatible with this skill type.`] };
            }

            merc.skillIds = [...(merc.skillIds || []), inventoryItem.skillId];
            logMsg = `${merc.name} studied the ${inventoryItem.name} and learned ${skill.name}!`;
            itemUsed = true;
            newKnownMercenaries[mercIdx] = merc;
        }
    }

    // --- Unified Potion System ---
    if (!itemUsed && itemId.startsWith('potion_')) {
        const parts = itemId.split('_'); // potion, type, size
        const type = parts[1];
        const size = parts[2];
        const recoverValue = POTION_EFFECTS[type]?.[size];

        if (recoverValue === undefined) return state;

        if (type === 'energy') {
            if (mercenaryId) {
                const mercIdx = newKnownMercenaries.findIndex(m => m.id === mercenaryId);
                if (mercIdx > -1) {
                    const merc = { ...newKnownMercenaries[mercIdx] };
                    if (merc.currentHp >= merc.maxHp && merc.currentMp >= merc.maxMp) {
                        return { ...state, toastQueue: [...state.toastQueue, `${merc.name} is already at full vitals.`] };
                    }
                    const amount = recoverValue === 'FULL' ? Math.max(merc.maxHp, merc.maxMp) : (recoverValue as number);
                    merc.currentHp = Math.min(merc.maxHp, merc.currentHp + amount);
                    merc.currentMp = Math.min(merc.maxMp, merc.currentMp + amount);
                    logMsg = `${merc.name} consumed ${inventoryItem.name}. Recovered ${amount} HP and MP.`;
                    itemUsed = true;
                    newKnownMercenaries[mercIdx] = merc;
                }
            } else {
                return { ...state, toastQueue: [...state.toastQueue, `This potion must be used on a mercenary.`] };
            }
        } else if (mercenaryId) {
            const mercIdx = newKnownMercenaries.findIndex(m => m.id === mercenaryId);
            if (mercIdx > -1) {
                const merc = { ...newKnownMercenaries[mercIdx] };
                if (type === 'health') {
                    if (merc.currentHp >= merc.maxHp) {
                        return { ...state, toastQueue: [...state.toastQueue, `${merc.name} is already at full health.`] };
                    }
                    const amount = recoverValue === 'FULL' ? merc.maxHp : (recoverValue as number);
                    merc.currentHp = Math.min(merc.maxHp, merc.currentHp + amount);
                    logMsg = `${merc.name} consumed ${inventoryItem.name}. Recovered ${amount} HP.`;
                    itemUsed = true;
                } else if (type === 'mana') {
                    if (merc.currentMp >= merc.maxMp) {
                        return { ...state, toastQueue: [...state.toastQueue, `${merc.name} is already at full mana.`] };
                    }
                    const amount = recoverValue === 'FULL' ? merc.maxMp : (recoverValue as number);
                    merc.currentMp = Math.min(merc.maxMp, merc.currentMp + amount);
                    logMsg = `${merc.name} consumed ${inventoryItem.name}. Recovered ${amount} MP.`;
                    itemUsed = true;
                } else if (type === 'stamina') {
                    if ((merc.expeditionEnergy || 0) >= DUNGEON_CONFIG.MAX_EXPEDITION_ENERGY) {
                        return { ...state, toastQueue: [...state.toastQueue, `${merc.name} is already at full stamina.`] };
                    }
                    const amount = typeof recoverValue === 'number' ? recoverValue : 100;
                    merc.expeditionEnergy = Math.min(DUNGEON_CONFIG.MAX_EXPEDITION_ENERGY, (merc.expeditionEnergy || 0) + amount);
                    logMsg = `${merc.name} consumed ${inventoryItem.name}. Recovered ${amount} Stamina.`;
                    itemUsed = true;
                }
                newKnownMercenaries[mercIdx] = merc;
            }
        }
    }

    if (!itemUsed) return state;

    const newInventory = state.inventory.map(item => {
        if (item.id === itemId) {
            return { ...item, quantity: item.quantity - 1 };
        }
        return item;
    }).filter(i => i.quantity > 0);

    return {
        ...state,
        stats: newStats,
        inventory: newInventory,
        unlockedRecipes: newUnlockedRecipes,
        knownMercenaries: newKnownMercenaries,
        logs: [logMsg, ...state.logs]
    };
};

export const handleApplySkillScroll = (state: GameState, payload: { scrollItemId: string; targetEquipmentId: string }): GameState => {
    const { scrollItemId, targetEquipmentId } = payload;
    const scroll = state.inventory.find(i => i.id === scrollItemId);
    const target = state.inventory.find(i => i.id === targetEquipmentId);

    if (!scroll || !target || !scroll.skillId || target.type !== 'EQUIPMENT' || !target.equipmentData) {
        return state;
    }

    const skill = SKILLS[scroll.skillId];
    if (!skill) return state;

    // 1. 소모 처리
    const newInventory = state.inventory.map(item => {
        if (item.id === scrollItemId) {
            return { ...item, quantity: item.quantity - 1 };
        }
        if (item.id === targetEquipmentId) {
            return { 
                ...item, 
                equipmentData: { 
                    ...item.equipmentData!, 
                    socketedSkillId: scroll.skillId 
                } 
            };
        }
        return item;
    }).filter(i => i.quantity > 0);

    return {
        ...state,
        inventory: newInventory,
        logs: [`Successfully imbued ${target.name} with ${skill.name}.`, ...state.logs]
    };
};

export const handleToggleLockItem = (state: GameState, payload: { itemId: string }): GameState => {
    const newInventory = state.inventory.map(item => {
        if (item.id === payload.itemId) {
            return { ...item, isLocked: !item.isLocked };
        }
        return item;
    });

    return {
        ...state,
        inventory: newInventory
    };
};

import React, { useState, useMemo, useEffect } from 'react';
import { useGame } from '../context/GameContext';
import { 
    Package, Sword, Shield, Coins, Info, Zap, Wrench, ShieldAlert, AlertCircle, 
    Brain, Lock, Unlock, Star, Sparkles, X, Minus, Plus, ChevronRight, Wand2
} from 'lucide-react';
import { InventoryItem } from '../types/index';
import { getAssetUrl } from '../utils';
import ConfirmationModal from './modals/ConfirmationModal';
import { SKILLS } from '../data/skills';

const RomanTierOverlay = ({ id }: { id: string }) => {
    if (id === 'scroll_t2') return <div className="absolute inset-0 flex items-center justify-center pointer-events-none"><span className="text-amber-500 font-serif font-black text-xs md:text-xl drop-shadow-[0_2px_2px_rgba(0,0,0,0.8)] translate-y-1">II</span></div>;
    if (id === 'scroll_t3') return <div className="absolute inset-0 flex items-center justify-center pointer-events-none"><span className="text-amber-500 font-serif font-black text-xs md:text-xl drop-shadow-[0_2px_2px_rgba(0,0,0,0.8)] translate-y-1">III</span></div>;
    if (id === 'scroll_t4') return <div className="absolute inset-0 flex items-center justify-center pointer-events-none"><span className="text-amber-500 font-serif font-black text-xs md:text-xl drop-shadow-[0_2px_2px_rgba(0,0,0,0.8)] translate-y-1">IV</span></div>;
    return null;
};

const AdaptiveInventoryImage = ({ item, className }: { item: InventoryItem, className?: string }) => {
    const isEquip = item.type === 'EQUIPMENT';
    const isSkill = item.type === 'SKILL_BOOK' || item.type === 'SKILL_SCROLL';
    const folder = isEquip ? 'equipments' : isSkill ? 'skills' : 'materials';

    const baseId = (isEquip && item.equipmentData?.recipeId) 
        ? item.equipmentData.recipeId 
        : item.id;

    const [imgSrc, setImgSrc] = useState(getAssetUrl(`${baseId}.png`, folder));

    // 아이템 데이터가 변경될 때 이미지 경로 상태를 동기화합니다.
    useEffect(() => {
        setImgSrc(getAssetUrl(`${baseId}.png`, folder));
    }, [baseId, folder]);

    const handleImgError = () => {
        const fallbackPath = item.image || item.equipmentData?.image;
        if (fallbackPath && imgSrc !== getAssetUrl(fallbackPath, folder)) {
            setImgSrc(getAssetUrl(fallbackPath, folder));
        }
    };

    return <img src={imgSrc} onError={handleImgError} className={className} />;
};

export const InventoryDisplay = () => {
    const { state, actions } = useGame();
    const [selectedItemId, setSelectedItemId] = useState<string | null>(null);
    const [isSellModalOpen, setIsSellModalOpen] = useState(false);
    const [sellQuantity, setSellQuantity] = useState(1);

    // 인챈트(스크롤 부여) 관련 상태
    const [enchantingScroll, setEnchantingScroll] = useState<InventoryItem | null>(null);
    const [confirmEnchantTarget, setConfirmEnchantTarget] = useState<InventoryItem | null>(null);

    const currentSelectedItem = useMemo(() => 
        state.inventory.find(i => i.id === selectedItemId) || null
    , [state.inventory, selectedItemId]);

    const handleSelect = (item: InventoryItem) => {
        // 인챈트 모드일 때 로직
        if (enchantingScroll) {
            if (item.type === 'EQUIPMENT') {
                if (item.isLocked) {
                    actions.showToast("Cannot enchant a locked item.");
                    return;
                }
                setConfirmEnchantTarget(item);
            }
            return;
        }
        setSelectedItemId(item.id);
    };

    const handleOpenSellModal = () => {
        if (!currentSelectedItem || currentSelectedItem.isLocked) return;
        setSellQuantity(1);
        setIsSellModalOpen(true);
    };

    const handleConfirmBulkSell = () => {
        if (!currentSelectedItem) return;
        const sellPricePerItem = Math.floor(currentSelectedItem.baseValue * 0.5);
        const totalPrice = sellPricePerItem * sellQuantity;

        actions.sellItem(
            currentSelectedItem.id, 
            sellQuantity, 
            totalPrice, 
            currentSelectedItem.type === 'EQUIPMENT' ? currentSelectedItem.id : undefined
        );

        setIsSellModalOpen(false);
        // If we sold all items, deselect
        if (currentSelectedItem.quantity <= sellQuantity) {
            setSelectedItemId(null);
        }
    };

    const handleUseScroll = () => {
        if (!currentSelectedItem || currentSelectedItem.type !== 'SKILL_SCROLL') return;
        setEnchantingScroll(currentSelectedItem);
    };

    const handleConfirmEnchant = () => {
        if (enchantingScroll && confirmEnchantTarget) {
            actions.dispatch({ 
                type: 'APPLY_SKILL_SCROLL', 
                payload: { 
                    scrollItemId: enchantingScroll.id, 
                    targetEquipmentId: confirmEnchantTarget.id 
                } 
            });
            setEnchantingScroll(null);
            setConfirmEnchantTarget(null);
            actions.showToast("Equipment enchanted successfully!");
        }
    };

    const handleConsume = () => {
        if (!currentSelectedItem) return;
        if (currentSelectedItem.type === 'SKILL_SCROLL') {
            handleUseScroll();
            return;
        }
        actions.useItem(currentSelectedItem.id);
        if (currentSelectedItem.quantity <= 1) setSelectedItemId(null);
    };

    const getQualityLabel = (q: number): string => {
        if (q >= 110) return 'MASTERWORK';
        if (q >= 100) return 'PRISTINE';
        if (q >= 90) return 'SUPERIOR';
        if (q >= 80) return 'FINE';
        if (q >= 70) return 'STANDARD';
        if (q >= 60) return 'RUSTIC';
        return 'CRUDE';
    };

    const getRarityClasses = (rarity?: string) => {
        switch (rarity) {
            case 'Legendary': return 'text-amber-400 border-amber-500/50 bg-amber-950/40';
            case 'Epic': return 'text-purple-400 border-purple-500/50 bg-purple-950/40';
            case 'Rare': return 'text-blue-400 border-blue-500/50 bg-blue-950/40';
            case 'Uncommon': return 'text-emerald-400 border-emerald-500/50 bg-emerald-950/40';
            default: return 'text-stone-400 border-stone-700/50 bg-stone-900/40';
        }
    };

    const renderEquipmentStats = (item: InventoryItem) => {
        if (!item.equipmentData?.stats) return null;
        const s = item.equipmentData.stats;
        const isMagical = s.magicalAttack > s.physicalAttack || s.magicalDefense > s.physicalDefense;
        const atkLabel = isMagical ? "M.ATK" : "P.ATK";
        const defLabel = isMagical ? "M.DEF" : "P.DEF";
        const atkValue = isMagical ? s.magicalAttack : s.physicalAttack;
        const defValue = isMagical ? s.magicalDefense : s.physicalDefense;

        const socketedSkill = item.equipmentData.socketedSkillId ? SKILLS[item.equipmentData.socketedSkillId] : null;

        return (
            <div className="mb-4 space-y-2 shrink-0">
                <div className="grid grid-cols-2 gap-1.5">
                    <div className="flex justify-between bg-stone-900 p-1.5 rounded border border-stone-800 text-[9px] md:text-[10px]">
                        <span className="text-stone-500 uppercase flex items-center gap-1">
                            {isMagical ? <Zap className="w-2 h-2 text-blue-400" /> : <Sword className="w-2 h-2 text-stone-500" />}
                            {atkLabel}
                        </span>
                        <span className="font-mono text-stone-200 font-bold">{atkValue}</span>
                    </div>
                    <div className="flex justify-between bg-stone-900 p-1.5 rounded border border-stone-800 text-[9px] md:text-[10px]">
                        <span className="text-stone-500 uppercase flex items-center gap-1">
                            {isMagical ? <Brain className="w-2 h-2 text-purple-400" /> : <Shield className="w-2 h-2 text-stone-500" />}
                            {defLabel}
                        </span>
                        <span className="font-mono text-stone-200 font-bold">{defValue}</span>
                    </div>
                </div>
                {item.equipmentData.quality && (
                     <div className="flex justify-between bg-stone-900 p-1.5 rounded border border-stone-800 text-[9px] md:text-[10px]">
                        <span className="text-stone-500 uppercase flex items-center gap-1">
                            <Sparkles className="w-2 h-2 text-amber-500" /> Quality
                        </span>
                        <span className="font-black text-amber-500 uppercase tracking-tighter">{getQualityLabel(item.equipmentData.quality)}</span>
                    </div>
                )}
                {socketedSkill && (
                    <div className="bg-indigo-900/30 border border-indigo-500/30 p-2 rounded-lg mt-2">
                        <div className="flex items-center gap-2 mb-1">
                            <Wand2 className="w-3 h-3 text-indigo-400" />
                            <span className="text-[10px] font-black text-indigo-200 uppercase tracking-widest">Socketed Skill</span>
                        </div>
                        <div className="text-xs font-bold text-white">{socketedSkill.name}</div>
                        <p className="text-[9px] text-stone-400 italic leading-tight mt-1">{socketedSkill.description}</p>
                    </div>
                )}
            </div>
        );
    };

    return (
        <div className="flex flex-row h-full w-full max-w-7xl mx-auto p-2 md:p-4 gap-2 md:gap-4 overflow-hidden relative">

            {/* Storage List Section */}
            <div className="flex-[1.5] md:flex-[2.5] bg-slate-900 rounded-xl border border-slate-700 overflow-hidden flex flex-col min-w-0 relative">
                <div className={`bg-slate-800/50 p-2 md:p-3 border-b border-slate-700 flex items-center justify-between shrink-0 ${enchantingScroll ? 'bg-amber-900/40' : ''}`}>
                    <div className="flex items-center gap-2">
                        <Package className="w-3.5 h-3.5 md:w-4 md:h-4 text-amber-50" />
                        <h3 className="text-slate-200 text-xs md:text-sm uppercase tracking-wider font-bold">
                            {enchantingScroll ? 'Select Equipment to Enchant' : 'Storage'}
                        </h3>
                    </div>
                    {enchantingScroll ? (
                        <button onClick={() => setEnchantingScroll(null)} className="px-2 py-1 bg-red-900/40 hover:bg-red-900/60 rounded text-[9px] md:text-[10px] font-black uppercase text-red-200 border border-red-500/30 transition-all flex items-center gap-1">
                            <X className="w-3 h-3" /> Cancel
                        </button>
                    ) : (
                        <span className="text-[10px] text-slate-500 font-mono">{state.inventory.length}</span>
                    )}
                </div>

                {enchantingScroll && (
                    <div className="bg-amber-950/80 px-3 py-1.5 border-b border-amber-500/20 text-[9px] md:text-[11px] text-amber-200 font-bold uppercase tracking-widest flex items-center gap-2 animate-pulse">
                        <Sparkles className="w-3 h-3" />
                        Apply Scroll: {enchantingScroll.name}
                    </div>
                )}

                <div className="p-2 overflow-y-auto flex-1 custom-scrollbar min-h-0 bg-stone-950/20">
                    {state.inventory.length === 0 ? (
                        <div className="text-slate-500 text-center py-12 italic text-xs">Empty</div>
                    ) : (
                        <div className="grid grid-cols-2 xs:grid-cols-3 sm:grid-cols-4 lg:grid-cols-5 gap-2 pb-8">
                            {state.inventory.map(item => {
                                const isSelected = selectedItemId === item.id;
                                const isEnchantTarget = enchantingScroll && item.type === 'EQUIPMENT';
                                const isEnchantRestricted = enchantingScroll && item.type !== 'EQUIPMENT';

                                return (
                                    <button
                                        key={item.id} onClick={() => handleSelect(item)}
                                        disabled={isEnchantRestricted}
                                        className={`relative flex flex-col items-center p-2 rounded-lg border transition-all h-20 md:h-28 justify-between ${
                                            isSelected ? 'bg-amber-900/20 border-amber-500 shadow-md ring-1 ring-amber-500/50' : 
                                            isEnchantTarget ? 'bg-indigo-900/10 border-indigo-500/50 animate-pulse ring-2 ring-indigo-500/30' :
                                            isEnchantRestricted ? 'opacity-30 grayscale cursor-not-allowed border-transparent' :
                                            'bg-slate-800/50 border-slate-700/50 hover:bg-slate-800 hover:border-slate-600'
                                        }`}
                                    >
                                        <div className="absolute top-1 right-1 bg-slate-950/80 px-1 rounded text-[8px] md:text-[10px] text-slate-400 font-mono flex items-center gap-1 z-20">
                                            {item.isLocked && <Lock className="w-2 h-2 md:w-2.5 md:h-2.5 text-amber-500" />}
                                            x{item.quantity}
                                        </div>
                                        <div className="flex-1 flex items-center justify-center relative">
                                             <AdaptiveInventoryImage item={item} className="w-6 h-6 md:w-10 md:h-10 object-contain" />
                                             <RomanTierOverlay id={item.id} />
                                        </div>
                                        <div className="text-[9px] md:text-xs text-center font-medium text-slate-300 w-full truncate">{item.name}</div>
                                    </button>
                                );
                            })}
                        </div>
                    )}
                </div>
            </div>

            {/* Details Section */}
            <div className="flex-1 md:w-96 bg-black rounded-xl border border-stone-800 overflow-hidden flex flex-col min-w-0">
                <div className="bg-stone-900/50 p-2 md:p-3 border-b border-stone-800 flex items-center justify-between shrink-0">
                    <div className="flex items-center gap-2">
                        <Info className="w-3.5 h-3.5 md:w-4 md:h-4 text-stone-500" />
                        <h3 className="text-stone-400 text-[10px] md:text-xs uppercase tracking-wider font-bold">Details</h3>
                    </div>
                    {currentSelectedItem && (
                         <button 
                            onClick={() => actions.toggleLockItem(currentSelectedItem.id)}
                            className={`p-1.5 rounded-lg border transition-all ${currentSelectedItem.isLocked ? 'bg-amber-950/40 border-amber-600/50 text-amber-500' : 'bg-stone-900 border-stone-800 text-stone-600 hover:text-stone-300'}`}
                            title={currentSelectedItem.isLocked ? 'Unlock Item' : 'Lock Item'}
                         >
                            {currentSelectedItem.isLocked ? <Lock className="w-3.5 h-3.5" /> : <Unlock className="w-3.5 h-3.5" />}
                         </button>
                    )}
                </div>
                {currentSelectedItem ? (
                    <div className="flex-1 p-3 md:p-5 flex flex-col animate-in fade-in duration-300 overflow-y-auto custom-scrollbar min-h-0">
                        <div className="flex flex-col items-center text-center mb-4 shrink-0">
                            <div className={`w-12 h-12 md:w-20 md:h-20 bg-stone-900 rounded-full border-2 flex items-center justify-center mb-2 shadow-lg relative ${currentSelectedItem.equipmentData ? getRarityClasses(currentSelectedItem.equipmentData.rarity) : 'border-stone-700'}`}>
                                <AdaptiveInventoryImage item={currentSelectedItem} className="w-8 h-8 md:w-12 md:h-12 object-contain" />
                                <RomanTierOverlay id={currentSelectedItem.id} />
                                {currentSelectedItem.isLocked && (
                                    <div className="absolute -top-1 -right-1 bg-amber-600 text-white p-1 rounded-full border border-stone-900 shadow-lg z-30">
                                        <Lock className="w-2.5 h-2.5 md:w-3.5 md:h-3.5" />
                                    </div>
                                )}
                            </div>
                            <h2 className="text-sm md:text-lg font-bold text-amber-500 font-serif leading-tight">{currentSelectedItem.name}</h2>
                            <div className="flex flex-wrap items-center justify-center gap-1.5 mt-1.5">
                                <span className="text-[7px] md:text-[9px] bg-stone-800 px-1.5 py-0.5 rounded text-stone-400 font-mono uppercase border border-white/5">{currentSelectedItem.type}</span>
                                {currentSelectedItem.equipmentData && (
                                    <span className={`text-[7px] md:text-[9px] px-1.5 py-0.5 rounded font-black uppercase border leading-none shadow-sm ${getRarityClasses(currentSelectedItem.equipmentData.rarity)}`}>
                                        {currentSelectedItem.equipmentData.rarity}
                                    </span>
                                )}
                            </div>
                        </div>

                        <p className="text-stone-400 text-[10px] md:text-xs italic leading-tight text-center mb-4 px-1 shrink-0">"{currentSelectedItem.description}"</p>

                        <div className="flex-1 overflow-y-auto custom-scrollbar min-h-0 pr-1">
                            {renderEquipmentStats(currentSelectedItem)}
                        </div>

                        <div className="mt-4 space-y-2 pt-2 shrink-0">
                            {(currentSelectedItem.type === 'CONSUMABLE' || currentSelectedItem.type === 'SCROLL' || currentSelectedItem.type === 'SKILL_BOOK' || currentSelectedItem.type === 'SKILL_SCROLL') && (
                                <button onClick={handleConsume} className="w-full py-2 bg-emerald-800 hover:bg-emerald-700 text-emerald-100 rounded text-[10px] md:text-sm font-bold transition-all shadow-lg active:scale-[0.98]">
                                    {currentSelectedItem.type === 'SCROLL' ? 'Study Scroll' : 
                                     currentSelectedItem.type === 'SKILL_BOOK' ? 'Study Manual' : 
                                     currentSelectedItem.type === 'SKILL_SCROLL' ? 'Imbue Equipment' :
                                     'Use Item'}
                                </button>
                            )}
                            {currentSelectedItem.baseValue > 0 && currentSelectedItem.type !== 'KEY_ITEM' && (
                                <button 
                                    onClick={handleOpenSellModal} 
                                    disabled={currentSelectedItem.isLocked}
                                    className={`w-full py-2 rounded text-[10px] md:text-sm font-bold border transition-all ${currentSelectedItem.isLocked ? 'bg-stone-900 border-stone-800 text-stone-700 cursor-not-allowed' : 'bg-stone-800 hover:bg-red-900/30 text-stone-300 border-stone-700'}`}
                                >
                                    {currentSelectedItem.isLocked ? <span className="flex items-center justify-center gap-1"><Lock className="w-3 h-3" /> Item Locked</span> : `Sell (${Math.floor(currentSelectedItem.baseValue * 0.5)}G)`}
                                </button>
                            )}
                        </div>
                    </div>
                ) : (
                    <div className="flex-1 flex flex-col items-center justify-center text-stone-600 p-4 text-center">
                        <Package className="w-6 h-6 md:w-8 md:h-8 opacity-20 mb-2" />
                        <p className="text-[10px] md:text-xs">Select an item</p>
                    </div>
                )}
            </div>

            {/* Bulk Sell Modal */}
            {isSellModalOpen && currentSelectedItem && (
                <div className="fixed inset-0 z-[1000] flex items-center justify-center bg-black/80 backdrop-blur-md p-4 animate-in fade-in duration-200">
                    <div className="bg-stone-900 border-2 border-stone-700 rounded-3xl w-full max-w-sm overflow-hidden flex flex-col shadow-2xl animate-in zoom-in-95">
                        <div className="p-4 border-b border-stone-800 bg-stone-850 flex justify-between items-center shrink-0">
                            <h3 className="font-bold text-stone-200 font-serif uppercase tracking-widest text-sm">Sell Inventory</h3>
                            <button onClick={() => setIsSellModalOpen(false)} className="p-1.5 hover:bg-stone-800 rounded-full text-stone-500"><X className="w-5 h-5" /></button>
                        </div>

                        <div className="p-6 flex flex-col items-center gap-6">
                            <div className="flex items-center gap-4 w-full">
                                <div className="w-16 h-16 bg-stone-950 rounded-xl border border-stone-800 flex items-center justify-center shrink-0">
                                    <AdaptiveInventoryImage item={currentSelectedItem} className="w-10 h-10 object-contain" />
                                </div>
                                <div className="flex-1 min-w-0">
                                    <h4 className="text-stone-100 font-black text-sm truncate uppercase">{currentSelectedItem.name}</h4>
                                    <p className="text-stone-500 text-[10px] font-bold">Price per unit: <span className="text-amber-500">{Math.floor(currentSelectedItem.baseValue * 0.5)}G</span></p>
                                </div>
                            </div>

                            <div className="w-full bg-stone-950/50 p-4 rounded-2xl border border-stone-800 flex flex-col items-center gap-3">
                                <span className="text-[8px] font-black text-stone-600 uppercase tracking-[0.2em]">Select Quantity</span>
                                <div className="flex items-center gap-4">
                                    <button 
                                        onClick={() => setSellQuantity(Math.max(1, sellQuantity - 1))}
                                        className="w-10 h-10 bg-stone-800 hover:bg-stone-700 rounded-full flex items-center justify-center text-stone-400 transition-colors border border-stone-700"
                                    >
                                        <Minus className="w-5 h-5" />
                                    </button>
                                    <div className="flex flex-col items-center min-w-[80px]">
                                        <span className="text-3xl font-mono font-black text-stone-100 leading-none">{sellQuantity}</span>
                                        <span className="text-[10px] font-bold text-stone-600 uppercase mt-1">/ {currentSelectedItem.quantity}</span>
                                    </div>
                                    <button 
                                        onClick={() => setSellQuantity(Math.min(currentSelectedItem.quantity, sellQuantity + 1))}
                                        className="w-10 h-10 bg-stone-800 hover:bg-stone-700 rounded-full flex items-center justify-center text-stone-400 transition-colors border border-stone-700"
                                    >
                                        <Plus className="w-5 h-5" />
                                    </button>
                                </div>
                                <div className="flex gap-2 w-full mt-2">
                                    <button 
                                        onClick={() => setSellQuantity(1)}
                                        className="flex-1 py-1.5 bg-stone-900 hover:bg-stone-800 rounded-lg text-[9px] font-black text-stone-500 uppercase border border-stone-800 transition-all"
                                    >
                                        Min
                                    </button>
                                    <button 
                                        onClick={() => setSellQuantity(currentSelectedItem.quantity)}
                                        className="flex-1 py-1.5 bg-stone-900 hover:bg-stone-800 rounded-lg text-[9px] font-black text-amber-500/80 uppercase border border-stone-800 transition-all"
                                    >
                                        Max
                                    </button>
                                </div>
                            </div>

                            <div className="w-full flex justify-between items-center px-2 py-3 border-t border-stone-800">
                                <span className="text-[10px] font-black text-stone-500 uppercase tracking-widest">Total Payout</span>
                                <div className="flex items-center gap-1.5">
                                    <Coins className="w-5 h-5 text-amber-500" />
                                    <span className="text-2xl font-mono font-black text-emerald-400">
                                        {(sellQuantity * Math.floor(currentSelectedItem.baseValue * 0.5)).toLocaleString()} G
                                    </span>
                                </div>
                            </div>
                        </div>

                        <div className="p-4 bg-stone-850 border-t border-stone-800 flex gap-3">
                            <button 
                                onClick={() => setIsSellModalOpen(false)}
                                className="flex-1 py-3 bg-stone-800 hover:bg-stone-700 text-stone-400 font-black rounded-xl text-xs uppercase tracking-widest transition-all"
                            >
                                Cancel
                            </button>
                            <button 
                                onClick={handleConfirmBulkSell}
                                className="flex-[2] py-3 bg-emerald-600 hover:bg-emerald-500 text-white font-black rounded-xl text-xs uppercase tracking-widest transition-all shadow-lg shadow-emerald-900/20 border-b-4 border-emerald-800 active:translate-y-0.5"
                            >
                                Confirm Sale
                            </button>
                        </div>
                    </div>
                </div>
            )}

            {/* Enchant Confirmation Modal */}
            <ConfirmationModal 
                isOpen={!!confirmEnchantTarget}
                title="Apply Skill Scroll"
                message={`Do you want to imbue ${confirmEnchantTarget?.name} with ${enchantingScroll?.skillId ? SKILLS[enchantingScroll.skillId]?.name : 'this skill'}? This scroll will be consumed.`}
                confirmLabel="Apply"
                cancelLabel="Cancel"
                onConfirm={handleConfirmEnchant}
                onCancel={() => setConfirmEnchantTarget(null)}
            />
        </div>
    );
};

import { GameState, GameSettings } from './game-state';
import { EquipmentItem, EquipmentSlotType } from './inventory';
import { ShopCustomer } from './shop';
import { Mercenary } from '../models/Mercenary';
import { PrimaryStats } from '../models/Stats';
import { GameEvent } from './events';

export interface GameContextType {
  state: GameState;
  actions: {
    repairItem: () => void;
    rest: () => void;
    confirmSleep: () => void;
    closeRest: () => void;
    triggerEvent: (event: GameEvent) => void;
    handleEventOption: (action: () => void) => void;
    closeEvent: () => void;

    saveGame: (slotIndex?: number) => void;
    loadGame: (loadedState: GameState) => void;

    startCrafting: (item: EquipmentItem) => void;
