                    {enchantingScroll ? (
                        <button onClick={() => setEnchantingScroll(null)} className="px-2 py-1 bg-red-900/40 hover:bg-red-900/60 rounded text-[9px] md:text-[10px] font-black uppercase text-red-200 border border-red-500/30 transition-all flex items-center gap-1">
