                    </div>
                ) : (
                    <div className="flex-1 flex flex-col items-center justify-center text-stone-600 p-4 text-center">
                        <Package className="w-6 h-6 md:w-8 md:h-8 opacity-20 mb-2" />
                        <p className="text-[10px] md:text-xs">Select an item</p>
                    </div>
                )}
            </div>

            {/* Bulk Sell Modal */}
            {isSellModalOpen && currentSelectedItem && (
                <div className="fixed inset-0 z-[1000] flex items-center justify-center bg-black/80 backdrop-blur-md p-4 animate-in fade-in duration-200">
                    <div className="bg-stone-900 border-2 border-stone-700 rounded-3xl w-full max-w-sm overflow-hidden flex flex-col shadow-2xl animate-in zoom-in-95">
                        <div className="p-4 border-b border-stone-800 bg-stone-850 flex justify-between items-center shrink-0">
                            <h3 className="font-bold text-stone-200 font-serif uppercase tracking-widest text-sm">Sell Inventory</h3>
                            <button onClick={() => setIsSellModalOpen(false)} className="p-1.5 hover:bg-stone-800 rounded-full text-stone-500"><X className="w-5 h-5" /></button>
                        </div>

                        <div className="p-6 flex flex-col items-center gap-6">
                            <div className="flex items-center gap-4 w-full">
                                <div className="w-16 h-16 bg-stone-950 rounded-xl border border-stone-800 flex items-center justify-center shrink-0">
                                    <AdaptiveInventoryImage item={currentSelectedItem} className="w-10 h-10 object-contain" />
                                </div>
                                <div className="flex-1 min-w-0">
                                    <h4 className="text-stone-100 font-black text-sm truncate uppercase">{currentSelectedItem.name}</h4>
                                    <p className="text-stone-500 text-[10px] font-bold">Price per unit: <span className="text-amber-500">{Math.floor(currentSelectedItem.baseValue * 0.5)}G</span></p>
                                </div>
                            </div>

                            <div className="w-full bg-stone-950/50 p-4 rounded-2xl border border-stone-800 flex flex-col items-center gap-3">
                                <span className="text-[8px] font-black text-stone-600 uppercase tracking-[0.2em]">Select Quantity</span>
                                <div className="flex items-center gap-4">
                                    <button 
                                        onClick={() => setSellQuantity(Math.max(1, sellQuantity - 1))}
                                        className="w-10 h-10 bg-stone-800 hover:bg-stone-700 rounded-full flex items-center justify-center text-stone-400 transition-colors border border-stone-700"
                                    >
                                        <Minus className="w-5 h-5" />
                                    </button>
                                    <div className="flex flex-col items-center min-w-[80px]">
                                        <span className="text-3xl font-mono font-black text-stone-100 leading-none">{sellQuantity}</span>
                                        <span className="text-[10px] font-bold text-stone-600 uppercase mt-1">/ {currentSelectedItem.quantity}</span>
                                    </div>
                                    <button 
                                        onClick={() => setSellQuantity(Math.min(currentSelectedItem.quantity, sellQuantity + 1))}
                                        className="w-10 h-10 bg-stone-800 hover:bg-stone-700 rounded-full flex items-center justify-center text-stone-400 transition-colors border border-stone-700"
                                    >
                                        <Plus className="w-5 h-5" />
                                    </button>
                                </div>
                                <div className="flex gap-2 w-full mt-2">
                                    <button 
                                        onClick={() => setSellQuantity(1)}
                                        className="flex-1 py-1.5 bg-stone-900 hover:bg-stone-800 rounded-lg text-[9px] font-black text-stone-500 uppercase border border-stone-800 transition-all"
                                    >
                                        Min
                                    </button>
                                    <button 
                                        onClick={() => setSellQuantity(currentSelectedItem.quantity)}
                                        className="flex-1 py-1.5 bg-stone-900 hover:bg-stone-800 rounded-lg text-[9px] font-black text-amber-500/80 uppercase border border-stone-800 transition-all"
                                    >
                                        Max
                                    </button>
                                </div>
                            </div>

                            <div className="w-full flex justify-between items-center px-2 py-3 border-t border-stone-800">
                                <span className="text-[10px] font-black text-stone-500 uppercase tracking-widest">Total Payout</span>
                                <div className="flex items-center gap-1.5">
                                    <Coins className="w-5 h-5 text-amber-500" />
                                    <span className="text-2xl font-mono font-black text-emerald-400">
                                        {(sellQuantity * Math.floor(currentSelectedItem.baseValue * 0.5)).toLocaleString()} G
                                    </span>
                                </div>
                            </div>
                        </div>

                        <div className="p-4 bg-stone-850 border-t border-stone-800 flex gap-3">
                            <button 
                                onClick={() => setIsSellModalOpen(false)}
                                className="flex-1 py-3 bg-stone-800 hover:bg-stone-700 text-stone-400 font-black rounded-xl text-xs uppercase tracking-widest transition-all"
                            >
                                Cancel
                            </button>
                            <button 
                                onClick={handleConfirmBulkSell}
                                className="flex-[2] py-3 bg-emerald-600 hover:bg-emerald-500 text-white font-black rounded-xl text-xs uppercase tracking-widest transition-all shadow-lg shadow-emerald-900/20 border-b-4 border-emerald-800 active:translate-y-0.5"
                            >
                                Confirm Sale
                            </button>
                        </div>
                    </div>
                </div>
            )}

            {/* Enchant Confirmation Modal */}
            <ConfirmationModal 
                isOpen={!!confirmEnchantTarget}
                title="Apply Skill Scroll"
                message={`Do you want to imbue ${confirmEnchantTarget?.name} with ${enchantingScroll?.skillId ? SKILLS[enchantingScroll.skillId]?.name : 'this skill'}? This scroll will be consumed to permanently add an ability to the gear.`}
                confirmLabel="Confirm Imbuement"
                cancelLabel="Cancel"
                onConfirm={handleConfirmEnchant}
                onCancel={() => setConfirmEnchantTarget(null)}
            />
        </div>
    );
};

import React from 'react';
import { X } from 'lucide-react';
import { useGame } from '../../context/GameContext';
import { Mercenary } from '../../models/Mercenary';
import { EquipmentSlotType } from '../../types/inventory';
import { useMercenaryDetail } from '../../hooks/useMercenaryDetail';
import { calculateMercenaryPower } from '../../utils/combatLogic';
import { MercenaryPaperDoll } from '../mercenary/MercenaryPaperDoll';
import { MercenaryStatsPanel } from '../mercenary/MercenaryStatsPanel';
import { EquipmentInventoryList } from '../mercenary/EquipmentInventoryList';
import { SfxButton } from '../common/ui/SfxButton';

interface MercenaryDetailModalProps {
  mercenary: Mercenary | null;
  onClose: () => void;
  onUnequip: (mercId: string, slot: EquipmentSlotType) => void;
  onEquip?: (mercId: string, itemId: string) => void; 
  onConsume?: (mercId: string, itemId: string) => void; 
  isReadOnly?: boolean;
}

export const MercenaryDetailModal: React.FC<MercenaryDetailModalProps> = ({ 
  mercenary, 
  onClose, 
  onUnequip, 
  onEquip,
  onConsume,
  isReadOnly = false 
}) => {
  const { state, actions } = useGame();
  const {
      selectedSlot,
      selectedInventoryItemId,
      setSelectedInventoryItemId,
      pendingAllocated,
      pendingPoints,
      isInventoryOpen,
      handleModifyStat,
      handleSaveAttributes,
      handleResetAttributes,
      handleSlotClick,
      handleToggleInventory,
      currentEqPrimaryStats,
      currentStats,
      currentCombatPower,
      preview
  } = useMercenaryDetail(mercenary);

  if (!mercenary || !currentStats) return null;

  const isHired = mercenary.status !== 'VISITOR' && mercenary.status !== 'DEAD';

  const effectiveFinalStats = preview?.stats || currentStats;
  const effectiveCombatPower = preview?.combatPower !== undefined ? preview.combatPower : currentCombatPower;
  const effectiveEqPrimaryStats = preview?.eqPrimaryStats || currentEqPrimaryStats;

  return (
    <div className="fixed inset-0 z-[1000] flex items-center justify-center bg-black/95 backdrop-blur-2xl p-2 md:p-6 py-[10dvh] md:py-6 animate-in fade-in duration-300 overflow-hidden">
      <SfxButton
        sfx="switch"
        onClick={onClose}
        className="fixed top-4 right-4 z-[1050] p-1.5 md:p-3 bg-red-900/30 hover:bg-red-600 rounded-full text-red-500 hover:text-white border border-red-500/30 transition-all shadow-2xl backdrop-blur-md active:scale-90"
      >
        <X className="w-4 h-4 md:w-6 md:h-6" />
      </SfxButton>

      <div className={`w-full h-full md:max-w-7xl md:h-[90dvh] bg-stone-950 border border-white/10 rounded-2xl md:rounded-[2rem] shadow-2xl flex flex-col md:flex-row overflow-hidden relative ring-1 ring-white/10 transition-all duration-500`}>

        <div className={`flex flex-col overflow-hidden transition-all duration-500 border-stone-800 ${isHired && isInventoryOpen ? 'w-full md:w-[45%] h-1/2 md:h-full border-b md:border-b-0 md:border-r' : 'w-full h-full'}`}>
          <div className="flex-1 overflow-y-auto custom-scrollbar bg-stone-900/20">
            <MercenaryPaperDoll
              mercenary={mercenary}
              currentCombatPower={calculateMercenaryPower(mercenary)}
              nextCombatPower={effectiveCombatPower}
              showAffinityGain={false}
              onUnequip={(slot) => onUnequip(mercenary.id, slot)}
              onSlotClick={handleSlotClick}
              selectedSlot={selectedSlot}
              isReadOnly={isReadOnly}
              isInventoryOpen={isInventoryOpen}
              onToggleInventory={handleToggleInventory}
              isHired={isHired}
            />
            <MercenaryStatsPanel
              mercenary={mercenary}
              baseStats={currentStats}
              finalStats={effectiveFinalStats}
              pendingAllocated={pendingAllocated}
              pendingPoints={pendingPoints}
              equipmentStats={effectiveEqPrimaryStats}
              previewEquipmentStats={preview?.eqPrimaryStats || null}
              onModifyStat={handleModifyStat}
              onSave={handleSaveAttributes}
              onReset={handleResetAttributes}
              isReadOnly={isReadOnly}
            />
          </div>
        </div>

        {isHired && (
          <div className={`bg-stone-950/20 flex flex-col transition-all duration-500 overflow-hidden ${isInventoryOpen ? 'flex-1 h-1/2 md:h-full opacity-100' : 'w-0 h-0 md:h-full opacity-0'}`}>
            <EquipmentInventoryList
              inventory={state.inventory.filter((i) => i.type === 'EQUIPMENT' || i.type === 'CONSUMABLE' || i.type === 'SKILL_BOOK')}
              selectedItemId={selectedInventoryItemId}
              onSelect={setSelectedInventoryItemId}
              onEquip={(id) => {
                if (onEquip) {
                  onEquip(mercenary.id, id);
                } else {
                  actions.equipItem(mercenary.id, id);
                }
                setSelectedInventoryItemId(null);
              }}
              onConsume={(id) => {
                if (onConsume) {
                  onConsume(mercenary.id, id);
                } else {
                  actions.useItem(id, mercenary.id);
                }
                setSelectedInventoryItemId(null);
              }}
              selectedSlotFilter={selectedSlot}
              mercenary={mercenary}
              isReadOnly={isReadOnly}
              onToggleInventory={handleToggleInventory}
            />
          </div>
        )}
      </div>
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { 
  Box, Sword, Shield, Sparkles, FlaskConical, Package, 
  ChevronRight, AlertCircle, Check, X, BookOpen 
} from 'lucide-react';
import { InventoryItem, EquipmentSlotType } from '../../types/inventory';
import { Mercenary } from '../../models/Mercenary';
import { PrimaryStats, mergePrimaryStats } from '../../models/Stats';
import { getAssetUrl } from '../../utils';
import { SfxButton } from '../common/ui/SfxButton';

type CategoryFilter = 'ALL' | 'WEAPON' | 'ARMOR' | 'ACCESSORY' | 'CONSUMABLE' | 'SKILL';

interface EquipmentInventoryListProps {
  inventory: InventoryItem[];
  selectedItemId: string | null;
  onSelect: (itemId: string) => void;
  onEquip: (itemId: string) => void;
  onConsume: (itemId: string) => void;
  selectedSlotFilter: EquipmentSlotType | null;
  mercenary: Mercenary;
  isReadOnly?: boolean;
  onToggleInventory: () => void;
}

const getRarityClasses = (rarity?: string) => {
  switch (rarity) {
    case 'Legendary':
      return 'text-amber-400 border-amber-500/50 bg-amber-950/40';
    case 'Epic':
      return 'text-purple-400 border-purple-500/50 bg-purple-950/40';
    case 'Rare':
      return 'text-blue-400 border-blue-500/50 bg-blue-950/40';
    case 'Uncommon':
      return 'text-emerald-400 border-emerald-500/50 bg-emerald-950/40';
    default:
      return 'text-stone-400 border-stone-700/50 bg-stone-900/40';
  }
};

const getQualityLabel = (q: number): string => {
  if (q >= 110) return 'MASTERWORK';
  if (q >= 100) return 'PRISTINE';
  if (q >= 90) return 'SUPERIOR';
  if (q >= 80) return 'FINE';
  if (q >= 70) return 'STANDARD';
  if (q >= 60) return 'RUSTIC';
  return 'CRUDE';
};

export const EquipmentInventoryList: React.FC<EquipmentInventoryListProps> = ({
  inventory,
  selectedItemId,
  onSelect,
  onEquip,
  onConsume,
  selectedSlotFilter,
  mercenary,
  isReadOnly,
  onToggleInventory,
}) => {
  const [activeFilter, setActiveFilter] = useState<CategoryFilter>('ALL');

  const displayInventory = useMemo(() => {
    let filtered = inventory;

    if (selectedSlotFilter) {
      return filtered.filter((item) => item.equipmentData?.slotType === selectedSlotFilter);
    }

    if (activeFilter === 'WEAPON') {
      return filtered.filter((item) => item.equipmentData?.slotType === 'MAIN_HAND');
    }
    if (activeFilter === 'ARMOR') {
      return filtered.filter((item) => 
        ['HEAD', 'BODY', 'LEGS', 'HANDS', 'FEET', 'OFF_HAND'].includes(item.equipmentData?.slotType || '')
      );
    }
    if (activeFilter === 'ACCESSORY') {
      return filtered.filter((item) => ['ACCESSORY', 'WAIST'].includes(item.equipmentData?.slotType || ''));
    }
    if (activeFilter === 'CONSUMABLE') {
      return filtered.filter((item) => item.type === 'CONSUMABLE' || item.type === 'SKILL_BOOK');
    }
    if (activeFilter === 'SKILL') {
      return filtered.filter((item) => item.type === 'SKILL_BOOK');
    }

    return filtered;
  }, [inventory, selectedSlotFilter, activeFilter]);

  const filterChips: { id: CategoryFilter; label: string; icon: React.ReactNode }[] = [
    { id: 'ALL', label: 'All', icon: <Box className="w-3 h-3" /> },
    { id: 'WEAPON', label: 'Weapons', icon: <Sword className="w-3 h-3" /> },
    { id: 'ARMOR', label: 'Armor', icon: <Shield className="w-3 h-3" /> },
    { id: 'ACCESSORY', label: 'Accessory', icon: <Sparkles className="w-3 h-3" /> },
    { id: 'CONSUMABLE', label: 'Items', icon: <FlaskConical className="w-3 h-3" /> },
    { id: 'SKILL', label: 'Manuals', icon: <BookOpen className="w-3 h-3" /> },
  ];

  return (
    <div className="flex-1 flex flex-col min-h-0">
      <div 
        onClick={onToggleInventory}
        className="p-4 md:p-6 bg-stone-950 border-b border-white/5 flex justify-between items-center shrink-0 z-10 backdrop-blur-md cursor-pointer hover:bg-stone-900 transition-colors group"
      >
        <div className="flex flex-col">
            <h3 className="text-[10px] md:text-sm font-black text-stone-100 uppercase tracking-widest flex items-center gap-2 group-hover:text-amber-500 transition-colors">
            <Package className="w-4 h-4 text-amber-600" />
            <span>{selectedSlotFilter ? `Filtering: ${selectedSlotFilter}` : 'Squad Inventory'}</span>
            </h3>
            <span className="text-[7px] md:text-[10px] text-stone-500 font-mono mt-0.5 uppercase">Click Header to Close</span>
        </div>
        <div className="flex items-center gap-3">
          <span className="text-[8px] md:text-xs text-stone-600 font-mono bg-stone-900 px-2 py-0.5 rounded border border-stone-800">{displayInventory.length} ITEMS</span>
          <ChevronRight className="w-4 h-4 text-stone-700 group-hover:text-amber-500 group-hover:translate-x-0.5 transition-all" />
        </div>
      </div>

      {!selectedSlotFilter && (
        <div className="px-3 md:px-6 py-2 md:py-3 bg-stone-950/40 border-b border-white/5 flex gap-2 overflow-x-auto no-scrollbar shrink-0">
          {filterChips.map((chip) => (
            <SfxButton
              key={chip.id}
              sfx="switch"
              onClick={() => setActiveFilter(chip.id)}
              className={`flex items-center gap-1.5 px-3 py-1.5 rounded-full border text-[9px] md:text-[10px] font-black uppercase tracking-tighter transition-all whitespace-nowrap ${
                activeFilter === chip.id
                  ? 'bg-amber-600 border-amber-400 text-white shadow-glow-sm'
                  : 'bg-stone-800 border-stone-700 text-stone-500 hover:text-stone-300'
              }`}
            >
              {chip.icon}
              {chip.label}
            </SfxButton>
          ))}
        </div>
      )}

      <div className="flex-1 overflow-y-auto custom-scrollbar p-3 md:p-6 space-y-2 md:space-y-3">
        {displayInventory.length === 0 ? (
          <div className="h-full flex flex-col items-center justify-center text-stone-800 italic p-12 text-center">
            <Box className="w-12 h-12 opacity-10 mb-2" />
            <p className="text-xs">No suitable items found.</p>
            {selectedSlotFilter && (
              <SfxButton 
                sfx="switch"
                onClick={onToggleInventory}
                className="mt-4 px-4 py-2 bg-stone-800 text-stone-400 rounded-lg text-[10px] uppercase font-bold hover:text-stone-200"
              >
                Back to View All
              </SfxButton>
            )}
          </div>
        ) : (
          displayInventory.map((item) => {
            const isConsumable = item.type === 'CONSUMABLE' || item.type === 'SKILL_BOOK';
            const isSkillBook = item.type === 'SKILL_BOOK';
            const isSelected = selectedItemId === item.id;

            const minLevel = item.equipmentData?.minLevel || 1;
            const canEquip = isConsumable || (mercenary.level >= minLevel);

            const rarityClasses = isConsumable ? 'text-stone-400 border-stone-700 bg-stone-900/40' : getRarityClasses(item.equipmentData?.rarity);
            const imageUrl = item.type === 'EQUIPMENT' && item.equipmentData
              ? (item.equipmentData.image
                  ? getAssetUrl(item.equipmentData.image, 'equipments')
                  : item.equipmentData.recipeId
                    ? getAssetUrl(`${item.equipmentData.recipeId}.png`, 'equipments')
                    : getAssetUrl(`${item.id.split('_')[0]}.png`, 'equipments'))
              : getAssetUrl(`${item.id}.png`, isSkillBook ? 'skills' : 'materials');

            return (
              <div
                key={item.id}
                onClick={() => !isSelected && onSelect(item.id)}
                className={`flex flex-col gap-2 p-3 md:p-5 rounded-xl border transition-all ${
                  isSelected ? 'border-amber-500 bg-stone-900/80 shadow-inner' : 'border-stone-800 bg-stone-900/30'
                } cursor-pointer group relative overflow-hidden ${!isConsumable && !canEquip ? 'opacity-60' : ''}`}
              >
                <div className="flex items-center gap-3 md:gap-4">
                  <div className={`w-10 h-10 md:w-16 md:h-16 bg-stone-950 rounded-lg border-2 flex items-center justify-center shrink-0 ${rarityClasses}`}>
                    <img src={imageUrl} className="w-8 h-8 md:w-12 md:h-12 object-contain" alt={item.name} />
                  </div>

                  <div className="flex-1 min-w-0">
                    <div className="text-[11px] md:text-lg font-black truncate text-stone-200">{item.name}</div>
                    <div className="flex wrap items-center gap-2 mt-1">
                      <span className={`text-[7px] md:text-[9px] px-1.5 py-0.5 rounded font-black uppercase border leading-none ${rarityClasses}`}>
                        {isSkillBook ? 'MANUAL' : isConsumable ? 'CONSUMABLE' : item.equipmentData?.rarity}
                      </span>
                      {item.quantity > 1 && (
                        <span className="text-[7px] md:text-[9px] text-stone-500 font-mono font-bold">
                          QTY: {item.quantity}
                        </span>
                      )}
                    </div>
                  </div>

                  {!isReadOnly && isSelected && !isConsumable && canEquip && (
                    <SfxButton
                      onClick={(e) => {
                        e.stopPropagation();
                        onEquip(item.id);
                      }}
                      className="shrink-0 px-3 md:px-8 py-1.5 md:py-3 bg-amber-700 hover:bg-amber-600 text-white text-[9px] md:text-xs font-black uppercase rounded shadow-lg transition-all"
                    >
                      Equip
                    </SfxButton>
                  )}

                  {!isReadOnly && isSelected && isConsumable && (
                    <div className="absolute top-0 right-0 h-full w-24 md:w-32 bg-stone-900/95 border-l border-amber-600/30 flex flex-col animate-in slide-in-from-right-full duration-200 z-30">
                        <SfxButton 
                            onClick={(e) => { e.stopPropagation(); onConsume(item.id); }}
                            className="flex-1 flex flex-col items-center justify-center gap-1 hover:bg-emerald-900/40 text-emerald-400 transition-colors"
                        >
                            <Check className="w-4 h-4" />
                            <span className="text-[8px] md:text-[10px] font-black uppercase">{isSkillBook ? 'Study Manual' : 'Consume'}</span>
                        </SfxButton>
                        <div className="h-px w-full bg-amber-600/10" />
                        <SfxButton 
                            sfx="switch"
                            onClick={(e) => { e.stopPropagation(); onSelect(""); }}
                            className="flex-1 flex flex-col items-center justify-center gap-1 hover:bg-red-900/40 text-stone-500 hover:text-red-400 transition-colors"
                        >
                            <X className="w-4 h-4" />
                            <span className="text-[8px] md:text-[10px] font-black uppercase">Cancel</span>
                        </SfxButton>
                    </div>
                  )}
                </div>

                {!isConsumable && !canEquip && isSelected && (
                  <div className="bg-red-950/20 border border-red-900/30 rounded-lg p-2 flex items-center gap-2 text-[8px] md:text-[10px] text-red-400 font-bold uppercase tracking-tight">
                    <AlertCircle className="w-3 h-3 shrink-0" />
                    Requires Level {minLevel} (Current: {mercenary.level})
                  </div>
                )}

                <div className="flex justify-between items-center border-t border-white/5 pt-2">
                   <div className="flex items-center gap-2">
                        {isConsumable ? (
                             <span className="text-[7px] md:text-[9px] text-stone-500 italic truncate max-w-[150px]">
                                {item.description}
                             </span>
                        ) : (
                            <div className="flex items-center gap-2">
                                <span className="text-[7px] md:text-[9px] text-amber-600 font-black uppercase tracking-tighter bg-amber-950/20 px-1.5 py-0.5 rounded border border-amber-900/20">
                                {getQualityLabel(item.equipmentData?.quality || 100)}
                                </span>
                                <span className={`text-[7px] md:text-[9px] font-black uppercase px-1.5 py-0.5 rounded border ${mercenary.level >= minLevel ? 'text-stone-500 border-stone-800' : 'text-red-500 border-red-900/30 bg-red-900/10'}`}>
                                    Req. Lv.{minLevel}
                                </span>
                            </div>
                        )}
                    </div>
                    {!isConsumable && item.equipmentData && (
                        <div className="flex items-center gap-2 text-[8px] md:xs text-stone-600 font-mono">
                            {(item.equipmentData.stats.physicalAttack > 0 || item.equipmentData.stats.magicalAttack > 0) && (
                                <span className="flex items-center gap-1"><Sword className="w-2.5 h-2.5" /> {item.equipmentData.stats.physicalAttack || item.equipmentData.stats.magicalAttack}</span>
                            )}
                            {(item.equipmentData.stats.physicalDefense > 0 || item.equipmentData.stats.magicalDefense > 0) && (
                                <span className="flex items-center gap-1"><Shield className="w-2.5 h-2.5" /> {item.equipmentData.stats.physicalDefense || item.equipmentData.stats.magicalDefense}</span>
                            )}
                        </div>
                    )}
                </div>
              </div>
            );
          })
        )}
      </div>
    </div>
  );
};

import React, { useState, useMemo, useEffect } from 'react';
import { useGame } from '../context/GameContext';
import { 
    Package, Sword, Shield, Coins, Info, Zap, Wrench, ShieldAlert, AlertCircle, 
    Brain, Lock, Unlock, Star, Sparkles, X, Minus, Plus, ChevronRight, Wand2
} from 'lucide-react';
import { InventoryItem } from '../types/index';
import { getAssetUrl } from '../utils';
import ConfirmationModal from './modals/ConfirmationModal';
import { SKILLS } from '../data/skills';

const RomanTierOverlay = ({ id }: { id: string }) => {
    if (id === 'scroll_t2') return <div className="absolute inset-0 flex items-center justify-center pointer-events-none"><span className="text-amber-500 font-serif font-black text-xs md:text-xl drop-shadow-[0_2px_2px_rgba(0,0,0,0.8)] translate-y-1">II</span></div>;
    if (id === 'scroll_t3') return <div className="absolute inset-0 flex items-center justify-center pointer-events-none"><span className="text-amber-500 font-serif font-black text-xs md:text-xl drop-shadow-[0_2px_2px_rgba(0,0,0,0.8)] translate-y-1">III</span></div>;
    if (id === 'scroll_t4') return <div className="absolute inset-0 flex items-center justify-center pointer-events-none"><span className="text-amber-500 font-serif font-black text-xs md:text-xl drop-shadow-[0_2px_2px_rgba(0,0,0,0.8)] translate-y-1">IV</span></div>;
    return null;
};

const AdaptiveInventoryImage = ({ item, className }: { item: InventoryItem, className?: string }) => {
    const isEquip = item.type === 'EQUIPMENT';
    const isSkill = item.type === 'SKILL_BOOK' || item.type === 'SKILL_SCROLL';
    const folder = isEquip ? 'equipments' : isSkill ? 'skills' : 'materials';

    const baseId = (isEquip && item.equipmentData?.recipeId) 
        ? item.equipmentData.recipeId 
        : item.id;

    const [imgSrc, setImgSrc] = useState(getAssetUrl(`${baseId}.png`, folder));

    // 아이템 데이터가 변경될 때 이미지 경로 상태를 동기화합니다.
    useEffect(() => {
        setImgSrc(getAssetUrl(`${baseId}.png`, folder));
    }, [baseId, folder]);

    const handleImgError = () => {
        const fallbackPath = item.image || item.equipmentData?.image;
        if (fallbackPath && imgSrc !== getAssetUrl(fallbackPath, folder)) {
            setImgSrc(getAssetUrl(fallbackPath, folder));
        }
    };

    return <img src={imgSrc} onError={handleImgError} className={className} />;
};

export const InventoryDisplay = () => {
    const { state, actions } = useGame();
    const [selectedItemId, setSelectedItemId] = useState<string | null>(null);
    const [isSellModalOpen, setIsSellModalOpen] = useState(false);
    const [sellQuantity, setSellQuantity] = useState(1);

    // 인챈트(스크롤 부여) 관련 상태
    const [enchantingScroll, setEnchantingScroll] = useState<InventoryItem | null>(null);
    const [confirmEnchantTarget, setConfirmEnchantTarget] = useState<InventoryItem | null>(null);

    const currentSelectedItem = useMemo(() => 
        state.inventory.find(i => i.id === selectedItemId) || null
    , [state.inventory, selectedItemId]);

    const handleSelect = (item: InventoryItem) => {
        // 인챈트 모드일 때 로직
        if (enchantingScroll) {
            if (item.type === 'EQUIPMENT') {
                if (item.isLocked) {
                    actions.showToast("Cannot enchant a locked item.");
                    return;
                }
                setConfirmEnchantTarget(item);
            }
            return;
        }
        setSelectedItemId(item.id);
    };

    const handleOpenSellModal = () => {
        if (!currentSelectedItem || currentSelectedItem.isLocked) return;
        setSellQuantity(1);
        setIsSellModalOpen(true);
    };

    const handleConfirmBulkSell = () => {
        if (!currentSelectedItem) return;
        const sellPricePerItem = Math.floor(currentSelectedItem.baseValue * 0.5);
        const totalPrice = sellPricePerItem * sellQuantity;

        actions.sellItem(
            currentSelectedItem.id, 
            sellQuantity, 
            totalPrice, 
            currentSelectedItem.type === 'EQUIPMENT' ? currentSelectedItem.id : undefined
        );

        setIsSellModalOpen(false);
        // If we sold all items, deselect
        if (currentSelectedItem.quantity <= sellQuantity) {
            setSelectedItemId(null);
        }
    };

    const handleUseScroll = () => {
        if (!currentSelectedItem || currentSelectedItem.type !== 'SKILL_SCROLL') return;
        setEnchantingScroll(currentSelectedItem);
    };

    const handleConfirmEnchant = () => {
        if (enchantingScroll && confirmEnchantTarget) {
            actions.applySkillScroll(enchantingScroll.id, confirmEnchantTarget.id);
            setEnchantingScroll(null);
            setConfirmEnchantTarget(null);
            actions.showToast("Equipment enchanted successfully!");
        }
    };

    const handleConsume = () => {
        if (!currentSelectedItem) return;
        if (currentSelectedItem.type === 'SKILL_SCROLL') {
            handleUseScroll();
            return;
        }
        actions.useItem(currentSelectedItem.id);
        if (currentSelectedItem.quantity <= 1) setSelectedItemId(null);
    };

    const getQualityLabel = (q: number): string => {
        if (q >= 110) return 'MASTERWORK';
        if (q >= 100) return 'PRISTINE';
        if (q >= 90) return 'SUPERIOR';
        if (q >= 80) return 'FINE';
        if (q >= 70) return 'STANDARD';
        if (q >= 60) return 'RUSTIC';
        return 'CRUDE';
    };

    const getRarityClasses = (rarity?: string) => {
        switch (rarity) {
            case 'Legendary': return 'text-amber-400 border-amber-500/50 bg-amber-950/40';
            case 'Epic': return 'text-purple-400 border-purple-500/50 bg-purple-950/40';
            case 'Rare': return 'text-blue-400 border-blue-500/50 bg-blue-950/40';
            case 'Uncommon': return 'text-emerald-400 border-emerald-500/50 bg-emerald-950/40';
            default: return 'text-stone-400 border-stone-700/50 bg-stone-900/40';
        }
    };

    const renderEquipmentStats = (item: InventoryItem) => {
        if (!item.equipmentData?.stats) return null;
        const s = item.equipmentData.stats;
        const isMagical = s.magicalAttack > s.physicalAttack || s.magicalDefense > s.physicalDefense;
        const atkLabel = isMagical ? "M.ATK" : "P.ATK";
        const defLabel = isMagical ? "M.DEF" : "P.DEF";
        const atkValue = isMagical ? s.magicalAttack : s.physicalAttack;
        const defValue = isMagical ? s.magicalDefense : s.physicalDefense;

        const socketedSkill = item.equipmentData.socketedSkillId ? SKILLS[item.equipmentData.socketedSkillId] : null;

        return (
            <div className="mb-4 space-y-2 shrink-0">
                <div className="grid grid-cols-2 gap-1.5">
                    <div className="flex justify-between bg-stone-900 p-1.5 rounded border border-stone-800 text-[9px] md:text-[10px]">
                        <span className="text-stone-500 uppercase flex items-center gap-1">
                            {isMagical ? <Zap className="w-2 h-2 text-blue-400" /> : <Sword className="w-2 h-2 text-stone-500" />}
                            {atkLabel}
                        </span>
                        <span className="font-mono text-stone-200 font-bold">{atkValue}</span>
                    </div>
                    <div className="flex justify-between bg-stone-900 p-1.5 rounded border border-stone-800 text-[9px] md:text-[10px]">
                        <span className="text-stone-500 uppercase flex items-center gap-1">
                            {isMagical ? <Brain className="w-2 h-2 text-purple-400" /> : <Shield className="w-2 h-2 text-stone-500" />}
                            {defLabel}
                        </span>
                        <span className="font-mono text-stone-200 font-bold">{defValue}</span>
                    </div>
                </div>
                {item.equipmentData.quality && (
                     <div className="flex justify-between bg-stone-900 p-1.5 rounded border border-stone-800 text-[9px] md:text-[10px]">
                        <span className="text-stone-500 uppercase flex items-center gap-1">
                            <Sparkles className="w-2 h-2 text-amber-500" /> Quality
                        </span>
                        <span className="font-black text-amber-500 uppercase tracking-tighter">{getQualityLabel(item.equipmentData.quality)}</span>
                    </div>
                )}
                {socketedSkill && (
                    <div className="bg-indigo-900/30 border border-indigo-500/30 p-2 rounded-lg mt-2">
                        <div className="flex items-center gap-2 mb-1">
                            <Wand2 className="w-3 h-3 text-indigo-400" />
                            <span className="text-[10px] font-black text-indigo-200 uppercase tracking-widest">Socketed Skill</span>
                        </div>
                        <div className="text-xs font-bold text-white">{socketedSkill.name}</div>
                        <p className="text-[9px] text-stone-400 italic leading-tight mt-1">{socketedSkill.description}</p>
                    </div>
                )}
            </div>
        );
    };

    return (
        <div className="flex flex-row h-full w-full max-w-7xl mx-auto p-2 md:p-4 gap-2 md:gap-4 overflow-hidden relative">

            {/* Storage List Section */}
            <div className="flex-[1.5] md:flex-[2.5] bg-slate-900 rounded-xl border border-slate-700 overflow-hidden flex flex-col min-w-0 relative">
                <div className={`bg-slate-800/50 p-2 md:p-3 border-b border-slate-700 flex items-center justify-between shrink-0 transition-colors duration-500 ${enchantingScroll ? 'bg-amber-900/60' : ''}`}>
                    <div className="flex items-center gap-2">
                        <Package className="w-3.5 h-3.5 md:w-4 md:h-4 text-amber-50" />
                        <h3 className="text-slate-200 text-xs md:text-sm uppercase tracking-wider font-bold">
                            {enchantingScroll ? 'Select Equipment to Imbue' : 'Storage'}
                        </h3>
                    </div>
                    {enchantingScroll ? (
                        <button onClick={() => setEnchantingScroll(null)} className="px-3 py-1 bg-red-600 hover:bg-red-500 rounded-full text-[9px] md:text-[10px] font-black uppercase text-white shadow-lg transition-all flex items-center gap-1 active:scale-95">
                            <X className="w-3 h-3" /> Cancel
                        </button>
                    ) : (
                        <span className="text-[10px] text-slate-500 font-mono">{state.inventory.length}</span>
                    )}
                </div>

                {enchantingScroll && (
                    <div className="bg-amber-600 px-3 py-1.5 border-b border-amber-400/50 text-[9px] md:text-[11px] text-white font-black uppercase tracking-widest flex items-center justify-center gap-2 animate-in slide-in-from-top-2 duration-300">
                        <Sparkles className="w-3 h-3 animate-spin-slow" />
                        Targeting: {enchantingScroll.name}
                    </div>
                )}

                <div className="p-2 overflow-y-auto flex-1 custom-scrollbar min-h-0 bg-stone-950/20">
                    {state.inventory.length === 0 ? (
                        <div className="text-slate-500 text-center py-12 italic text-xs">Empty</div>
                    ) : (
                        <div className="grid grid-cols-2 xs:grid-cols-3 sm:grid-cols-4 lg:grid-cols-5 gap-2 pb-8">
                            {state.inventory.map(item => {
                                const isSelected = selectedItemId === item.id;
                                const isEnchantTarget = enchantingScroll && item.type === 'EQUIPMENT';
                                const isEnchantRestricted = enchantingScroll && item.type !== 'EQUIPMENT';

                                return (
                                    <button
                                        key={item.id} onClick={() => handleSelect(item)}
                                        disabled={!!isEnchantRestricted}
                                        className={`relative flex flex-col items-center p-2 rounded-lg border transition-all h-20 md:h-28 justify-between ${
                                            isSelected && !enchantingScroll ? 'bg-amber-900/20 border-amber-500 shadow-md ring-1 ring-amber-500/50' : 
                                            isEnchantTarget ? 'bg-amber-500/10 border-amber-500 ring-4 ring-amber-500/40 animate-pulse shadow-[0_0_20px_rgba(245,158,11,0.3)] z-10' :
                                            isEnchantRestricted ? 'opacity-20 grayscale cursor-not-allowed border-transparent' :
                                            'bg-slate-800/50 border-slate-700/50 hover:bg-slate-800 hover:border-slate-600'
                                        }`}
                                    >
                                        <div className="absolute top-1 right-1 bg-slate-950/80 px-1 rounded text-[8px] md:text-[10px] text-slate-400 font-mono flex items-center gap-1 z-20">
                                            {item.isLocked && <Lock className="w-2 h-2 md:w-2.5 md:h-2.5 text-amber-500" />}
                                            x{item.quantity}
                                        </div>
                                        <div className="flex-1 flex items-center justify-center relative">
                                             <AdaptiveInventoryImage item={item} className="w-6 h-6 md:w-10 md:h-10 object-contain drop-shadow-lg" />
                                             <RomanTierOverlay id={item.id} />
                                        </div>
                                        <div className="text-[9px] md:text-xs text-center font-bold text-slate-300 w-full truncate px-1">{item.name}</div>
                                    </button>
                                );
                            })}
                        </div>
                    )}
                </div>
            </div>

            {/* Details Section */}
            <div className="flex-1 md:w-96 bg-black rounded-xl border border-stone-800 overflow-hidden flex flex-col min-w-0 transition-opacity duration-300" style={{ opacity: enchantingScroll ? 0.4 : 1 }}>
                <div className="bg-stone-900/50 p-2 md:p-3 border-b border-stone-800 flex items-center justify-between shrink-0">
                    <div className="flex items-center gap-2">
                        <Info className="w-3.5 h-3.5 md:w-4 md:h-4 text-stone-500" />
                        <h3 className="text-stone-400 text-[10px] md:text-xs uppercase tracking-wider font-bold">Details</h3>
                    </div>
                    {currentSelectedItem && (
                         <button 
                            onClick={() => actions.toggleLockItem(currentSelectedItem.id)}
                            className={`p-1.5 rounded-lg border transition-all ${currentSelectedItem.isLocked ? 'bg-amber-950/40 border-amber-600/50 text-amber-500' : 'bg-stone-900 border-stone-800 text-stone-600 hover:text-stone-300'}`}
                            title={currentSelectedItem.isLocked ? 'Unlock Item' : 'Lock Item'}
                         >
                            {currentSelectedItem.isLocked ? <Lock className="w-3.5 h-3.5" /> : <Unlock className="w-3.5 h-3.5" />}
                         </button>
                    )}
                </div>
                {currentSelectedItem ? (
                    <div className="flex-1 p-3 md:p-5 flex flex-col animate-in fade-in duration-300 overflow-y-auto custom-scrollbar min-h-0">
                        <div className="flex flex-col items-center text-center mb-4 shrink-0">
                            <div className={`w-12 h-12 md:w-20 md:h-20 bg-stone-900 rounded-full border-2 flex items-center justify-center mb-2 shadow-lg relative ${currentSelectedItem.equipmentData ? getRarityClasses(currentSelectedItem.equipmentData.rarity) : 'border-stone-700'}`}>
                                <AdaptiveInventoryImage item={currentSelectedItem} className="w-8 h-8 md:w-12 md:h-12 object-contain" />
                                <RomanTierOverlay id={currentSelectedItem.id} />
                                {currentSelectedItem.isLocked && (
                                    <div className="absolute -top-1 -right-1 bg-amber-600 text-white p-1 rounded-full border border-stone-900 shadow-lg z-30">
                                        <Lock className="w-2.5 h-2.5 md:w-3.5 md:h-3.5" />
                                    </div>
                                )}
                            </div>
                            <h2 className="text-sm md:text-lg font-bold text-amber-500 font-serif leading-tight">{currentSelectedItem.name}</h2>
                            <div className="flex flex-wrap items-center justify-center gap-1.5 mt-1.5">
                                <span className="text-[7px] md:text-[9px] bg-stone-800 px-1.5 py-0.5 rounded text-stone-400 font-mono uppercase border border-white/5">{currentSelectedItem.type}</span>
                                {currentSelectedItem.equipmentData && (
                                    <span className={`text-[7px] md:text-[9px] px-1.5 py-0.5 rounded font-black uppercase border leading-none shadow-sm ${getRarityClasses(currentSelectedItem.equipmentData.rarity)}`}>
                                        {currentSelectedItem.equipmentData.rarity}
                                    </span>
                                )}
                            </div>
                        </div>

                        <p className="text-stone-400 text-[10px] md:text-xs italic leading-tight text-center mb-4 px-1 shrink-0">"{currentSelectedItem.description}"</p>

                        <div className="flex-1 overflow-y-auto custom-scrollbar min-h-0 pr-1">
                            {renderEquipmentStats(currentSelectedItem)}
                        </div>

                        <div className="mt-4 space-y-2 pt-2 shrink-0">
                            {(currentSelectedItem.type === 'CONSUMABLE' || currentSelectedItem.type === 'SCROLL' || currentSelectedItem.type === 'SKILL_BOOK' || currentSelectedItem.type === 'SKILL_SCROLL') && (
                                <button onClick={handleConsume} className="w-full py-2 bg-emerald-800 hover:bg-emerald-700 text-emerald-100 rounded text-[10px] md:text-sm font-bold transition-all shadow-lg active:scale-[0.98]">
                                    {currentSelectedItem.type === 'SCROLL' ? 'Study Scroll' : 
                                     currentSelectedItem.type === 'SKILL_BOOK' ? 'Study Manual' : 
                                     currentSelectedItem.type === 'SKILL_SCROLL' ? 'Imbue Equipment' :
                                     'Use Item'}
                                </button>
                            )}
                            {currentSelectedItem.baseValue > 0 && currentSelectedItem.type !== 'KEY_ITEM' && (
                                <button 
                                    onClick={handleOpenSellModal} 
                                    disabled={currentSelectedItem.isLocked}
                                    className={`w-full py-2 rounded text-[10px] md:text-sm font-bold border transition-all ${currentSelectedItem.isLocked ? 'bg-stone-900 border-stone-800 text-stone-700 cursor-not-allowed' : 'bg-stone-800 hover:bg-red-900/30 text-stone-300 border-stone-700'}`}
                                >
                                    {currentSelectedItem.isLocked ? <span className="flex items-center justify-center gap-1"><Lock className="w-3 h-3" /> Item Locked</span> : `Sell (${Math.floor(currentSelectedItem.baseValue * 0.5)}G)`}
                                </button>
                            )}
                        </div>
                    </div>
                ) : (
                    <div className="flex-1 flex flex-col items-center justify-center text-stone-600 p-4 text-center">
                        <Package className="w-6 h-6 md:w-8 md:h-8 opacity-20 mb-2" />
                        <p className="text-[10px] md:text-xs">Select an item</p>
                    </div>
                )}
            </div>

            {/* Bulk Sell Modal */}
            {isSellModalOpen && currentSelectedItem && (
                <div className="fixed inset-0 z-[1000] flex items-center justify-center bg-black/80 backdrop-blur-md p-4 animate-in fade-in duration-200">
                    <div className="bg-stone-900 border-2 border-stone-700 rounded-3xl w-full max-w-sm overflow-hidden flex flex-col shadow-2xl animate-in zoom-in-95">
                        <div className="p-4 border-b border-stone-800 bg-stone-850 flex justify-between items-center shrink-0">
                            <h3 className="font-bold text-stone-200 font-serif uppercase tracking-widest text-sm">Sell Inventory</h3>
                            <button onClick={() => setIsSellModalOpen(false)} className="p-1.5 hover:bg-stone-800 rounded-full text-stone-500"><X className="w-5 h-5" /></button>
                        </div>

                        <div className="p-6 flex flex-col items-center gap-6">
                            <div className="flex items-center gap-4 w-full">
                                <div className="w-16 h-16 bg-stone-950 rounded-xl border border-stone-800 flex items-center justify-center shrink-0">
                                    <AdaptiveInventoryImage item={currentSelectedItem} className="w-10 h-10 object-contain" />
                                </div>
                                <div className="flex-1 min-w-0">
                                    <h4 className="text-stone-100 font-black text-sm truncate uppercase">{currentSelectedItem.name}</h4>
                                    <p className="text-stone-500 text-[10px] font-bold">Price per unit: <span className="text-amber-500">{Math.floor(currentSelectedItem.baseValue * 0.5)}G</span></p>
                                </div>
                            </div>

                            <div className="w-full bg-stone-950/50 p-4 rounded-2xl border border-stone-800 flex flex-col items-center gap-3">
                                <span className="text-[8px] font-black text-stone-600 uppercase tracking-[0.2em]">Select Quantity</span>
                                <div className="flex items-center gap-4">
                                    <button 
                                        onClick={() => setSellQuantity(Math.max(1, sellQuantity - 1))}
                                        className="w-10 h-10 bg-stone-800 hover:bg-stone-700 rounded-full flex items-center justify-center text-stone-400 transition-colors border border-stone-700"
                                    >
                                        <Minus className="w-5 h-5" />
                                    </button>
                                    <div className="flex flex-col items-center min-w-[80px]">
                                        <span className="text-3xl font-mono font-black text-stone-100 leading-none">{sellQuantity}</span>
                                        <span className="text-[10px] font-bold text-stone-600 uppercase mt-1">/ {currentSelectedItem.quantity}</span>
                                    </div>
                                    <button 
                                        onClick={() => setSellQuantity(Math.min(currentSelectedItem.quantity, sellQuantity + 1))}
                                        className="w-10 h-10 bg-stone-800 hover:bg-stone-700 rounded-full flex items-center justify-center text-stone-400 transition-colors border border-stone-700"
                                    >
                                        <Plus className="w-5 h-5" />
                                    </button>
                                </div>
                                <div className="flex gap-2 w-full mt-2">
                                    <button 
                                        onClick={() => setSellQuantity(1)}
                                        className="flex-1 py-1.5 bg-stone-900 hover:bg-stone-800 rounded-lg text-[9px] font-black text-stone-500 uppercase border border-stone-800 transition-all"
                                    >
                                        Min
                                    </button>
                                    <button 
                                        onClick={() => setSellQuantity(currentSelectedItem.quantity)}
                                        className="flex-1 py-1.5 bg-stone-900 hover:bg-stone-800 rounded-lg text-[9px] font-black text-amber-500/80 uppercase border border-stone-800 transition-all"
                                    >
                                        Max
                                    </button>
                                </div>
                            </div>

                            <div className="w-full flex justify-between items-center px-2 py-3 border-t border-stone-800">
                                <span className="text-[10px] font-black text-stone-500 uppercase tracking-widest">Total Payout</span>
                                <div className="flex items-center gap-1.5">
                                    <Coins className="w-5 h-5 text-amber-500" />
                                    <span className="text-2xl font-mono font-black text-emerald-400">
                                        {(sellQuantity * Math.floor(currentSelectedItem.baseValue * 0.5)).toLocaleString()} G
                                    </span>
                                </div>
                            </div>
                        </div>

                        <div className="p-4 bg-stone-850 border-t border-stone-800 flex gap-3">
                            <button 
                                onClick={() => setIsSellModalOpen(false)}
                                className="flex-1 py-3 bg-stone-800 hover:bg-stone-700 text-stone-400 font-black rounded-xl text-xs uppercase tracking-widest transition-all"
                            >
                                Cancel
                            </button>
                            <button 
                                onClick={handleConfirmBulkSell}
                                className="flex-[2] py-3 bg-emerald-600 hover:bg-emerald-500 text-white font-black rounded-xl text-xs uppercase tracking-widest transition-all shadow-lg shadow-emerald-900/20 border-b-4 border-emerald-800 active:translate-y-0.5"
                            >
                                Confirm Sale
                            </button>
                        </div>
                    </div>
                </div>
            )}

            {/* Enchant Confirmation Modal */}
            <ConfirmationModal 
                isOpen={!!confirmEnchantTarget}
                title="Apply Skill Scroll"
                message={`Do you want to imbue ${confirmEnchantTarget?.name} with ${enchantingScroll?.skillId ? SKILLS[enchantingScroll.skillId]?.name : 'this skill'}? This scroll will be consumed to permanently add an ability to the gear.`}
                confirmLabel="Confirm Imbuement"
                cancelLabel="Cancel"
                onConfirm={handleConfirmEnchant}
                onCancel={() => setConfirmEnchantTarget(null)}
            />
        </div>
    );
};

import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import { Shield, Sword, Activity, Skull, Zap, LogOut, FastForward, Pause, Play, ChevronDown, ChevronUp, Sparkles, Target, Package, X, Check, RotateCcw } from 'lucide-react';
import { Mercenary } from '../../../models/Mercenary';
import { Monster } from '../../../models/Monster';
import { ManualDungeonSession } from '../../../types/game-state';
import { calculateCombatResult } from '../../../utils/combatLogic';
import { calculateDerivedStats, applyEquipmentBonuses, mergePrimaryStats } from '../../../models/Stats';
import { useGame } from '../../../context/GameContext';
import { SKILLS } from '../../../data/skills';
import { MercenaryPortrait } from '../../common/ui/MercenaryPortrait';
import { getAssetUrl } from '../../../utils';
import { InventoryItem, EquipmentSlotType } from '../../../types/inventory';
import { MercenaryDetailModal } from '../../modals/MercenaryDetailModal';
import { DUNGEONS } from '../../../data/dungeons';
import { SfxButton } from '../../common/ui/SfxButton';

const ACTION_THRESHOLD = 1000;

interface CombatLogEntry {
    msg: string;
    team: 'PLAYER' | 'ENEMY' | 'SYSTEM';
    isCrit?: boolean;
    isSkill?: boolean;
}

interface DamagePopup {
    id: number;
    value: number;
    targetId: string;
    isCrit: boolean;
    isSkill: boolean;
}

interface DungeonCombatViewProps {
    session: ManualDungeonSession;
    party: Mercenary[];
    enemies: Monster[];
    fleeChance: number;
    onFinish: (win: boolean, finalParty: any[]) => void;
    onFlee: (finalParty: any[]) => void;
}

const DungeonCombatView: React.FC<DungeonCombatViewProps> = ({ session, party, enemies, fleeChance, onFinish, onFlee }) => {
    const { state, actions } = useGame();
    const [orientation, setOrientation] = useState<'PORTRAIT' | 'LANDSCAPE'>(
        window.innerWidth > window.innerHeight ? 'LANDSCAPE' : 'PORTRAIT'
    );

    const dungeonInfo = useMemo(() => DUNGEONS.find(d => d.id === session.dungeonId), [session.dungeonId]);

    const [partyState, setPartyState] = useState(party.map(m => {
        const primary = mergePrimaryStats(m.stats, m.allocatedStats);
        const derived = applyEquipmentBonuses(calculateDerivedStats(primary, m.level), (Object.values(m.equipment) as any[]).map(e=>e?.stats).filter(Boolean) as any);
        return { ...m, derived, currentHp: m.currentHp, currentMp: m.currentMp, gauge: 0, lastDamaged: false };
    }));

    const [enemySquadState, setEnemySquadState] = useState(enemies.map((e, idx) => ({
        ...e,
        instanceId: `enemy_${idx}`,
        gauge: 0,
        lastDamaged: false,
        hasUsedRevival: false
    })));

    const [logs, setLogs] = useState<CombatLogEntry[]>([]);
    const [damagePopups, setDamagePopups] = useState<DamagePopup[]>([]);

    // --- PERSISTENCE: 설정 데이터 유지 ---
    const [isAuto, setIsAuto] = useState(() => {
        const saved = localStorage.getItem('dungeon_combat_auto');
        return saved === null ? true : saved === 'true';
    });

    const [battleSpeed, setBattleSpeed] = useState<1 | 2 | 4>(() => {
        const saved = localStorage.getItem('dungeon_combat_speed');
        const parsed = saved ? parseInt(saved) : 1; 
        if (parsed === 1 || parsed === 2 || parsed === 4) return parsed as 1 | 2 | 4;
        return 1;
    });

    useEffect(() => {
        localStorage.setItem('dungeon_combat_auto', isAuto.toString());
    }, [isAuto]);

    useEffect(() => {
        localStorage.setItem('dungeon_combat_speed', battleSpeed.toString());
    }, [battleSpeed]);

    const [isPaused, setIsPaused] = useState(false);
    const [activeActorId, setActiveActorId] = useState<string | null>(null); 
    const [attackingUnitId, setAttackingUnitId] = useState<string | null>(null);
    const [showLogs, setShowLogs] = useState(false);

    const [pendingAction, setPendingAction] = useState<{ type: 'ATTACK' | 'SKILL', skillId?: string } | null>(null);
    const [inspectedMercId, setInspectedMercId] = useState<string | null>(null);

    const battleInterval = useRef<ReturnType<typeof setInterval> | null>(null);
    const speedRef = useRef(1);

    useEffect(() => {
        speedRef.current = battleSpeed;
    }, [battleSpeed]);

    useEffect(() => {
        const handleResize = () => {
            setOrientation(window.innerWidth > window.innerHeight ? 'LANDSCAPE' : 'PORTRAIT');
        };
        window.addEventListener('resize', handleResize);
        return () => window.removeEventListener('resize', handleResize);
    }, []);

    const addLog = useCallback((msg: string, team: 'PLAYER' | 'ENEMY' | 'SYSTEM', isCrit = false, isSkill = false) => {
        setLogs(prev => [{ msg, team, isCrit, isSkill }, ...prev].slice(0, 50));
    }, []);

    const triggerDamagePopup = useCallback((targetId: string, value: number, isCrit: boolean, isSkill: boolean) => {
        const id = Date.now() + Math.random();
        setDamagePopups(prev => [...prev, { id, value, targetId, isCrit, isSkill }]);
        setTimeout(() => {
            setDamagePopups(prev => prev.filter(p => p.id !== id));
        }, 800 / speedRef.current);
    }, []);

    const executeAttack = useCallback((attacker: any, target: any, isPlayerAttacker: boolean, skillId?: string) => {
        setAttackingUnitId(isPlayerAttacker ? attacker.id : target.instanceId);

        setTimeout(() => {
            const skill = skillId ? SKILLS[skillId] : null;
            const multiplier = skill ? skill.multiplier : 1.0;
            const mpCost = skill?.mpCost ?? 0;

            const res = calculateCombatResult(
                isPlayerAttacker ? attacker.derived : attacker.stats,
                isPlayerAttacker ? target.stats : target.derived,
                isPlayerAttacker ? attacker.job : 'Fighter' as any,
                isPlayerAttacker ? (attacker.derived.magicalAttack > attacker.derived.physicalAttack ? 'MAGICAL' : 'PHYSICAL') : 'PHYSICAL',
                multiplier
            );

            // 명중/회피 시 효과음 출력
            if (res.isHit) {
                window.dispatchEvent(new CustomEvent('play-sfx', { detail: { file: 'battle_slash.mp3' } }));
            } else {
                window.dispatchEvent(new CustomEvent('play-sfx', { detail: { file: 'swing_miss.mp3' } }));
            }

            if (isPlayerAttacker) {
                setEnemySquadState(prev => prev.map(e => {
                    if (e.instanceId === target.instanceId) {
                        const next = { ...e, lastDamaged: res.isHit };
                        if (res.isHit) {
                            let nextHp = Math.max(0, next.currentHp - res.damage);
                            if (nextHp <= 0 && next.id === 'phoenix' && !next.hasUsedRevival) {
                                nextHp = next.stats.maxHp;
                                next.hasUsedRevival = true;
                                addLog("Phoenix rebirth triggered!", 'ENEMY', true, true);
                                triggerDamagePopup(target.instanceId, 0, true, true);
                            } else {
                                next.currentHp = nextHp;
                            }
                            triggerDamagePopup(target.instanceId, res.damage, res.isCrit, !!skill);
                        }
                        setTimeout(() => setEnemySquadState(curr => curr.map(currE => currE.instanceId === target.instanceId ? { ...currE, lastDamaged: false } : currE)), 200 / speedRef.current);
                        return next;
                    }
                    return e;
                }));

                if (skill) {
                    setPartyState(prev => prev.map(p => p.id === attacker.id ? { ...p, currentMp: Math.max(0, p.currentMp - mpCost) } : p));
                    addLog(`${attacker.name} used ${skill.name}!`, 'PLAYER', res.isCrit, true);
                } else {
                    addLog(`${attacker.name} hits ${target.name} for ${res.damage}`, 'PLAYER', res.isCrit);
                }
            } else {
                setPartyState(prev => prev.map(p => {
                    if (p.id === target.id) {
                        const next = { ...p, lastDamaged: res.isHit };
                        if (res.isHit) {
                            next.currentHp = Math.max(0, next.currentHp - res.damage);
                            triggerDamagePopup(p.id, res.damage, res.isCrit, false);
                        }
                        setTimeout(() => setPartyState(curr => curr.map(c => c.id === p.id ? { ...c, lastDamaged: false } : c)), 200 / speedRef.current);
                        return next;
                    }
                    return p;
                }));
                addLog(`${attacker.name} strikes ${target.name} for ${res.damage}`, 'ENEMY');
            }

            setTimeout(() => setAttackingUnitId(null), 150 / speedRef.current);
        }, 200 / speedRef.current);
    }, [addLog, triggerDamagePopup]);

    const processLoop = useCallback(() => {
        if (isPaused || activeActorId || attackingUnitId || inspectedMercId) return;

        const enemiesDefeated = enemySquadState.every(e => e.currentHp <= 0);
        const partyDefeated = partyState.every(p => p.currentHp <= 0);

        if (enemiesDefeated) {
            setIsPaused(true);
            setTimeout(() => onFinish(true, partyState), 800 / speedRef.current);
            return;
        }
        if (partyDefeated) {
            setIsPaused(true);
            setTimeout(() => onFinish(false, partyState), 800 / speedRef.current);
            return;
        }

        // --- SPEED BALANCING: 기초 게이지 충전량 0.2로 고정 ---
        setPartyState(prev => {
            const next = [...prev];
            let readyMerc = null;
            for (let p of next) {
                if (p.currentHp > 0) {
                    p.gauge += (p.derived.speed * 0.2 * speedRef.current); 
                    if (p.gauge >= ACTION_THRESHOLD && !readyMerc) readyMerc = p;
                }
            }
            if (readyMerc && !attackingUnitId) {
                const livingEnemies = enemySquadState.filter(e => e.currentHp > 0);
                if (livingEnemies.length > 0) {
                    if (isAuto) {
                        readyMerc.gauge -= ACTION_THRESHOLD;
                        const target = livingEnemies[Math.floor(Math.random() * livingEnemies.length)];
                        let sid = undefined;
                        if (readyMerc.skillIds && readyMerc.skillIds.length > 0) {
                            const skill = SKILLS[readyMerc.skillIds[0]];
                            if (skill && readyMerc.currentMp >= (skill.mpCost ?? 0) && Math.random() < 0.3) sid = skill.id;
                        }
                        executeAttack(readyMerc, target, true, sid);
                    } else {
                        setActiveActorId(readyMerc.id);
                    }
                }
            }
            return next;
        });

        setEnemySquadState(prev => {
            const next = [...prev];
            let readyEnemy = null;
            for (let e of next) {
                if (e.currentHp > 0) {
                    e.gauge += (e.stats.speed * 0.2 * speedRef.current); 
                    if (e.gauge >= ACTION_THRESHOLD && !readyEnemy) readyEnemy = e;
                }
            }
            if (readyEnemy && !activeActorId && !attackingUnitId) {
                readyEnemy.gauge -= ACTION_THRESHOLD;
                const livingPlayers = partyState.filter(p => p.currentHp > 0);
                if (livingPlayers.length > 0) {
                    const target = livingPlayers[Math.floor(Math.random() * livingPlayers.length)];
                    executeAttack(readyEnemy, target, false);
                }
            }
            return next;
        });
    }, [isPaused, isAuto, activeActorId, attackingUnitId, inspectedMercId, enemySquadState, partyState, executeAttack, onFinish]);

    useEffect(() => {
        battleInterval.current = setInterval(processLoop, 100);
        return () => { if (battleInterval.current) clearInterval(battleInterval.current); };
    }, [processLoop]);

    const handleTurnConsumed = useCallback((targetMercId: string) => {
        setTimeout(() => {
            const updatedMercFromContext = state.knownMercenaries.find(m => m.id === targetMercId);
            if (updatedMercFromContext) {
                setPartyState(prev => prev.map(p => {
                    if (p.id === targetMercId) {
                        const primary = mergePrimaryStats(updatedMercFromContext.stats, updatedMercFromContext.allocatedStats);
                        const derived = applyEquipmentBonuses(
                            calculateDerivedStats(primary, updatedMercFromContext.level), 
                            (Object.values(updatedMercFromContext.equipment) as any[]).map(e=>e?.stats).filter(Boolean) as any
                        );
                        return { 
                            ...p, 
                            ...updatedMercFromContext, 
                            derived,
                            currentHp: updatedMercFromContext.currentHp,
                            currentMp: updatedMercFromContext.currentMp,
                            gauge: Math.max(0, p.gauge - ACTION_THRESHOLD)
                        };
                    }
                    return p;
                }));
                setInspectedMercId(null);
                setActiveActorId(null);
            }
        }, 50);
    }, [state.knownMercenaries]);

    const handleManualAction = (e: React.MouseEvent, type: 'ATTACK' | 'SKILL', skillId?: string) => {
        e.stopPropagation(); 
        if (!activeActorId) return;
        setPendingAction({ type, skillId });
    };

    const handleEnemyClick = (target: any) => {
        if (!activeActorId || !pendingAction) return;
        if (target.currentHp <= 0) return;
        const actor = partyState.find(p => p.id === activeActorId);
        if (!actor) return;
        setPartyState(prev => prev.map(p => p.id === activeActorId ? { ...p, gauge: p.gauge - ACTION_THRESHOLD } : p));
        executeAttack(actor, target, true, pendingAction.skillId);
        setPendingAction(null);
        setActiveActorId(null);
    };

    const handleFlee = (e: React.MouseEvent) => {
        e.stopPropagation();
        if (Math.random() * 100 < fleeChance) {
            onFlee(partyState);
        } else {
            addLog("Escape failed!", 'SYSTEM');
            setActiveActorId(null);
            setPendingAction(null);
            setPartyState(prev => prev.map(p => p.id === activeActorId ? { ...p, gauge: 0 } : p));
        }
    };

    const getUnitStyle = (id: string, side: 'PLAYER' | 'ENEMY'): React.CSSProperties => {
        if (attackingUnitId !== id) return {};
        let transform = orientation === 'PORTRAIT' 
            ? (side === 'PLAYER' ? 'translateY(-120px) scale(1.1)' : 'translateY(120px) scale(1.1)')
            : (side === 'PLAYER' ? 'translateX(120px) scale(1.1)' : 'translateX(-120px) scale(1.1)');
        return { transform, zIndex: 100 };
    };

    return (
        <div className="fixed inset-0 z-[150] flex flex-col bg-stone-950 animate-in fade-in duration-500 overflow-hidden font-sans pb-safe">
            <style>{`
                @keyframes damage-float { 0% { transform: translateY(0); opacity: 1; } 100% { transform: translateY(-60px); opacity: 0; } }
                .animate-damage { animation: damage-float 1s ease-out forwards; }
                @keyframes unit-shake { 0%, 100% { transform: translate(0,0); } 25% { transform: translate(-4px, 2px); } 50% { transform: translate(4px, -2px); } 75% { transform: translate(-2px, -4px); } }
                .animate-hit { animation: unit-shake 0.2s ease-in-out 3; }
                @keyframes target-pulse { 0% { transform: scale(1); box-shadow: 0 0 0 0 rgba(239, 68, 68, 0.7); } 70% { transform: scale(1.05); box-shadow: 0 0 0 10px rgba(239, 68, 68, 0); } 100% { transform: scale(1); } }
                .animate-target { animation: target-pulse 1.5s infinite; }
            `}</style>

            {/* Background Tile Layer */}
            {dungeonInfo?.tile && (
                <div className="absolute inset-0 z-0 overflow-hidden pointer-events-none">
                    <img 
                        src={getAssetUrl(dungeonInfo.tile, 'dungeons')} 
                        className="w-full h-full object-cover opacity-60 brightness-[0.6]" 
                        alt="Combat Background" 
                    />
                </div>
            )}

            {/* Top Bar */}
            <div className="p-3 bg-red-950/20 border-b border-red-900/30 flex justify-between items-center z-[200] backdrop-blur-sm">
                <div className="flex items-center gap-2">
                    <Skull className="w-4 h-4 text-red-50" />
                    <h2 className="text-white font-black uppercase text-[10px] md:text-sm tracking-widest font-mono">Combat Zone</h2>
                </div>
                <div className="flex items-center gap-3 bg-black/40 px-3 py-1 rounded-full border border-white/5">
                    <SfxButton sfx="switch" onClick={() => setIsPaused(!isPaused)} className={`p-1.5 rounded-full transition-all ${isPaused ? 'bg-amber-600 text-white' : 'bg-stone-800 text-stone-400'}`}>
                        {isPaused ? <Play size={14} /> : <Pause size={14} />}
                    </SfxButton>
                    <div className="flex items-center gap-1">
                        {[1, 2, 4].map(s => (
                            <SfxButton sfx="switch" key={s} onClick={() => setBattleSpeed(s as any)} className={`px-2 py-0.5 rounded font-mono text-[8px] md:text-[10px] font-black ${battleSpeed === s ? 'bg-indigo-600 text-white' : 'text-stone-600'}`}>{s}x</SfxButton>
                        ))}
                    </div>
                </div>
                <SfxButton sfx="switch" onClick={() => { setIsAuto(!isAuto); setPendingAction(null); }} className={`px-4 py-1.5 rounded-lg border font-black text-[9px] tracking-widest transition-all ${isAuto ? 'bg-amber-600 border-amber-400 text-white' : 'bg-stone-800 border-stone-600 text-stone-400'}`}>
                    {isAuto ? 'AUTO' : 'MANUAL'}
                </SfxButton>
            </div>

            {/* Combat Field */}
            <div className={`flex-1 flex relative transition-all duration-700 z-10 ${orientation === 'PORTRAIT' ? 'flex-col' : 'flex-row'}`}>
                {/* Enemies Area */}
                <div className={`flex flex-1 items-center justify-center p-4 gap-6 md:gap-12 ${orientation === 'PORTRAIT' ? 'order-1' : 'order-2'}`}>
                    {enemySquadState.map(e => (
                        <div key={e.instanceId} style={getUnitStyle(e.instanceId, 'ENEMY')} onClick={() => pendingAction && e.currentHp > 0 && handleEnemyClick(e)} className={`relative flex flex-col items-center transition-all ${e.currentHp <= 0 ? 'opacity-20 grayscale' : e.lastDamaged ? 'animate-hit' : ''}`}>
                            <div className={`w-24 h-24 md:w-48 md:h-48 bg-stone-900 rounded-2xl border-2 flex items-center justify-center relative shadow-2xl ${e.lastDamaged ? 'border-red-500 bg-red-950/20' : 'border-stone-800'} ${pendingAction && e.currentHp > 0 ? 'animate-target border-red-500 cursor-crosshair' : ''}`}>
                                <img src={getAssetUrl(e.sprite || '', 'monsters')} className="w-[80%] h-[80%] object-contain" alt={e.name} />
                                {pendingAction && e.currentHp > 0 && <div className="absolute inset-0 flex items-center justify-center"><Target className="w-12 h-12 text-red-500 opacity-50" /></div>}
                                <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
                                    {damagePopups.filter(p => p.targetId === e.instanceId).map(p => (
                                        <div key={p.id} className={`absolute font-black text-3xl md:text-5xl animate-damage ${p.isCrit ? 'text-amber-400 scale-125' : 'text-red-500'}`}>-{p.value}</div>
                                    ))}
                                </div>
                            </div>
                            {e.currentHp > 0 && (
                                <div className="mt-2 w-24 md:w-52 space-y-1">
                                    <div className="flex flex-col items-center leading-none mb-1">
                                        <span className="text-[9px] md:text-xs font-black text-stone-300 uppercase tracking-tighter truncate w-full text-center">{e.name}</span>
                                        <span className="text-[7px] md:text-[9px] font-bold text-stone-500 uppercase tracking-widest">Lv.{e.level}</span>
                                    </div>
                                    <div className="relative h-2.5 bg-black rounded-full overflow-hidden border border-white/5">
                                        <div className="h-full bg-red-600 transition-all duration-500" style={{ width: `${(e.currentHp/e.stats.maxHp)*100}%` }} />
                                        <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
                                            <span className="text-[7px] md:text-[10px] font-mono font-black text-white drop-shadow-sm">{Math.floor(e.currentHp)} / {e.stats.maxHp}</span>
                                        </div>
                                    </div>
                                    <div className="h-1 bg-black rounded-full overflow-hidden">
                                        <div className="h-full bg-amber-500 transition-all" style={{ width: `${(e.gauge/ACTION_THRESHOLD)*100}%` }} />
                                    </div>
                                </div>
                            )}
                        </div>
                    ))}
                </div>

                {/* Players Area */}
                <div className={`flex flex-1 items-center justify-center p-4 gap-6 md:gap-12 ${orientation === 'PORTRAIT' ? 'order-3 pt-0' : 'order-1'}`}>
                    {partyState.map(p => {
                        const isActive = activeActorId === p.id;
                        const hpPer = (p.currentHp / p.derived.maxHp) * 100;
                        const mpPer = (p.currentMp / (p.derived.maxMp || 1)) * 100;

                        return (
                            <div key={p.id} style={getUnitStyle(p.id, 'PLAYER')} className={`relative flex flex-col items-center transition-all ${p.currentHp <= 0 ? 'opacity-20 grayscale' : isActive ? '-translate-y-4' : ''} ${p.lastDamaged ? 'animate-hit' : ''}`}>
                                {/* Portrait Container */}
                                <div className={`w-24 h-24 md:w-48 md:h-48 bg-stone-900 rounded-2xl border-2 flex items-center justify-center relative shadow-2xl ${isActive ? 'border-amber-400 ring-4 ring-amber-500/20' : 'border-stone-800'}`}>
                                    <MercenaryPortrait mercenary={p} className="w-[85%] h-[85%] rounded-xl" />
                                    <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
                                        {damagePopups.filter(pop => pop.targetId === p.id).map(pop => (
                                            <div key={pop.id} className="absolute font-black text-3xl md:text-5xl animate-damage text-red-50">-{pop.value}</div>
                                        ))}
                                    </div>
                                    {isActive && !pendingAction && !isAuto && (
                                        <div className="absolute -bottom-36 left-1/2 -translate-x-1/2 z-[300] bg-stone-900/95 border-2 border-amber-500 p-2 rounded-xl flex gap-3 shadow-2xl animate-in slide-in-from-top-2 backdrop-blur-md">
                                            <SfxButton onClick={(e) => handleManualAction(e, 'ATTACK')} className="p-3 bg-stone-800 hover:bg-stone-700 rounded-lg text-white transition-colors border border-white/5"><Sword size={24} /></SfxButton>
                                            <SfxButton sfx="switch" onClick={(e) => { e.stopPropagation(); setInspectedMercId(p.id); }} className="p-3 bg-indigo-900/40 hover:bg-indigo-800 rounded-lg text-indigo-100 transition-colors border border-indigo-500/30"><Package size={24} /></SfxButton>
                                            <SfxButton onClick={(e) => handleFlee(e)} className="p-3 bg-red-950/40 hover:bg-red-900 rounded-lg text-red-500 transition-colors border border-red-500/30"><LogOut size={24} /></SfxButton>
                                        </div>
                                    )}
                                </div>

                                {p.currentHp > 0 && (
                                    <div className="mt-2 w-24 md:w-52 space-y-1">
                                        {/* Full Name, Job, Level */}
                                        <div className="flex flex-col items-center leading-none mb-1">
                                            <span className="text-[9px] md:text-xs font-black text-stone-100 uppercase tracking-tighter truncate w-full text-center">{p.name}</span>
                                            <span className="text-[7px] md:text-[10px] font-bold text-stone-500 uppercase tracking-widest mt-0.5">{p.job} • Lv.{p.level}</span>
                                        </div>

                                        {/* HP Bar & Value */}
                                        <div className="relative h-3 bg-black rounded-full overflow-hidden border border-white/5 shadow-inner">
                                            <div className={`h-full transition-all duration-500 ${hpPer < 30 ? 'bg-red-500 animate-pulse' : 'bg-red-600'}`} style={{ width: `${hpPer}%` }} />
                                            <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
                                                <span className="text-[7px] md:text-[11px] font-mono font-black text-white drop-shadow-sm">{Math.floor(p.currentHp)} / {p.derived.maxHp}</span>
                                            </div>
                                        </div>

                                        {/* MP Bar & Value */}
                                        <div className="relative h-2.5 bg-black rounded-full overflow-hidden border border-white/5 shadow-inner">
                                            <div className="h-full bg-blue-600 transition-all duration-500" style={{ width: `${mpPer}%` }} />
                                            <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
                                                <span className="text-[6px] md:text-[9px] font-mono font-black text-blue-100 drop-shadow-sm">{Math.floor(p.currentMp)} / {p.derived.maxMp}</span>
                                            </div>
                                        </div>

                                        {/* ATB Gauge */}
                                        <div className="h-1 bg-black rounded-full overflow-hidden">
                                            <div className="h-full bg-amber-500 transition-all" style={{ width: `${(p.gauge/ACTION_THRESHOLD)*100}%` }} />
                                        </div>
                                    </div>
                                )}
                            </div>
                        );
                    })}
                </div>
            </div>

            {/* Tactical Feed */}
            <div className={`bg-stone-900 border-t border-stone-800 flex flex-col shrink-0 transition-all z-10 ${showLogs ? 'h-48' : 'h-18'}`}>
                <button onClick={() => setShowLogs(!showLogs)} className="w-full h-10 flex items-center justify-between px-4 bg-black/20 hover:bg-black/40 transition-colors shrink-0">
                    <div className="flex items-center gap-2">
                        <Activity className={`w-3.5 h-3.5 ${isPaused ? 'text-stone-600' : 'text-amber-500 animate-pulse'}`} />
                        <span className="text-[9px] font-black text-stone-500 uppercase tracking-widest">Engagement Feed</span>
                    </div>
                    {showLogs ? <ChevronDown size={14} /> : <ChevronUp size={14} />}
                </button>
                <div className={`flex-1 ${showLogs ? 'overflow-y-auto' : 'overflow-hidden'} p-2 space-y-1 font-mono text-[9px] custom-scrollbar`}>
                    {(showLogs ? logs : logs.slice(0, 1)).map((log, i) => (
                        <div key={i} className={`p-1.5 border-l-2 ${log.team === 'PLAYER' ? 'border-blue-500 text-blue-100' : log.team === 'ENEMY' ? 'border-red-500 text-red-100' : 'border-stone-700 text-stone-400'} ${log.isCrit ? 'bg-white/5 font-black' : ''}`}>
                            <span className="opacity-30 mr-2">[{new Date().toLocaleTimeString([], { hour12: false, minute: '2-digit', second: '2-digit' })}]</span>
                            {log.msg}
                        </div>
                    ))}
                </div>
            </div>

            {/* Modals */}
            {inspectedMercId && (
                <MercenaryDetailModal 
                    mercenary={partyState.find(p => p.id === inspectedMercId) || null}
                    onClose={() => setInspectedMercId(null)}
                    onEquip={(mercId, itemId) => { actions.equipItem(mercId, itemId); handleTurnConsumed(mercId); }}
                    onConsume={(mercId, itemId) => { actions.useItem(itemId, mercId); handleTurnConsumed(mercId); }}
                    onUnequip={(mercId, slot) => { actions.unequipItem(mercId, slot); handleTurnConsumed(mercId); }}
                    isReadOnly={false} 
                />
            )}
        </div>
    );
};

export default DungeonCombatView;

import React, { useMemo } from 'react';
import { 
  Sword, Shield, Activity, Star, Zap, Brain, Target, Wind, 
  Plus, Minus, RotateCcw, Save, Heart, Sparkles, Wrench
} from 'lucide-react';
import { Mercenary } from '../../models/Mercenary';
import { DerivedStats, PrimaryStats } from '../../models/Stats';
import { SKILLS } from '../../data/skills';
import { StatDiff } from './StatDiff';
import { SfxButton } from '../common/ui/SfxButton';

interface MercenaryStatsPanelProps {
  mercenary: Mercenary;
  baseStats: DerivedStats;
  finalStats: DerivedStats;
  pendingAllocated: PrimaryStats;
  pendingPoints: number;
  equipmentStats: PrimaryStats;
  previewEquipmentStats: PrimaryStats | null;
  onModifyStat: (key: keyof PrimaryStats, delta: number) => void;
  onSave: () => void;
  onReset: () => void;
  isReadOnly?: boolean;
}

export const MercenaryStatsPanel: React.FC<MercenaryStatsPanelProps> = ({
  mercenary,
  baseStats,
  finalStats,
  pendingAllocated,
  pendingPoints,
  equipmentStats,
  previewEquipmentStats,
  onModifyStat,
  onSave,
  onReset,
  isReadOnly,
}) => {
  const xpPercent =
    mercenary.xpToNextLevel > 0
      ? Math.min(100, Math.max(0, (mercenary.currentXp / mercenary.xpToNextLevel) * 100))
      : 0;
  const hpPercent = finalStats.maxHp > 0 ? (mercenary.currentHp / finalStats.maxHp) * 100 : 0;
  const mpPercent = finalStats.maxMp > 0 ? (mercenary.currentMp / finalStats.maxMp) * 100 : 0;
  const staminaPercent = Math.min(100, Math.max(0, (mercenary.expeditionEnergy || 0)));

  const isModified = useMemo(() => {
    return (Object.keys(pendingAllocated) as Array<keyof PrimaryStats>).some(
        key => pendingAllocated[key] !== mercenary.allocatedStats[key]
    );
  }, [pendingAllocated, mercenary.allocatedStats]);

  // Combine learned skills and equipment-socketed skills
  const allAvailableSkills = useMemo(() => {
      const learned = (mercenary.skillIds || []).map(id => ({ id, source: 'LEARNED' as const }));

      const fromGear: { id: string, source: 'GEAR' as const }[] = [];
      Object.values(mercenary.equipment).forEach(item => {
          if (item?.socketedSkillId) {
              fromGear.push({ id: item.socketedSkillId, source: 'GEAR' as const });
          }
      });

      return [...learned, ...fromGear];
  }, [mercenary.skillIds, mercenary.equipment]);

  const renderStatRow = (icon: React.ReactNode, label: string, baseValue: number, nextValue: number, isPercent = false) => {
    return (
      <div className="bg-stone-950/40 p-1.5 md:p-3 rounded-lg border border-white/5 flex justify-between items-center h-8 md:h-12">
        <span className="text-[7px] md:text-xs text-stone-500 font-black uppercase flex items-center gap-1.5 md:gap-2">
          {icon}
          <span className="hidden md:inline">{label}</span>
          <span className="md:hidden truncate max-w-[40px]">
            {label === 'Physical Atk' ? 'P.Atk' : label === 'Physical Def' ? 'P.Def' : label === 'Magical Atk' ? 'M.Atk' : label === 'Magical Def' ? 'M.Def' : label === 'Crit Rate' ? 'Crit' : label === 'Evasion' ? 'Eva' : label}
          </span>
        </span>
        <div className="flex items-center gap-1 md:gap-2">
          <span className={`font-mono text-[9px] md:text-base font-black ${nextValue > baseValue ? 'text-emerald-400' : nextValue < baseValue ? 'text-red-400' : 'text-stone-300'}`}>
            {isPercent ? nextValue.toFixed(1) : Math.round(nextValue)}
            {isPercent ? '%' : ''}
          </span>
          <StatDiff current={baseValue} next={nextValue} isPercent={isPercent} />
        </div>
      </div>
    );
  };

  return (
    <div className="p-3 md:p-6 flex flex-col gap-4 md:gap-6 bg-stone-900/10 border-t border-white/5">
      <div className="bg-stone-950/40 p-3 md:p-5 rounded-xl border border-white/5 shadow-inner shrink-0">
        <div className="flex justify-between items-end mb-1 md:mb-2 leading-none">
          <span className="text-amber-500 font-black font-mono text-[10px] md:text-lg uppercase tracking-tight">
            XP PROGRESS
          </span>
          <span className="text-stone-500 text-[8px] md:text-sm font-mono font-bold">
            {mercenary.currentXp} / {mercenary.xpToNextLevel}
          </span>
        </div>
        <div className="w-full h-1 md:h-2 bg-stone-900 rounded-full overflow-hidden border border-white/5">
          <div className="h-full bg-gradient-to-r from-amber-800 to-amber-500 transition-all duration-700" style={{ width: `${xpPercent}%` }} />
        </div>
      </div>

      <div className="bg-stone-950/60 rounded-xl border border-stone-800 p-3 md:p-6 shrink-0 relative overflow-hidden">
        <div className="flex justify-between items-center mb-3 md:mb-4 px-1">
          <h4 className="text-[8px] md:text-xs font-black text-stone-500 uppercase tracking-widest flex items-center gap-1.5 md:gap-2">
            <Star className="w-3 h-3 text-amber-600" /> Attributes
          </h4>
          {!isReadOnly && (
            <span className={`text-[8px] md:text-xs font-black px-2 md:px-3 py-0.5 md:py-1 border rounded-full transition-all ${pendingPoints > 0 ? 'bg-amber-900/30 border-amber-500/30 text-amber-400 animate-pulse' : 'bg-stone-900 border-stone-700 text-stone-600'}`}>
              {pendingPoints} AP AVAILABLE
            </span>
          )}
        </div>

        <div className="grid grid-cols-5 gap-1.5 md:gap-4">
          {[
            { label: 'STR', key: 'str' as const, color: 'text-orange-400' },
            { label: 'INT', key: 'int' as const, color: 'text-blue-400' },
            { label: 'DEX', key: 'dex' as const, color: 'text-emerald-400' },
            { label: 'VIT', key: 'vit' as const, color: 'text-red-400' },
            { label: 'LUK', key: 'luk' as const, color: 'text-pink-400' },
          ].map((stat) => {
            const currentEquipBonus = equipmentStats[stat.key] || 0;
            const currentTotal = mercenary.stats[stat.key] + mercenary.allocatedStats[stat.key] + currentEquipBonus;

            const previewEquipBonus = previewEquipmentStats ? (previewEquipmentStats[stat.key] || 0) : currentEquipBonus;
            const previewTotal = mercenary.stats[stat.key] + pendingAllocated[stat.key] + previewEquipBonus;

            const isAllocatedModified = pendingAllocated[stat.key] > mercenary.allocatedStats[stat.key];
            const isPreviewing = previewEquipmentStats !== null;

            return (
              <div key={stat.key} className="flex flex-col gap-1 md:gap-2">
                <div
                  className={`bg-stone-900/80 border ${isAllocatedModified || (isPreviewing && previewTotal !== currentTotal) ? 'border-amber-500 shadow-glow-sm' : 'border-stone-800'} p-1 md:p-2 rounded-lg flex flex-col items-center justify-center h-14 md:h-20 transition-all relative`}
                >
                  <span className={`text-[6px] md:text-[8px] font-black ${stat.color} mb-0.5`}>{stat.label}</span>
                  <div className="flex items-center gap-0.5">
                    <span className={`text-[10px] md:text-lg font-mono font-black ${isPreviewing && previewTotal > currentTotal ? 'text-emerald-400' : isPreviewing && previewTotal < currentTotal ? 'text-red-400' : isAllocatedModified ? 'text-amber-400' : 'text-stone-400'}`}>
                      {previewTotal}
                    </span>
                  </div>
                  {previewEquipBonus > 0 && <span className="text-[6px] md:text-[8px] font-bold text-emerald-400 leading-none mt-0.5">+{previewEquipBonus}</span>}
                </div>

                {!isReadOnly && (
                  <div className="flex flex-col gap-1">
                    <SfxButton
                      onClick={() => onModifyStat(stat.key, 1)}
                      disabled={pendingPoints <= 0}
                      className="w-full h-4 md:h-7 bg-stone-800 hover:bg-amber-600 text-stone-500 hover:text-white rounded transition-all disabled:opacity-20 flex items-center justify-center shadow-sm"
                    >
                      <Plus className="w-2.5 h-2.5 md:w-3.5 md:h-3.5" />
                    </SfxButton>
                    <SfxButton
                      onClick={() => onModifyStat(stat.key, -1)}
                      disabled={pendingAllocated[stat.key] <= mercenary.allocatedStats[stat.key]}
                      className="w-full h-4 md:h-7 bg-stone-800 hover:bg-red-900 text-stone-500 hover:text-white rounded transition-all disabled:opacity-20 flex items-center justify-center shadow-sm"
                    >
                      <Minus className="w-2.5 h-2.5 md:w-3.5 md:h-3.5" />
                    </SfxButton>
                  </div>
                )}
              </div>
            );
          })}
        </div>
      </div>

      {isModified && !isReadOnly && (
          <div className="flex gap-2 animate-in slide-in-from-bottom-2 duration-300">
              <SfxButton 
                sfx="switch"
                onClick={onReset}
                className="flex-1 flex items-center justify-center gap-2 py-2.5 bg-stone-800 hover:bg-stone-750 text-stone-400 hover:text-stone-200 rounded-xl border border-stone-700 transition-all text-[10px] font-black uppercase tracking-widest"
              >
                  <RotateCcw className="w-3.5 h-3.5" /> Discard
              </SfxButton>
              <SfxButton 
                onClick={onSave}
                className="flex-[2] flex items-center justify-center gap-2 py-2.5 bg-amber-600 hover:bg-amber-500 text-white rounded-xl border-b-4 border-amber-800 shadow-xl transition-all active:translate-y-0.5 text-[10px] font-black uppercase tracking-widest"
              >
                  <Save className="w-3.5 h-3.5" /> Save Attributes
              </SfxButton>
          </div>
      )}

      <div className="grid grid-cols-1 sm:grid-cols-3 gap-2 md:gap-4 shrink-0">
        <div className="bg-stone-950/40 p-2 md:p-3 rounded-xl border border-white/5 flex items-center gap-2 md:gap-3 shadow-sm">
          <div className="p-1.5 md:p-2 bg-red-950/40 rounded-lg text-red-500 border border-red-900/30">
            <Heart className="w-3.5 h-3.5 md:w-5 md:h-5" />
          </div>
          <div className="flex-1 min-w-0">
            <div className="flex justify-between text-[7px] md:text-[10px] text-stone-500 font-black mb-0.5 md:mb-1">
              <span>HP</span>
              <span className="text-stone-300 font-mono">
                {Math.floor(mercenary.currentHp)}/{finalStats.maxHp}
              </span>
            </div>
            <div className="w-full h-1 md:h-1.5 bg-stone-900 rounded-full overflow-hidden shadow-inner">
              <div className="h-full bg-red-600 transition-all duration-500" style={{ width: `${hpPercent}%` }} />
            </div>
          </div>
        </div>

        <div className="bg-stone-950/40 p-2 md:p-3 rounded-xl border border-white/5 flex items-center gap-2 md:gap-3 shadow-sm">
          <div className="p-1.5 md:p-2 bg-blue-950/40 rounded-lg text-blue-400 border border-blue-900/30">
            <Activity className="w-3.5 h-3.5 md:w-5 md:h-5" />
          </div>
          <div className="flex-1 min-w-0">
            <div className="flex justify-between text-[7px] md:text-[10px] text-stone-500 font-black mb-0.5 md:mb-1">
              <span>MP</span>
              <span className="text-stone-300 font-mono">
                {Math.floor(mercenary.currentMp)}/{finalStats.maxMp}
              </span>
            </div>
            <div className="w-full h-1 md:h-1.5 bg-stone-900 rounded-full overflow-hidden shadow-inner">
              <div className="h-full bg-blue-600 transition-all duration-500" style={{ width: `${mpPercent}%` }} />
            </div>
          </div>
        </div>

        <div className="bg-stone-950/40 p-2 md:p-3 rounded-xl border border-white/5 flex items-center gap-2 md:gap-3 shadow-sm">
          <div className="p-1.5 md:p-2 bg-stone-800 rounded-lg text-stone-100 border border-white/10">
            <Zap className={`w-3.5 h-3.5 md:w-5 md:h-5 ${staminaPercent < 20 ? 'animate-pulse text-red-500' : 'text-stone-100'}`} />
          </div>
          <div className="flex-1 min-w-0">
            <div className="flex justify-between text-[7px] md:text-[10px] text-stone-500 font-black mb-0.5 md:mb-1">
              <span>STAMINA</span>
              <span className="text-stone-300 font-mono">
                {Math.floor(mercenary.expeditionEnergy || 0)}/100
              </span>
            </div>
            <div className="w-full h-1 md:h-1.5 bg-stone-900 rounded-full overflow-hidden shadow-inner">
              <div className={`h-full transition-all duration-500 ${staminaPercent < 20 ? 'bg-red-500 animate-pulse' : 'bg-stone-100'}`} style={{ width: `${staminaPercent}%` }} />
            </div>
          </div>
        </div>
      </div>

      <div className="space-y-2 md:space-y-3 pb-2 shrink-0">
        <h4 className="text-[8px] md:text-xs font-black text-stone-500 uppercase tracking-widest flex items-center gap-1.5 px-1">
          <Sword className="w-3 h-3" /> Battle Performance
        </h4>
        <div className="grid grid-cols-2 gap-1.5 md:gap-4">
          {renderStatRow(<Sword className="w-3 h-3 md:w-4 md:h-4 text-orange-500" />, 'Physical Atk', baseStats.physicalAttack, finalStats.physicalAttack)}
          {renderStatRow(<Shield className="w-3 h-3 md:w-4 md:h-4 text-blue-500" />, 'Physical Def', baseStats.physicalDefense, finalStats.physicalDefense)}
          {renderStatRow(<Zap className="w-3 h-3 md:w-4 md:h-4 text-blue-400" />, 'Magical Atk', baseStats.magicalAttack, finalStats.magicalAttack)}
          {renderStatRow(<Brain className="w-3 h-3 md:w-4 md:h-4 text-purple-400" />, 'Magical Def', baseStats.magicalDefense, finalStats.magicalDefense)}
          {renderStatRow(<Target className="w-3 h-3 md:w-4 md:h-4 text-red-500" />, 'Crit Rate', baseStats.critChance, finalStats.critChance, true)}
          {renderStatRow(<Wind className="w-3 h-3 md:w-4 md:h-4 text-emerald-400" />, 'Evasion', baseStats.evasion, finalStats.evasion)}
        </div>
      </div>

      <div className="space-y-2 md:space-y-3 pb-6 shrink-0">
        <h4 className="text-[8px] md:text-xs font-black text-stone-500 uppercase tracking-widest flex items-center gap-1.5 px-1">
          <Sparkles className="w-3 h-3 text-amber-600" /> Techniques & Skills
        </h4>

        {allAvailableSkills.length > 0 ? (
          <div className="space-y-1.5 md:space-y-3">
            {allAvailableSkills.map((skillRef, idx) => {
              const skill = SKILLS[skillRef.id];
              if (!skill) return null;
              const isGearSkill = skillRef.source === 'GEAR';

              return (
                <div
                  key={`${skillRef.id}-${idx}`}
                  className={`bg-stone-950/40 border rounded-xl p-3 md:p-4 flex justify-between items-center gap-3 hover:border-amber-900/40 transition-all ${isGearSkill ? 'border-indigo-500/30 bg-indigo-900/10' : 'border-stone-800'}`}
                >
                  <div className="flex items-center gap-3 min-w-0">
                    <div className={`p-2 rounded-lg border shrink-0 ${isGearSkill ? 'bg-indigo-900/30 border-indigo-500/50 text-indigo-400' : 'bg-amber-900/15 border-amber-600/20 text-amber-500'}`}>
                      {isGearSkill ? <Wrench className="w-3.5 h-3.5 md:w-4 md:h-4" /> : <Sword className="w-3.5 h-3.5 md:w-4 md:h-4" />}
                    </div>
                    <div className="min-w-0">
                      <div className="flex items-center gap-1.5">
                          <h5 className="text-[10px] md:text-xs font-black text-stone-200 uppercase truncate">{skill.name}</h5>
                          {isGearSkill && <span className="text-[6px] md:text-[8px] font-black bg-indigo-600 text-white px-1 py-0.5 rounded leading-none uppercase">Gear</span>}
                      </div>
                      <p className="text-[8px] md:text-[9px] text-stone-500 italic leading-tight line-clamp-1">
                        {skill.description}
                      </p>
                    </div>
                  </div>
                  <div className="text-right shrink-0">
                     <span className="text-[7px] md:text-[8px] font-black text-amber-500 uppercase tracking-tighter">
                        {Math.round((skill.multiplier || 0) * 100)}% {skill.damageType || 'EFF'}
                      </span>
                  </div>
                </div>
              );
            })}
          </div>
        ) : (
          <div className="py-4 md:py-6 text-center border-2 border-dashed border-stone-800 rounded-xl text-stone-600 text-[8px] md:text-[10px] font-bold uppercase tracking-widest">
            No available skills
          </div>
        )}
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import { Shield, Sword, Activity, Skull, Zap, LogOut, FastForward, Pause, Play, ChevronDown, ChevronUp, Sparkles, Target, Package, X, Check, RotateCcw, Wand2 } from 'lucide-react';
import { Mercenary } from '../../../models/Mercenary';
import { Monster } from '../../../models/Monster';
import { ManualDungeonSession } from '../../../types/game-state';
import { calculateCombatResult } from '../../../utils/combatLogic';
import { calculateDerivedStats, applyEquipmentBonuses, mergePrimaryStats } from '../../../models/Stats';
import { useGame } from '../../../context/GameContext';
import { SKILLS } from '../../../data/skills';
import { MercenaryPortrait } from '../../common/ui/MercenaryPortrait';
import { getAssetUrl } from '../../../utils';
import { InventoryItem, EquipmentSlotType } from '../../../types/inventory';
import { MercenaryDetailModal } from '../../modals/MercenaryDetailModal';
import { DUNGEONS } from '../../../data/dungeons';
import { SfxButton } from '../../common/ui/SfxButton';

const ACTION_THRESHOLD = 1000;

interface CombatLogEntry {
    msg: string;
    team: 'PLAYER' | 'ENEMY' | 'SYSTEM';
    isCrit?: boolean;
    isSkill?: boolean;
}

interface DamagePopup {
    id: number;
    value: number;
    targetId: string;
    isCrit: boolean;
    isSkill: boolean;
}

interface DungeonCombatViewProps {
    session: ManualDungeonSession;
    party: Mercenary[];
    enemies: Monster[];
    fleeChance: number;
    onFinish: (win: boolean, finalParty: any[]) => void;
    onFlee: (finalParty: any[]) => void;
}

const DungeonCombatView: React.FC<DungeonCombatViewProps> = ({ session, party, enemies, fleeChance, onFinish, onFlee }) => {
    const { state, actions } = useGame();
    const [orientation, setOrientation] = useState<'PORTRAIT' | 'LANDSCAPE'>(
        window.innerWidth > window.innerHeight ? 'LANDSCAPE' : 'PORTRAIT'
    );

    const dungeonInfo = useMemo(() => DUNGEONS.find(d => d.id === session.dungeonId), [session.dungeonId]);

    const [partyState, setPartyState] = useState(party.map(m => {
        const primary = mergePrimaryStats(m.stats, m.allocatedStats);
        const derived = applyEquipmentBonuses(calculateDerivedStats(primary, m.level), (Object.values(m.equipment) as any[]).map(e=>e?.stats).filter(Boolean) as any);
        return { ...m, derived, currentHp: m.currentHp, currentMp: m.currentMp, gauge: 0, lastDamaged: false };
    }));

    const [enemySquadState, setEnemySquadState] = useState(enemies.map((e, idx) => ({
        ...e,
        instanceId: `enemy_${idx}`,
        gauge: 0,
        lastDamaged: false,
        hasUsedRevival: false
    })));

    const [logs, setLogs] = useState<CombatLogEntry[]>([]);
    const [damagePopups, setDamagePopups] = useState<DamagePopup[]>([]);

    // --- PERSISTENCE: 설정 데이터 유지 ---
    const [isAuto, setIsAuto] = useState(() => {
        const saved = localStorage.getItem('dungeon_combat_auto');
        return saved === null ? true : saved === 'true';
    });

    const [battleSpeed, setBattleSpeed] = useState<1 | 2 | 4>(() => {
        const saved = localStorage.getItem('dungeon_combat_speed');
        const parsed = saved ? parseInt(saved) : 1; 
        if (parsed === 1 || parsed === 2 || parsed === 4) return parsed as 1 | 2 | 4;
        return 1;
    });

    useEffect(() => {
        localStorage.setItem('dungeon_combat_auto', isAuto.toString());
    }, [isAuto]);

    useEffect(() => {
        localStorage.setItem('dungeon_combat_speed', battleSpeed.toString());
    }, [battleSpeed]);

    const [isPaused, setIsPaused] = useState(false);
    const [activeActorId, setActiveActorId] = useState<string | null>(null); 
    const [attackingUnitId, setAttackingUnitId] = useState<string | null>(null);
    const [showLogs, setShowLogs] = useState(false);
    const [showSkillList, setShowSkillList] = useState(false);

    const [pendingAction, setPendingAction] = useState<{ type: 'ATTACK' | 'SKILL', skillId?: string } | null>(null);
    const [inspectedMercId, setInspectedMercId] = useState<string | null>(null);

    const battleInterval = useRef<ReturnType<typeof setInterval> | null>(null);
    const speedRef = useRef(1);

    useEffect(() => {
        speedRef.current = battleSpeed;
    }, [battleSpeed]);

    useEffect(() => {
        const handleResize = () => {
            setOrientation(window.innerWidth > window.innerHeight ? 'LANDSCAPE' : 'PORTRAIT');
        };
        window.addEventListener('resize', handleResize);
        return () => window.removeEventListener('resize', handleResize);
    }, []);

    const addLog = useCallback((msg: string, team: 'PLAYER' | 'ENEMY' | 'SYSTEM', isCrit = false, isSkill = false) => {
        setLogs(prev => [{ msg, team, isCrit, isSkill }, ...prev].slice(0, 50));
    }, []);

    const triggerDamagePopup = useCallback((targetId: string, value: number, isCrit: boolean, isSkill: boolean) => {
        const id = Date.now() + Math.random();
        setDamagePopups(prev => [...prev, { id, value, targetId, isCrit, isSkill }]);
        setTimeout(() => {
            setDamagePopups(prev => prev.filter(p => p.id !== id));
        }, 800 / speedRef.current);
    }, []);

    const executeAttack = useCallback((attacker: any, target: any, isPlayerAttacker: boolean, skillId?: string) => {
        setAttackingUnitId(isPlayerAttacker ? attacker.id : target.instanceId);

        setTimeout(() => {
            const skill = skillId ? SKILLS[skillId] : null;
            const multiplier = skill ? skill.multiplier : 1.0;
            const mpCost = skill?.mpCost ?? 0;

            const res = calculateCombatResult(
                isPlayerAttacker ? attacker.derived : attacker.stats,
                isPlayerAttacker ? target.stats : target.derived,
                isPlayerAttacker ? attacker.job : 'Fighter' as any,
                isPlayerAttacker ? (attacker.derived.magicalAttack > attacker.derived.physicalAttack ? 'MAGICAL' : 'PHYSICAL') : 'PHYSICAL',
                multiplier
            );

            // 명중/회피 시 효과음 출력
            if (res.isHit) {
                window.dispatchEvent(new CustomEvent('play-sfx', { detail: { file: 'battle_slash.mp3' } }));
            } else {
                window.dispatchEvent(new CustomEvent('play-sfx', { detail: { file: 'swing_miss.mp3' } }));
            }

            if (isPlayerAttacker) {
                setEnemySquadState(prev => prev.map(e => {
                    if (e.instanceId === target.instanceId) {
                        const next = { ...e, lastDamaged: res.isHit };
                        if (res.isHit) {
                            let nextHp = Math.max(0, next.currentHp - res.damage);
                            if (nextHp <= 0 && next.id === 'phoenix' && !next.hasUsedRevival) {
                                nextHp = next.stats.maxHp;
                                next.hasUsedRevival = true;
                                addLog("Phoenix rebirth triggered!", 'ENEMY', true, true);
                                triggerDamagePopup(target.instanceId, 0, true, true);
                            } else {
                                next.currentHp = nextHp;
                            }
                            triggerDamagePopup(target.instanceId, res.damage, res.isCrit, !!skill);
                        }
                        setTimeout(() => setEnemySquadState(curr => curr.map(currE => currE.instanceId === target.instanceId ? { ...currE, lastDamaged: false } : currE)), 200 / speedRef.current);
                        return next;
                    }
                    return e;
                }));

                if (skill) {
                    setPartyState(prev => prev.map(p => p.id === attacker.id ? { ...p, currentMp: Math.max(0, p.currentMp - mpCost) } : p));
                    addLog(`${attacker.name} used ${skill.name}!`, 'PLAYER', res.isCrit, true);
                } else {
                    addLog(`${attacker.name} hits ${target.name} for ${res.damage}`, 'PLAYER', res.isCrit);
                }
            } else {
                setPartyState(prev => prev.map(p => {
                    if (p.id === target.id) {
                        const next = { ...p, lastDamaged: res.isHit };
                        if (res.isHit) {
                            next.currentHp = Math.max(0, next.currentHp - res.damage);
                            triggerDamagePopup(p.id, res.damage, res.isCrit, false);
                        }
                        setTimeout(() => setPartyState(curr => curr.map(c => c.id === p.id ? { ...c, lastDamaged: false } : c)), 200 / speedRef.current);
                        return next;
                    }
                    return p;
                }));
                addLog(`${attacker.name} strikes ${target.name} for ${res.damage}`, 'ENEMY');
            }

            setTimeout(() => setAttackingUnitId(null), 150 / speedRef.current);
        }, 200 / speedRef.current);
    }, [addLog, triggerDamagePopup]);

    const processLoop = useCallback(() => {
        if (isPaused || activeActorId || attackingUnitId || inspectedMercId) return;

        const enemiesDefeated = enemySquadState.every(e => e.currentHp <= 0);
        const partyDefeated = partyState.every(p => p.currentHp <= 0);

        if (enemiesDefeated) {
            setIsPaused(true);
            setTimeout(() => onFinish(true, partyState), 800 / speedRef.current);
            return;
        }
        if (partyDefeated) {
            setIsPaused(true);
            setTimeout(() => onFinish(false, partyState), 800 / speedRef.current);
            return;
        }

        // --- SPEED BALANCING: 기초 게이지 충전량 0.2로 고정 ---
        setPartyState(prev => {
            const next = [...prev];
            let readyMerc = null;
            for (let p of next) {
                if (p.currentHp > 0) {
                    p.gauge += (p.derived.speed * 0.2 * speedRef.current); 
                    if (p.gauge >= ACTION_THRESHOLD && !readyMerc) readyMerc = p;
                }
            }
            if (readyMerc && !attackingUnitId) {
                const livingEnemies = enemySquadState.filter(e => e.currentHp > 0);
                if (livingEnemies.length > 0) {
                    if (isAuto) {
                        readyMerc.gauge -= ACTION_THRESHOLD;
                        const target = livingEnemies[Math.floor(Math.random() * livingEnemies.length)];
                        let sid = undefined;

                        // 자동 전투 시 스킬 사용 우선순위 로직
                        const availableSkillIds = [
                            ...(readyMerc.skillIds || []),
                            ...Object.values(readyMerc.equipment || {}).map(i => i?.socketedSkillId).filter(Boolean) as string[]
                        ];

                        if (availableSkillIds.length > 0) {
                            const skill = SKILLS[availableSkillIds[0]];
                            if (skill && readyMerc.currentMp >= (skill.mpCost ?? 0) && Math.random() < 0.3) sid = skill.id;
                        }
                        executeAttack(readyMerc, target, true, sid);
                    } else {
                        setActiveActorId(readyMerc.id);
                        setShowSkillList(false);
                        setPendingAction(null);
                    }
                }
            }
            return next;
        });

        setEnemySquadState(prev => {
            const next = [...prev];
            let readyEnemy = null;
            for (let e of next) {
                if (e.currentHp > 0) {
                    e.gauge += (e.stats.speed * 0.2 * speedRef.current); 
                    if (e.gauge >= ACTION_THRESHOLD && !readyEnemy) readyEnemy = e;
                }
            }
            if (readyEnemy && !activeActorId && !attackingUnitId) {
                readyEnemy.gauge -= ACTION_THRESHOLD;
                const livingPlayers = partyState.filter(p => p.currentHp > 0);
                if (livingPlayers.length > 0) {
                    const target = livingPlayers[Math.floor(Math.random() * livingPlayers.length)];
                    executeAttack(readyEnemy, target, false);
                }
            }
            return next;
        });
    }, [isPaused, isAuto, activeActorId, attackingUnitId, inspectedMercId, enemySquadState, partyState, executeAttack, onFinish]);

    useEffect(() => {
        battleInterval.current = setInterval(processLoop, 100);
        return () => { if (battleInterval.current) clearInterval(battleInterval.current); };
    }, [processLoop]);

    const handleTurnConsumed = useCallback((targetMercId: string) => {
        setTimeout(() => {
            const updatedMercFromContext = state.knownMercenaries.find(m => m.id === targetMercId);
            if (updatedMercFromContext) {
                setPartyState(prev => prev.map(p => {
                    if (p.id === targetMercId) {
                        const primary = mergePrimaryStats(updatedMercFromContext.stats, updatedMercFromContext.allocatedStats);
                        const derived = applyEquipmentBonuses(
                            calculateDerivedStats(primary, updatedMercFromContext.level), 
                            (Object.values(updatedMercFromContext.equipment) as any[]).map(e=>e?.stats).filter(Boolean) as any
                        );
                        return { 
                            ...p, 
                            ...updatedMercFromContext, 
                            derived,
                            currentHp: updatedMercFromContext.currentHp,
                            currentMp: updatedMercFromContext.currentMp,
                            gauge: Math.max(0, p.gauge - ACTION_THRESHOLD)
                        };
                    }
                    return p;
                }));
                setInspectedMercId(null);
                setActiveActorId(null);
            }
        }, 50);
    }, [state.knownMercenaries]);

    const handleManualAction = (e: React.MouseEvent, type: 'ATTACK' | 'SKILL', skillId?: string) => {
        e.stopPropagation(); 
        if (!activeActorId) return;

        if (type === 'SKILL' && !skillId) {
            setShowSkillList(true);
            return;
        }

        if (type === 'SKILL' && skillId) {
            const skill = SKILLS[skillId];
            const actor = partyState.find(p => p.id === activeActorId);
            if (!actor || actor.currentMp < (skill?.mpCost ?? 0)) {
                actions.showToast("Not enough MP!");
                return;
            }
            setShowSkillList(false);
        }

        setPendingAction({ type, skillId });
    };

    const handleEnemyClick = (target: any) => {
        if (!activeActorId || !pendingAction) return;
        if (target.currentHp <= 0) return;
        const actor = partyState.find(p => p.id === activeActorId);
        if (!actor) return;
        setPartyState(prev => prev.map(p => p.id === activeActorId ? { ...p, gauge: p.gauge - ACTION_THRESHOLD } : p));
        executeAttack(actor, target, true, pendingAction.skillId);
        setPendingAction(null);
        setActiveActorId(null);
    };

    const handleFlee = (e: React.MouseEvent) => {
        e.stopPropagation();
        if (Math.random() * 100 < fleeChance) {
            onFlee(partyState);
        } else {
            addLog("Escape failed!", 'SYSTEM');
            setActiveActorId(null);
            setPendingAction(null);
            setPartyState(prev => prev.map(p => p.id === activeActorId ? { ...p, gauge: 0 } : p));
        }
    };

    const getUnitStyle = (id: string, side: 'PLAYER' | 'ENEMY'): React.CSSProperties => {
        if (attackingUnitId !== id) return {};
        let transform = orientation === 'PORTRAIT' 
            ? (side === 'PLAYER' ? 'translateY(-120px) scale(1.1)' : 'translateY(120px) scale(1.1)')
            : (side === 'PLAYER' ? 'translateX(120px) scale(1.1)' : 'translateX(-120px) scale(1.1)');
        return { transform, zIndex: 100 };
    };

    const activeActor = useMemo(() => partyState.find(p => p.id === activeActorId), [partyState, activeActorId]);
    const activeActorSkills = useMemo(() => {
        if (!activeActor) return [];
        const learned = (activeActor.skillIds || []).map(id => ({ id, source: 'LEARNED' }));
        const fromGear = Object.values(activeActor.equipment || {}).map(i => i?.socketedSkillId).filter(Boolean).map(id => ({ id, source: 'GEAR' }));
        return [...learned, ...fromGear as any];
    }, [activeActor]);

    return (
        <div className="fixed inset-0 z-[150] flex flex-col bg-stone-950 animate-in fade-in duration-500 overflow-hidden font-sans pb-safe">
            <style>{`
                @keyframes damage-float { 0% { transform: translateY(0); opacity: 1; } 100% { transform: translateY(-60px); opacity: 0; } }
                .animate-damage { animation: damage-float 1s ease-out forwards; }
                @keyframes unit-shake { 0%, 100% { transform: translate(0,0); } 25% { transform: translate(-4px, 2px); } 50% { transform: translate(4px, -2px); } 75% { transform: translate(-2px, -4px); } }
                .animate-hit { animation: unit-shake 0.2s ease-in-out 3; }
                @keyframes target-pulse { 0% { transform: scale(1); box-shadow: 0 0 0 0 rgba(239, 68, 68, 0.7); } 70% { transform: scale(1.05); box-shadow: 0 0 0 10px rgba(239, 68, 68, 0); } 100% { transform: scale(1); } }
                .animate-target { animation: target-pulse 1.5s infinite; }
            `}</style>

            {/* Background Tile Layer */}
            {dungeonInfo?.tile && (
                <div className="absolute inset-0 z-0 overflow-hidden pointer-events-none">
                    <img 
                        src={getAssetUrl(dungeonInfo.tile, 'dungeons')} 
                        className="w-full h-full object-cover opacity-60 brightness-[0.6]" 
                        alt="Combat Background" 
                    />
                </div>
            )}

            {/* Top Bar */}
            <div className="p-3 bg-red-950/20 border-b border-red-900/30 flex justify-between items-center z-[200] backdrop-blur-sm">
                <div className="flex items-center gap-2">
                    <Skull className="w-4 h-4 text-red-50" />
                    <h2 className="text-white font-black uppercase text-[10px] md:text-sm tracking-widest font-mono">Combat Zone</h2>
                </div>
                <div className="flex items-center gap-3 bg-black/40 px-3 py-1 rounded-full border border-white/5">
                    <SfxButton sfx="switch" onClick={() => setIsPaused(!isPaused)} className={`p-1.5 rounded-full transition-all ${isPaused ? 'bg-amber-600 text-white' : 'bg-stone-800 text-stone-400'}`}>
                        {isPaused ? <Play size={14} /> : <Pause size={14} />}
                    </SfxButton>
                    <div className="flex items-center gap-1">
                        {[1, 2, 4].map(s => (
                            <SfxButton sfx="switch" key={s} onClick={() => setBattleSpeed(s as any)} className={`px-2 py-0.5 rounded font-mono text-[8px] md:text-[10px] font-black ${battleSpeed === s ? 'bg-indigo-600 text-white' : 'text-stone-600'}`}>{s}x</SfxButton>
                        ))}
                    </div>
                </div>
                <SfxButton sfx="switch" onClick={() => { setIsAuto(!isAuto); setPendingAction(null); setShowSkillList(false); }} className={`px-4 py-1.5 rounded-lg border font-black text-[9px] tracking-widest transition-all ${isAuto ? 'bg-amber-600 border-amber-400 text-white' : 'bg-stone-800 border-stone-600 text-stone-400'}`}>
                    {isAuto ? 'AUTO' : 'MANUAL'}
                </SfxButton>
            </div>

            {/* Combat Field */}
            <div className={`flex-1 flex relative transition-all duration-700 z-10 ${orientation === 'PORTRAIT' ? 'flex-col' : 'flex-row'}`}>
                {/* Enemies Area */}
                <div className={`flex flex-1 items-center justify-center p-4 gap-6 md:gap-12 ${orientation === 'PORTRAIT' ? 'order-1' : 'order-2'}`}>
                    {enemySquadState.map(e => (
                        <div key={e.instanceId} style={getUnitStyle(e.instanceId, 'ENEMY')} onClick={() => pendingAction && e.currentHp > 0 && handleEnemyClick(e)} className={`relative flex flex-col items-center transition-all ${e.currentHp <= 0 ? 'opacity-20 grayscale' : e.lastDamaged ? 'animate-hit' : ''}`}>
                            <div className={`w-24 h-24 md:w-48 md:h-48 bg-stone-900 rounded-2xl border-2 flex items-center justify-center relative shadow-2xl ${e.lastDamaged ? 'border-red-500 bg-red-950/20' : 'border-stone-800'} ${pendingAction && e.currentHp > 0 ? 'animate-target border-red-500 cursor-crosshair' : ''}`}>
                                <img src={getAssetUrl(e.sprite || '', 'monsters')} className="w-[80%] h-[80%] object-contain" alt={e.name} />
                                {pendingAction && e.currentHp > 0 && <div className="absolute inset-0 flex items-center justify-center"><Target className="w-12 h-12 text-red-500 opacity-50" /></div>}
                                <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
                                    {damagePopups.filter(p => p.targetId === e.instanceId).map(p => (
                                        <div key={p.id} className={`absolute font-black text-3xl md:text-5xl animate-damage ${p.isCrit ? 'text-amber-400 scale-125' : 'text-red-500'}`}>-{p.value}</div>
                                    ))}
                                </div>
                            </div>
                            {e.currentHp > 0 && (
                                <div className="mt-2 w-24 md:w-52 space-y-1">
                                    <div className="flex flex-col items-center leading-none mb-1">
                                        <span className="text-[9px] md:text-xs font-black text-stone-300 uppercase tracking-tighter truncate w-full text-center">{e.name}</span>
                                        <span className="text-[7px] md:text-[9px] font-bold text-stone-500 uppercase tracking-widest">Lv.{e.level}</span>
                                    </div>
                                    <div className="relative h-2.5 bg-black rounded-full overflow-hidden border border-white/5">
                                        <div className="h-full bg-red-600 transition-all duration-500" style={{ width: `${(e.currentHp/e.stats.maxHp)*100}%` }} />
                                        <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
                                            <span className="text-[7px] md:text-[10px] font-mono font-black text-white drop-shadow-sm">{Math.floor(e.currentHp)} / {e.stats.maxHp}</span>
                                        </div>
                                    </div>
                                    <div className="h-1 bg-black rounded-full overflow-hidden">
                                        <div className="h-full bg-amber-500 transition-all" style={{ width: `${(e.gauge/ACTION_THRESHOLD)*100}%` }} />
                                    </div>
                                </div>
                            )}
                        </div>
                    ))}
                </div>

                {/* Players Area */}
                <div className={`flex flex-1 items-center justify-center p-4 gap-6 md:gap-12 ${orientation === 'PORTRAIT' ? 'order-3 pt-0' : 'order-1'}`}>
                    {partyState.map(p => {
                        const isActive = activeActorId === p.id;
                        const hpPer = (p.currentHp / p.derived.maxHp) * 100;
                        const mpPer = (p.currentMp / (p.derived.maxMp || 1)) * 100;

                        return (
                            <div key={p.id} style={getUnitStyle(p.id, 'PLAYER')} className={`relative flex flex-col items-center transition-all ${p.currentHp <= 0 ? 'opacity-20 grayscale' : isActive ? '-translate-y-4' : ''} ${p.lastDamaged ? 'animate-hit' : ''}`}>
                                {/* Portrait Container */}
                                <div className={`w-24 h-24 md:w-48 md:h-48 bg-stone-900 rounded-2xl border-2 flex items-center justify-center relative shadow-2xl ${isActive ? 'border-amber-400 ring-4 ring-amber-500/20' : 'border-stone-800'}`}>
                                    <MercenaryPortrait mercenary={p} className="w-[85%] h-[85%] rounded-xl" />
                                    <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
                                        {damagePopups.filter(pop => pop.targetId === p.id).map(pop => (
                                            <div key={pop.id} className="absolute font-black text-3xl md:text-5xl animate-damage text-red-50">-{pop.value}</div>
                                        ))}
                                    </div>

                                    {/* Action indicator for targeting */}
                                    {pendingAction && isActive && (
                                        <div className="absolute -top-12 left-1/2 -translate-x-1/2 flex flex-col items-center animate-bounce">
                                            <div className="bg-amber-600 text-white px-3 py-1 rounded-full text-[10px] font-black uppercase shadow-lg border border-amber-400">
                                                {pendingAction.skillId ? SKILLS[pendingAction.skillId].name : 'Striking'}
                                            </div>
                                            <div className="w-0 h-0 border-l-[6px] border-l-transparent border-r-[6px] border-r-transparent border-t-[6px] border-t-amber-600"></div>
                                        </div>
                                    )}

                                    {isActive && !pendingAction && !isAuto && !showSkillList && (
                                        <div className="absolute -bottom-40 left-1/2 -translate-x-1/2 z-[300] bg-stone-900/95 border-2 border-amber-500 p-2.5 rounded-2xl grid grid-cols-2 gap-3 shadow-2xl animate-in slide-in-from-top-2 backdrop-blur-md w-40">
                                            <SfxButton onClick={(e) => handleManualAction(e, 'ATTACK')} className="p-3 bg-stone-800 hover:bg-stone-700 rounded-xl text-white transition-colors border border-white/5 flex flex-col items-center gap-1 group">
                                                <Sword size={20} className="group-hover:scale-110 transition-transform" />
                                                <span className="text-[8px] font-black uppercase">Atk</span>
                                            </SfxButton>
                                            <SfxButton onClick={(e) => handleManualAction(e, 'SKILL')} className="p-3 bg-indigo-900/40 hover:bg-indigo-800 rounded-xl text-indigo-100 transition-colors border border-indigo-500/30 flex flex-col items-center gap-1 group">
                                                <Wand2 size={20} className="group-hover:scale-110 transition-transform" />
                                                <span className="text-[8px] font-black uppercase">Skill</span>
                                            </SfxButton>
                                            <SfxButton sfx="switch" onClick={(e) => { e.stopPropagation(); setInspectedMercId(p.id); }} className="p-3 bg-stone-800 hover:bg-stone-750 rounded-xl text-stone-300 transition-colors border border-stone-700 flex flex-col items-center gap-1 group">
                                                <Package size={20} className="group-hover:scale-110 transition-transform" />
                                                <span className="text-[8px] font-black uppercase">Bag</span>
                                            </SfxButton>
                                            <SfxButton onClick={(e) => handleFlee(e)} className="p-3 bg-red-950/40 hover:bg-red-900 rounded-xl text-red-500 transition-colors border border-red-500/30 flex flex-col items-center gap-1 group">
                                                <LogOut size={20} className="group-hover:scale-110 transition-transform" />
                                                <span className="text-[8px] font-black uppercase">Flee</span>
                                            </SfxButton>
                                        </div>
                                    )}

                                    {/* Skill List Overlay */}
                                    {isActive && showSkillList && (
                                        <div className="absolute -bottom-52 left-1/2 -translate-x-1/2 z-[310] bg-stone-900/98 border-2 border-indigo-500 p-3 rounded-2xl shadow-2xl animate-in zoom-in-95 backdrop-blur-xl w-64 md:w-80">
                                            <div className="flex justify-between items-center mb-2 px-1">
                                                <span className="text-[10px] font-black text-indigo-400 uppercase tracking-widest">Available Skills</span>
                                                <SfxButton sfx="switch" onClick={() => setShowSkillList(false)} className="text-stone-500 hover:text-white"><X size={16} /></SfxButton>
                                            </div>
                                            <div className="space-y-1.5 max-h-48 overflow-y-auto custom-scrollbar pr-1">
                                                {activeActorSkills.map((ref, idx) => {
                                                    const skill = SKILLS[ref.id];
                                                    if (!skill) return null;
                                                    const canCast = activeActor.currentMp >= (skill.mpCost ?? 0);
                                                    return (
                                                        <button 
                                                            key={`${ref.id}-${idx}`}
                                                            disabled={!canCast}
                                                            onClick={(e) => handleManualAction(e, 'SKILL', ref.id)}
                                                            className={`w-full flex items-center justify-between p-2 rounded-xl border transition-all text-left group ${canCast ? 'bg-indigo-900/20 border-indigo-500/30 hover:bg-indigo-800/40 hover:border-indigo-400' : 'bg-stone-900 border-stone-800 opacity-50 grayscale cursor-not-allowed'}`}
                                                        >
                                                            <div className="flex items-center gap-2 min-w-0">
                                                                <div className={`p-1.5 rounded-lg border ${ref.source === 'GEAR' ? 'bg-purple-900/30 border-purple-500/50 text-purple-400' : 'bg-indigo-900/40 border-indigo-500/50 text-indigo-300'}`}>
                                                                    <Zap size={14} />
                                                                </div>
                                                                <div className="min-w-0 flex flex-col leading-tight">
                                                                    <span className="text-[10px] font-black text-stone-100 uppercase truncate">{skill.name}</span>
                                                                    <span className="text-[7px] text-stone-500 italic truncate">{skill.description}</span>
                                                                </div>
                                                            </div>
                                                            <div className="flex items-center gap-1.5 shrink-0 pl-2">
                                                                <span className="text-[9px] font-mono font-black text-blue-400">{skill.mpCost} MP</span>
                                                                <ChevronRight size={14} className="text-stone-700 group-hover:text-white transition-colors" />
                                                            </div>
                                                        </button>
                                                    );
                                                })}
                                                {activeActorSkills.length === 0 && (
                                                    <div className="py-8 text-center text-stone-600 text-[10px] font-black uppercase tracking-widest opacity-40 italic">No usable skills</div>
                                                )}
                                            </div>
                                            {pendingAction && (
                                                <div className="mt-3 pt-3 border-t border-indigo-500/30">
                                                    <SfxButton onClick={() => setPendingAction(null)} className="w-full py-2 bg-stone-800 hover:bg-stone-700 text-stone-400 text-[10px] font-black uppercase rounded-lg">Cancel Selection</SfxButton>
                                                </div>
                                            )}
                                        </div>
                                    )}
                                </div>

                                {p.currentHp > 0 && (
                                    <div className="mt-2 w-24 md:w-52 space-y-1">
                                        {/* Full Name, Job, Level */}
                                        <div className="flex flex-col items-center leading-none mb-1">
                                            <span className="text-[9px] md:text-xs font-black text-stone-100 uppercase tracking-tighter truncate w-full text-center">{p.name}</span>
                                            <span className="text-[7px] md:text-[10px] font-bold text-stone-500 uppercase tracking-widest mt-0.5">{p.job} • Lv.{p.level}</span>
                                        </div>

                                        {/* HP Bar & Value */}
                                        <div className="relative h-3 bg-black rounded-full overflow-hidden border border-white/5 shadow-inner">
                                            <div className={`h-full transition-all duration-500 ${hpPer < 30 ? 'bg-red-500 animate-pulse' : 'bg-red-600'}`} style={{ width: `${hpPer}%` }} />
                                            <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
                                                <span className="text-[7px] md:text-[11px] font-mono font-black text-white drop-shadow-sm">{Math.floor(p.currentHp)} / {p.derived.maxHp}</span>
                                            </div>
                                        </div>

                                        {/* MP Bar & Value */}
                                        <div className="relative h-2.5 bg-black rounded-full overflow-hidden border border-white/5 shadow-inner">
                                            <div className="h-full bg-blue-600 transition-all duration-500" style={{ width: `${mpPer}%` }} />
                                            <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
                                                <span className="text-[6px] md:text-[9px] font-mono font-black text-blue-100 drop-shadow-sm">{Math.floor(p.currentMp)} / {p.derived.maxMp}</span>
                                            </div>
                                        </div>

                                        {/* ATB Gauge */}
                                        <div className="h-1 bg-black rounded-full overflow-hidden">
                                            <div className="h-full bg-amber-500 transition-all" style={{ width: `${(p.gauge/ACTION_THRESHOLD)*100}%` }} />
                                        </div>
                                    </div>
                                )}
                            </div>
                        );
                    })}
                </div>
            </div>

            {/* Tactical Feed */}
            <div className={`bg-stone-900 border-t border-stone-800 flex flex-col shrink-0 transition-all z-10 ${showLogs ? 'h-48' : 'h-18'}`}>
                <button onClick={() => setShowLogs(!showLogs)} className="w-full h-10 flex items-center justify-between px-4 bg-black/20 hover:bg-black/40 transition-colors shrink-0">
                    <div className="flex items-center gap-2">
                        <Activity className={`w-3.5 h-3.5 ${isPaused ? 'text-stone-600' : 'text-amber-500 animate-pulse'}`} />
                        <span className="text-[9px] font-black text-stone-500 uppercase tracking-widest">Engagement Feed</span>
                    </div>
                    {showLogs ? <ChevronDown size={14} /> : <ChevronUp size={14} />}
                </button>
                <div className={`flex-1 ${showLogs ? 'overflow-y-auto' : 'overflow-hidden'} p-2 space-y-1 font-mono text-[9px] custom-scrollbar`}>
                    {(showLogs ? logs : logs.slice(0, 1)).map((log, i) => (
                        <div key={i} className={`p-1.5 border-l-2 ${log.team === 'PLAYER' ? 'border-blue-500 text-blue-100' : log.team === 'ENEMY' ? 'border-red-500 text-red-100' : 'border-stone-700 text-stone-400'} ${log.isCrit ? 'bg-white/5 font-black' : ''}`}>
                            <span className="opacity-30 mr-2">[{new Date().toLocaleTimeString([], { hour12: false, minute: '2-digit', second: '2-digit' })}]</span>
                            {log.msg}
                        </div>
                    ))}
                </div>
            </div>

            {/* Modals */}
            {inspectedMercId && (
                <MercenaryDetailModal 
                    mercenary={partyState.find(p => p.id === inspectedMercId) || null}
                    onClose={() => setInspectedMercId(null)}
                    onEquip={(mercId, itemId) => { actions.equipItem(mercId, itemId); handleTurnConsumed(mercId); }}
                    onConsume={(mercId, itemId) => { actions.useItem(itemId, mercId); handleTurnConsumed(mercId); }}
                    onUnequip={(mercId, slot) => { actions.unequipItem(mercId, slot); handleTurnConsumed(mercId); }}
                    isReadOnly={false} 
                />
            )}
        </div>
    );
};

export default DungeonCombatView;

import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import { Shield, Sword, Activity, Skull, Zap, LogOut, FastForward, Pause, Play, ChevronDown, ChevronUp, Sparkles, Target, Package, X, Check, RotateCcw, Wand2, ChevronRight } from 'lucide-react';
import { Mercenary } from '../../../models/Mercenary';
import { Monster } from '../../../models/Monster';
import { ManualDungeonSession } from '../../../types/game-state';
import { calculateCombatResult } from '../../../utils/combatLogic';
import { calculateDerivedStats, applyEquipmentBonuses, mergePrimaryStats } from '../../../models/Stats';
import { useGame } from '../../../context/GameContext';
import { SKILLS } from '../../../data/skills';
import { MercenaryPortrait } from '../../common/ui/MercenaryPortrait';
import { getAssetUrl } from '../../../utils';
import { InventoryItem, EquipmentSlotType } from '../../../types/inventory';
import { MercenaryDetailModal } from '../../modals/MercenaryDetailModal';
import { DUNGEONS } from '../../../data/dungeons';
import { SfxButton } from '../../common/ui/SfxButton';

const ACTION_THRESHOLD = 1000;

interface CombatLogEntry {
    msg: string;
    team: 'PLAYER' | 'ENEMY' | 'SYSTEM';
    isCrit?: boolean;
    isSkill?: boolean;
}

interface DamagePopup {
    id: number;
    value: number;
    targetId: string;
    isCrit: boolean;
    isSkill: boolean;
}

interface DungeonCombatViewProps {
    session: ManualDungeonSession;
    party: Mercenary[];
    enemies: Monster[];
    fleeChance: number;
    onFinish: (win: boolean, finalParty: any[]) => void;
    onFlee: (finalParty: any[]) => void;
}

const DungeonCombatView: React.FC<DungeonCombatViewProps> = ({ session, party, enemies, fleeChance, onFinish, onFlee }) => {
    const { state, actions } = useGame();
    const [orientation, setOrientation] = useState<'PORTRAIT' | 'LANDSCAPE'>(
        window.innerWidth > window.innerHeight ? 'LANDSCAPE' : 'PORTRAIT'
    );

    const dungeonInfo = useMemo(() => DUNGEONS.find(d => d.id === session.dungeonId), [session.dungeonId]);

    const [partyState, setPartyState] = useState(party.map(m => {
        const primary = mergePrimaryStats(m.stats, m.allocatedStats);
        const derived = applyEquipmentBonuses(calculateDerivedStats(primary, m.level), (Object.values(m.equipment) as any[]).map(e=>e?.stats).filter(Boolean) as any);
        return { ...m, derived, currentHp: m.currentHp, currentMp: m.currentMp, gauge: 0, lastDamaged: false };
    }));

    const [enemySquadState, setEnemySquadState] = useState(enemies.map((e, idx) => ({
        ...e,
        instanceId: `enemy_${idx}`,
        gauge: 0,
        lastDamaged: false,
        hasUsedRevival: false
    })));

    const [logs, setLogs] = useState<CombatLogEntry[]>([]);
    const [damagePopups, setDamagePopups] = useState<DamagePopup[]>([]);

    // --- PERSISTENCE: 설정 데이터 유지 ---
    const [isAuto, setIsAuto] = useState(() => {
        const saved = localStorage.getItem('dungeon_combat_auto');
        return saved === null ? true : saved === 'true';
    });

    const [battleSpeed, setBattleSpeed] = useState<1 | 2 | 4>(() => {
        const saved = localStorage.getItem('dungeon_combat_speed');
        const parsed = saved ? parseInt(saved) : 1; 
        if (parsed === 1 || parsed === 2 || parsed === 4) return parsed as 1 | 2 | 4;
        return 1;
    });

    useEffect(() => {
        localStorage.setItem('dungeon_combat_auto', isAuto.toString());
    }, [isAuto]);

    useEffect(() => {
        localStorage.setItem('dungeon_combat_speed', battleSpeed.toString());
    }, [battleSpeed]);

    const [isPaused, setIsPaused] = useState(false);
    const [activeActorId, setActiveActorId] = useState<string | null>(null); 
    const [attackingUnitId, setAttackingUnitId] = useState<string | null>(null);
    const [showLogs, setShowLogs] = useState(false);
    const [showSkillList, setShowSkillList] = useState(false);

    const [pendingAction, setPendingAction] = useState<{ type: 'ATTACK' | 'SKILL', skillId?: string } | null>(null);
    const [inspectedMercId, setInspectedMercId] = useState<string | null>(null);

    const battleInterval = useRef<ReturnType<typeof setInterval> | null>(null);
    const speedRef = useRef(1);

    useEffect(() => {
        speedRef.current = battleSpeed;
    }, [battleSpeed]);

    useEffect(() => {
        const handleResize = () => {
            setOrientation(window.innerWidth > window.innerHeight ? 'LANDSCAPE' : 'PORTRAIT');
        };
        window.addEventListener('resize', handleResize);
        return () => window.removeEventListener('resize', handleResize);
    }, []);

    const addLog = useCallback((msg: string, team: 'PLAYER' | 'ENEMY' | 'SYSTEM', isCrit = false, isSkill = false) => {
        setLogs(prev => [{ msg, team, isCrit, isSkill }, ...prev].slice(0, 50));
    }, []);

    const triggerDamagePopup = useCallback((targetId: string, value: number, isCrit: boolean, isSkill: boolean) => {
        const id = Date.now() + Math.random();
        setDamagePopups(prev => [...prev, { id, value, targetId, isCrit, isSkill }]);
        setTimeout(() => {
            setDamagePopups(prev => prev.filter(p => p.id !== id));
        }, 800 / speedRef.current);
    }, []);

    const executeAttack = useCallback((attacker: any, target: any, isPlayerAttacker: boolean, skillId?: string) => {
        setAttackingUnitId(isPlayerAttacker ? attacker.id : target.instanceId);

        setTimeout(() => {
            const skill = skillId ? SKILLS[skillId] : null;
            const multiplier = skill ? skill.multiplier : 1.0;
            const mpCost = skill?.mpCost ?? 0;

            const res = calculateCombatResult(
                isPlayerAttacker ? attacker.derived : attacker.stats,
                isPlayerAttacker ? target.stats : target.derived,
                isPlayerAttacker ? attacker.job : 'Fighter' as any,
                isPlayerAttacker ? (attacker.derived.magicalAttack > attacker.derived.physicalAttack ? 'MAGICAL' : 'PHYSICAL') : 'PHYSICAL',
                multiplier
            );

            // 명중/회피 시 효과음 출력
            if (res.isHit) {
                window.dispatchEvent(new CustomEvent('play-sfx', { detail: { file: 'battle_slash.mp3' } }));
            } else {
                window.dispatchEvent(new CustomEvent('play-sfx', { detail: { file: 'swing_miss.mp3' } }));
            }

            if (isPlayerAttacker) {
                setEnemySquadState(prev => prev.map(e => {
                    if (e.instanceId === target.instanceId) {
                        const next = { ...e, lastDamaged: res.isHit };
                        if (res.isHit) {
                            let nextHp = Math.max(0, next.currentHp - res.damage);
                            if (nextHp <= 0 && next.id === 'phoenix' && !next.hasUsedRevival) {
                                nextHp = next.stats.maxHp;
                                next.hasUsedRevival = true;
                                addLog("Phoenix rebirth triggered!", 'ENEMY', true, true);
                                triggerDamagePopup(target.instanceId, 0, true, true);
                            } else {
                                next.currentHp = nextHp;
                            }
                            triggerDamagePopup(target.instanceId, res.damage, res.isCrit, !!skill);
                        }
                        setTimeout(() => setEnemySquadState(curr => curr.map(currE => currE.instanceId === target.instanceId ? { ...currE, lastDamaged: false } : currE)), 200 / speedRef.current);
                        return next;
                    }
                    return e;
                }));

                if (skill) {
                    setPartyState(prev => prev.map(p => p.id === attacker.id ? { ...p, currentMp: Math.max(0, p.currentMp - mpCost) } : p));
                    addLog(`${attacker.name} used ${skill.name}!`, 'PLAYER', res.isCrit, true);
                } else {
                    addLog(`${attacker.name} hits ${target.name} for ${res.damage}`, 'PLAYER', res.isCrit);
                }
            } else {
                setPartyState(prev => prev.map(p => {
                    if (p.id === target.id) {
                        const next = { ...p, lastDamaged: res.isHit };
                        if (res.isHit) {
                            next.currentHp = Math.max(0, next.currentHp - res.damage);
                            triggerDamagePopup(p.id, res.damage, res.isCrit, false);
                        }
                        setTimeout(() => setPartyState(curr => curr.map(c => c.id === p.id ? { ...c, lastDamaged: false } : c)), 200 / speedRef.current);
                        return next;
                    }
                    return p;
                }));
                addLog(`${attacker.name} strikes ${target.name} for ${res.damage}`, 'ENEMY');
            }

            setTimeout(() => setAttackingUnitId(null), 150 / speedRef.current);
        }, 200 / speedRef.current);
    }, [addLog, triggerDamagePopup]);

    const processLoop = useCallback(() => {
        if (isPaused || activeActorId || attackingUnitId || inspectedMercId) return;

        const enemiesDefeated = enemySquadState.every(e => e.currentHp <= 0);
        const partyDefeated = partyState.every(p => p.currentHp <= 0);

        if (enemiesDefeated) {
            setIsPaused(true);
            setTimeout(() => onFinish(true, partyState), 800 / speedRef.current);
            return;
        }
        if (partyDefeated) {
            setIsPaused(true);
            setTimeout(() => onFinish(false, partyState), 800 / speedRef.current);
            return;
        }

        // --- SPEED BALANCING: 기초 게이지 충전량 0.2로 고정 ---
        setPartyState(prev => {
            const next = [...prev];
            let readyMerc = null;
            for (let p of next) {
                if (p.currentHp > 0) {
                    p.gauge += (p.derived.speed * 0.2 * speedRef.current); 
                    if (p.gauge >= ACTION_THRESHOLD && !readyMerc) readyMerc = p;
                }
            }
            if (readyMerc && !attackingUnitId) {
                const livingEnemies = enemySquadState.filter(e => e.currentHp > 0);
                if (livingEnemies.length > 0) {
                    if (isAuto) {
                        readyMerc.gauge -= ACTION_THRESHOLD;
                        const target = livingEnemies[Math.floor(Math.random() * livingEnemies.length)];
                        let sid = undefined;

                        // 자동 전투 시 스킬 사용 우선순위 로직
                        // Added casting to any to fix socketedSkillId property access error on unknown type
                        const availableSkillIds = [
                            ...(readyMerc.skillIds || []),
                            ...Object.values(readyMerc.equipment || {}).map(i => (i as any)?.socketedSkillId).filter(Boolean) as string[]
                        ];

                        if (availableSkillIds.length > 0) {
                            const skill = SKILLS[availableSkillIds[0]];
                            if (skill && readyMerc.currentMp >= (skill.mpCost ?? 0) && Math.random() < 0.3) sid = skill.id;
                        }
                        executeAttack(readyMerc, target, true, sid);
                    } else {
                        setActiveActorId(readyMerc.id);
                        setShowSkillList(false);
                        setPendingAction(null);
                    }
                }
            }
            return next;
        });

        setEnemySquadState(prev => {
            const next = [...prev];
            let readyEnemy = null;
            for (let e of next) {
                if (e.currentHp > 0) {
                    e.gauge += (e.stats.speed * 0.2 * speedRef.current); 
                    if (e.gauge >= ACTION_THRESHOLD && !readyEnemy) readyEnemy = e;
                }
            }
            if (readyEnemy && !activeActorId && !attackingUnitId) {
                readyEnemy.gauge -= ACTION_THRESHOLD;
                const livingPlayers = partyState.filter(p => p.currentHp > 0);
                if (livingPlayers.length > 0) {
                    const target = livingPlayers[Math.floor(Math.random() * livingPlayers.length)];
                    executeAttack(readyEnemy, target, false);
                }
            }
            return next;
        });
    }, [isPaused, isAuto, activeActorId, attackingUnitId, inspectedMercId, enemySquadState, partyState, executeAttack, onFinish]);

    useEffect(() => {
        battleInterval.current = setInterval(processLoop, 100);
        return () => { if (battleInterval.current) clearInterval(battleInterval.current); };
    }, [processLoop]);

    const handleTurnConsumed = useCallback((targetMercId: string) => {
        setTimeout(() => {
            const updatedMercFromContext = state.knownMercenaries.find(m => m.id === targetMercId);
            if (updatedMercFromContext) {
                setPartyState(prev => prev.map(p => {
                    if (p.id === targetMercId) {
                        const primary = mergePrimaryStats(updatedMercFromContext.stats, updatedMercFromContext.allocatedStats);
                        const derived = applyEquipmentBonuses(
                            calculateDerivedStats(primary, updatedMercFromContext.level), 
                            (Object.values(updatedMercFromContext.equipment) as any[]).map(e=>e?.stats).filter(Boolean) as any
                        );
                        return { 
                            ...p, 
                            ...updatedMercFromContext, 
                            derived,
                            currentHp: updatedMercFromContext.currentHp,
                            currentMp: updatedMercFromContext.currentMp,
                            gauge: Math.max(0, p.gauge - ACTION_THRESHOLD)
                        };
                    }
                    return p;
                }));
                setInspectedMercId(null);
                setActiveActorId(null);
            }
        }, 50);
    }, [state.knownMercenaries]);

    const handleManualAction = (e: React.MouseEvent, type: 'ATTACK' | 'SKILL', skillId?: string) => {
        e.stopPropagation(); 
        if (!activeActorId) return;

        if (type === 'SKILL' && !skillId) {
            setShowSkillList(true);
            return;
        }

        if (type === 'SKILL' && skillId) {
            const skill = SKILLS[skillId];
            const actor = partyState.find(p => p.id === activeActorId);
            if (!actor || actor.currentMp < (skill?.mpCost ?? 0)) {
                actions.showToast("Not enough MP!");
                return;
            }
            setShowSkillList(false);
        }

        setPendingAction({ type, skillId });
    };

    const handleEnemyClick = (target: any) => {
        if (!activeActorId || !pendingAction) return;
        if (target.currentHp <= 0) return;
        const actor = partyState.find(p => p.id === activeActorId);
        if (!actor) return;
        setPartyState(prev => prev.map(p => p.id === activeActorId ? { ...p, gauge: p.gauge - ACTION_THRESHOLD } : p));
        executeAttack(actor, target, true, pendingAction.skillId);
        setPendingAction(null);
        setActiveActorId(null);
    };

    const handleFlee = (e: React.MouseEvent) => {
        e.stopPropagation();
        if (Math.random() * 100 < fleeChance) {
            onFlee(partyState);
        } else {
            addLog("Escape failed!", 'SYSTEM');
            setActiveActorId(null);
            setPendingAction(null);
            setPartyState(prev => prev.map(p => p.id === activeActorId ? { ...p, gauge: 0 } : p));
        }
    };

    const getUnitStyle = (id: string, side: 'PLAYER' | 'ENEMY'): React.CSSProperties => {
        if (attackingUnitId !== id) return {};
        let transform = orientation === 'PORTRAIT' 
            ? (side === 'PLAYER' ? 'translateY(-120px) scale(1.1)' : 'translateY(120px) scale(1.1)')
            : (side === 'PLAYER' ? 'translateX(120px) scale(1.1)' : 'translateX(-120px) scale(1.1)');
        return { transform, zIndex: 100 };
    };

    const activeActor = useMemo(() => partyState.find(p => p.id === activeActorId), [partyState, activeActorId]);
    const activeActorSkills = useMemo(() => {
        if (!activeActor) return [];
        const learned = (activeActor.skillIds || []).map(id => ({ id, source: 'LEARNED' }));
        // Added casting to any to fix socketedSkillId property access error on unknown type
        const fromGear = Object.values(activeActor.equipment || {}).map(i => (i as any)?.socketedSkillId).filter(Boolean).map(id => ({ id, source: 'GEAR' }));
        return [...learned, ...fromGear as any];
    }, [activeActor]);

    return (
        <div className="fixed inset-0 z-[150] flex flex-col bg-stone-950 animate-in fade-in duration-500 overflow-hidden font-sans pb-safe">
            <style>{`
                @keyframes damage-float { 0% { transform: translateY(0); opacity: 1; } 100% { transform: translateY(-60px); opacity: 0; } }
                .animate-damage { animation: damage-float 1s ease-out forwards; }
                @keyframes unit-shake { 0%, 100% { transform: translate(0,0); } 25% { transform: translate(-4px, 2px); } 50% { transform: translate(4px, -2px); } 75% { transform: translate(-2px, -4px); } }
                .animate-hit { animation: unit-shake 0.2s ease-in-out 3; }
                @keyframes target-pulse { 0% { transform: scale(1); box-shadow: 0 0 0 0 rgba(239, 68, 68, 0.7); } 70% { transform: scale(1.05); box-shadow: 0 0 0 10px rgba(239, 68, 68, 0); } 100% { transform: scale(1); } }
                .animate-target { animation: target-pulse 1.5s infinite; }
            `}</style>

            {/* Background Tile Layer */}
            {dungeonInfo?.tile && (
                <div className="absolute inset-0 z-0 overflow-hidden pointer-events-none">
                    <img 
                        src={getAssetUrl(dungeonInfo.tile, 'dungeons')} 
                        className="w-full h-full object-cover opacity-60 brightness-[0.6]" 
                        alt="Combat Background" 
                    />
                </div>
            )}

            {/* Top Bar */}
            <div className="p-3 bg-red-950/20 border-b border-red-900/30 flex justify-between items-center z-[200] backdrop-blur-sm">
                <div className="flex items-center gap-2">
                    <Skull className="w-4 h-4 text-red-50" />
                    <h2 className="text-white font-black uppercase text-[10px] md:text-sm tracking-widest font-mono">Combat Zone</h2>
                </div>
                <div className="flex items-center gap-3 bg-black/40 px-3 py-1 rounded-full border border-white/5">
                    <SfxButton sfx="switch" onClick={() => setIsPaused(!isPaused)} className={`p-1.5 rounded-full transition-all ${isPaused ? 'bg-amber-600 text-white' : 'bg-stone-800 text-stone-400'}`}>
                        {isPaused ? <Play size={14} /> : <Pause size={14} />}
                    </SfxButton>
                    <div className="flex items-center gap-1">
                        {[1, 2, 4].map(s => (
                            <SfxButton sfx="switch" key={s} onClick={() => setBattleSpeed(s as any)} className={`px-2 py-0.5 rounded font-mono text-[8px] md:text-[10px] font-black ${battleSpeed === s ? 'bg-indigo-600 text-white' : 'text-stone-600'}`}>{s}x</SfxButton>
                        ))}
                    </div>
                </div>
                <SfxButton sfx="switch" onClick={() => { setIsAuto(!isAuto); setPendingAction(null); setShowSkillList(false); }} className={`px-4 py-1.5 rounded-lg border font-black text-[9px] tracking-widest transition-all ${isAuto ? 'bg-amber-600 border-amber-400 text-white' : 'bg-stone-800 border-stone-600 text-stone-400'}`}>
                    {isAuto ? 'AUTO' : 'MANUAL'}
                </SfxButton>
            </div>

            {/* Combat Field */}
            <div className={`flex-1 flex relative transition-all duration-700 z-10 ${orientation === 'PORTRAIT' ? 'flex-col' : 'flex-row'}`}>
                {/* Enemies Area */}
                <div className={`flex flex-1 items-center justify-center p-4 gap-6 md:gap-12 ${orientation === 'PORTRAIT' ? 'order-1' : 'order-2'}`}>
                    {enemySquadState.map(e => (
                        <div key={e.instanceId} style={getUnitStyle(e.instanceId, 'ENEMY')} onClick={() => pendingAction && e.currentHp > 0 && handleEnemyClick(e)} className={`relative flex flex-col items-center transition-all ${e.currentHp <= 0 ? 'opacity-20 grayscale' : e.lastDamaged ? 'animate-hit' : ''}`}>
                            <div className={`w-24 h-24 md:w-48 md:h-48 bg-stone-900 rounded-2xl border-2 flex items-center justify-center relative shadow-2xl ${e.lastDamaged ? 'border-red-500 bg-red-950/20' : 'border-stone-800'} ${pendingAction && e.currentHp > 0 ? 'animate-target border-red-500 cursor-crosshair' : ''}`}>
                                <img src={getAssetUrl(e.sprite || '', 'monsters')} className="w-[80%] h-[80%] object-contain" alt={e.name} />
                                {pendingAction && e.currentHp > 0 && <div className="absolute inset-0 flex items-center justify-center"><Target className="w-12 h-12 text-red-500 opacity-50" /></div>}
                                <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
                                    {damagePopups.filter(p => p.targetId === e.instanceId).map(p => (
                                        <div key={p.id} className={`absolute font-black text-3xl md:text-5xl animate-damage ${p.isCrit ? 'text-amber-400 scale-125' : 'text-red-500'}`}>-{p.value}</div>
                                    ))}
                                </div>
                            </div>
                            {e.currentHp > 0 && (
                                <div className="mt-2 w-24 md:w-52 space-y-1">
                                    <div className="flex flex-col items-center leading-none mb-1">
                                        <span className="text-[9px] md:text-xs font-black text-stone-300 uppercase tracking-tighter truncate w-full text-center">{e.name}</span>
                                        <span className="text-[7px] md:text-[9px] font-bold text-stone-500 uppercase tracking-widest">Lv.{e.level}</span>
                                    </div>
                                    <div className="relative h-2.5 bg-black rounded-full overflow-hidden border border-white/5">
                                        <div className="h-full bg-red-600 transition-all duration-500" style={{ width: `${(e.currentHp/e.stats.maxHp)*100}%` }} />
                                        <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
                                            <span className="text-[7px] md:text-[10px] font-mono font-black text-white drop-shadow-sm">{Math.floor(e.currentHp)} / {e.stats.maxHp}</span>
                                        </div>
                                    </div>
                                    <div className="h-1 bg-black rounded-full overflow-hidden">
                                        <div className="h-full bg-amber-500 transition-all" style={{ width: `${(e.gauge/ACTION_THRESHOLD)*100}%` }} />
                                    </div>
                                </div>
                            )}
                        </div>
                    ))}
                </div>

                {/* Players Area */}
                <div className={`flex flex-1 items-center justify-center p-4 gap-6 md:gap-12 ${orientation === 'PORTRAIT' ? 'order-3 pt-0' : 'order-1'}`}>
                    {partyState.map(p => {
                        const isActive = activeActorId === p.id;
                        const hpPer = (p.currentHp / p.derived.maxHp) * 100;
                        const mpPer = (p.currentMp / (p.derived.maxMp || 1)) * 100;

                        return (
                            <div key={p.id} style={getUnitStyle(p.id, 'PLAYER')} className={`relative flex flex-col items-center transition-all ${p.currentHp <= 0 ? 'opacity-20 grayscale' : isActive ? '-translate-y-4' : ''} ${p.lastDamaged ? 'animate-hit' : ''}`}>
                                {/* Portrait Container */}
                                <div className={`w-24 h-24 md:w-48 md:h-48 bg-stone-900 rounded-2xl border-2 flex items-center justify-center relative shadow-2xl ${isActive ? 'border-amber-400 ring-4 ring-amber-500/20' : 'border-stone-800'}`}>
                                    <MercenaryPortrait mercenary={p} className="w-[85%] h-[85%] rounded-xl" />
                                    <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
                                        {damagePopups.filter(pop => pop.targetId === p.id).map(pop => (
                                            <div key={pop.id} className="absolute font-black text-3xl md:text-5xl animate-damage text-red-50">-{pop.value}</div>
                                        ))}
                                    </div>

                                    {/* Action indicator for targeting */}
                                    {pendingAction && isActive && (
                                        <div className="absolute -top-12 left-1/2 -translate-x-1/2 flex flex-col items-center animate-bounce">
                                            <div className="bg-amber-600 text-white px-3 py-1 rounded-full text-[10px] font-black uppercase shadow-lg border border-amber-400">
                                                {pendingAction.skillId ? SKILLS[pendingAction.skillId].name : 'Striking'}
                                            </div>
                                            <div className="w-0 h-0 border-l-[6px] border-l-transparent border-r-[6px] border-r-transparent border-t-[6px] border-t-amber-600"></div>
                                        </div>
                                    )}

                                    {isActive && !pendingAction && !isAuto && !showSkillList && (
                                        <div className="absolute -bottom-40 left-1/2 -translate-x-1/2 z-[300] bg-stone-900/95 border-2 border-amber-500 p-2.5 rounded-2xl grid grid-cols-2 gap-3 shadow-2xl animate-in slide-in-from-top-2 backdrop-blur-md w-40">
                                            <SfxButton onClick={(e) => handleManualAction(e, 'ATTACK')} className="p-3 bg-stone-800 hover:bg-stone-700 rounded-xl text-white transition-colors border border-white/5 flex flex-col items-center gap-1 group">
                                                <Sword size={20} className="group-hover:scale-110 transition-transform" />
                                                <span className="text-[8px] font-black uppercase">Atk</span>
                                            </SfxButton>
                                            <SfxButton onClick={(e) => handleManualAction(e, 'SKILL')} className="p-3 bg-indigo-900/40 hover:bg-indigo-800 rounded-xl text-indigo-100 transition-colors border border-indigo-500/30 flex flex-col items-center gap-1 group">
                                                <Wand2 size={20} className="group-hover:scale-110 transition-transform" />
                                                <span className="text-[8px] font-black uppercase">Skill</span>
                                            </SfxButton>
                                            <SfxButton sfx="switch" onClick={(e) => { e.stopPropagation(); setInspectedMercId(p.id); }} className="p-3 bg-stone-800 hover:bg-stone-750 rounded-xl text-stone-300 transition-colors border border-stone-700 flex flex-col items-center gap-1 group">
                                                <Package size={20} className="group-hover:scale-110 transition-transform" />
                                                <span className="text-[8px] font-black uppercase">Bag</span>
                                            </SfxButton>
                                            <SfxButton onClick={(e) => handleFlee(e)} className="p-3 bg-red-950/40 hover:bg-red-900 rounded-xl text-red-500 transition-colors border border-red-500/30 flex flex-col items-center gap-1 group">
                                                <LogOut size={20} className="group-hover:scale-110 transition-transform" />
                                                <span className="text-[8px] font-black uppercase">Flee</span>
                                            </SfxButton>
                                        </div>
                                    )}

                                    {/* Skill List Overlay */}
                                    {isActive && showSkillList && (
                                        <div className="absolute -bottom-52 left-1/2 -translate-x-1/2 z-[310] bg-stone-900/98 border-2 border-indigo-500 p-3 rounded-2xl shadow-2xl animate-in zoom-in-95 backdrop-blur-xl w-64 md:w-80">
                                            <div className="flex justify-between items-center mb-2 px-1">
                                                <span className="text-[10px] font-black text-indigo-400 uppercase tracking-widest">Available Skills</span>
                                                <SfxButton sfx="switch" onClick={() => setShowSkillList(false)} className="text-stone-500 hover:text-white"><X size={16} /></SfxButton>
                                            </div>
                                            <div className="space-y-1.5 max-h-48 overflow-y-auto custom-scrollbar pr-1">
                                                {activeActorSkills.map((ref, idx) => {
                                                    const skill = SKILLS[ref.id];
                                                    if (!skill) return null;
                                                    const canCast = activeActor.currentMp >= (skill.mpCost ?? 0);
                                                    return (
                                                        <button 
                                                            key={`${ref.id}-${idx}`}
                                                            disabled={!canCast}
                                                            onClick={(e) => handleManualAction(e, 'SKILL', ref.id)}
                                                            className={`w-full flex items-center justify-between p-2 rounded-xl border transition-all text-left group ${canCast ? 'bg-indigo-900/20 border-indigo-500/30 hover:bg-indigo-800/40 hover:border-indigo-400' : 'bg-stone-900 border-stone-800 opacity-50 grayscale cursor-not-allowed'}`}
                                                        >
                                                            <div className="flex items-center gap-2 min-w-0">
                                                                <div className={`p-1.5 rounded-lg border ${ref.source === 'GEAR' ? 'bg-purple-900/30 border-purple-500/50 text-purple-400' : 'bg-indigo-900/40 border-indigo-500/50 text-indigo-300'}`}>
                                                                    <Zap size={14} />
                                                                </div>
                                                                <div className="min-w-0 flex flex-col leading-tight">
                                                                    <span className="text-[10px] font-black text-stone-100 uppercase truncate">{skill.name}</span>
                                                                    <span className="text-[7px] text-stone-500 italic truncate">{skill.description}</span>
                                                                </div>
                                                            </div>
                                                            <div className="flex items-center gap-1.5 shrink-0 pl-2">
                                                                <span className="text-[9px] font-mono font-black text-blue-400">{skill.mpCost} MP</span>
                                                                <ChevronRight size={14} className="text-stone-700 group-hover:text-white transition-colors" />
                                                            </div>
                                                        </button>
                                                    );
                                                })}
                                                {activeActorSkills.length === 0 && (
                                                    <div className="py-8 text-center text-stone-600 text-[10px] font-black uppercase tracking-widest opacity-40 italic">No usable skills</div>
                                                )}
                                            </div>
                                            {pendingAction && (
                                                <div className="mt-3 pt-3 border-t border-indigo-500/30">
                                                    <SfxButton onClick={() => setPendingAction(null)} className="w-full py-2 bg-stone-800 hover:bg-stone-700 text-stone-400 text-[10px] font-black uppercase rounded-lg">Cancel Selection</SfxButton>
                                                </div>
                                            )}
                                        </div>
                                    )}
                                </div>

                                {p.currentHp > 0 && (
                                    <div className="mt-2 w-24 md:w-52 space-y-1">
                                        {/* Full Name, Job, Level */}
                                        <div className="flex flex-col items-center leading-none mb-1">
                                            <span className="text-[9px] md:text-xs font-black text-stone-100 uppercase tracking-tighter truncate w-full text-center">{p.name}</span>
                                            <span className="text-[7px] md:text-[10px] font-bold text-stone-500 uppercase tracking-widest mt-0.5">{p.job} • Lv.{p.level}</span>
                                        </div>

                                        {/* HP Bar & Value */}
                                        <div className="relative h-3 bg-black rounded-full overflow-hidden border border-white/5 shadow-inner">
                                            <div className={`h-full transition-all duration-500 ${hpPer < 30 ? 'bg-red-500 animate-pulse' : 'bg-red-600'}`} style={{ width: `${hpPer}%` }} />
                                            <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
                                                <span className="text-[7px] md:text-[11px] font-mono font-black text-white drop-shadow-sm">{Math.floor(p.currentHp)} / {p.derived.maxHp}</span>
                                            </div>
                                        </div>

                                        {/* MP Bar & Value */}
                                        <div className="relative h-2.5 bg-black rounded-full overflow-hidden border border-white/5 shadow-inner">
                                            <div className="h-full bg-blue-600 transition-all duration-500" style={{ width: `${mpPer}%` }} />
                                            <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
                                                <span className="text-[6px] md:text-[9px] font-mono font-black text-blue-100 drop-shadow-sm">{Math.floor(p.currentMp)} / {p.derived.maxMp}</span>
                                            </div>
                                        </div>

                                        {/* ATB Gauge */}
                                        <div className="h-1 bg-black rounded-full overflow-hidden">
                                            <div className="h-full bg-amber-500 transition-all" style={{ width: `${(p.gauge/ACTION_THRESHOLD)*100}%` }} />
                                        </div>
                                    </div>
                                )}
                            </div>
                        );
                    })}
                </div>
            </div>

            {/* Tactical Feed */}
            <div className={`bg-stone-900 border-t border-stone-800 flex flex-col shrink-0 transition-all z-10 ${showLogs ? 'h-48' : 'h-18'}`}>
                <button onClick={() => setShowLogs(!showLogs)} className="w-full h-10 flex items-center justify-between px-4 bg-black/20 hover:bg-black/40 transition-colors shrink-0">
                    <div className="flex items-center gap-2">
                        <Activity className={`w-3.5 h-3.5 ${isPaused ? 'text-stone-600' : 'text-amber-500 animate-pulse'}`} />
                        <span className="text-[9px] font-black text-stone-500 uppercase tracking-widest">Engagement Feed</span>
                    </div>
                    {showLogs ? <ChevronDown size={14} /> : <ChevronUp size={14} />}
                </button>
                <div className={`flex-1 ${showLogs ? 'overflow-y-auto' : 'overflow-hidden'} p-2 space-y-1 font-mono text-[9px] custom-scrollbar`}>
                    {(showLogs ? logs : logs.slice(0, 1)).map((log, i) => (
                        <div key={i} className={`p-1.5 border-l-2 ${log.team === 'PLAYER' ? 'border-blue-500 text-blue-100' : log.team === 'ENEMY' ? 'border-red-500 text-red-100' : 'border-stone-700 text-stone-400'} ${log.isCrit ? 'bg-white/5 font-black' : ''}`}>
                            <span className="opacity-30 mr-2">[{new Date().toLocaleTimeString([], { hour12: false, minute: '2-digit', second: '2-digit' })}]</span>
                            {log.msg}
                        </div>
                    ))}
                </div>
            </div>

            {/* Modals */}
            {inspectedMercId && (
                <MercenaryDetailModal 
                    mercenary={partyState.find(p => p.id === inspectedMercId) || null}
                    onClose={() => setInspectedMercId(null)}
                    onEquip={(mercId, itemId) => { actions.equipItem(mercId, itemId); handleTurnConsumed(mercId); }}
                    onConsume={(mercId, itemId) => { actions.useItem(itemId, mercId); handleTurnConsumed(mercId); }}
                    onUnequip={(mercId, slot) => { actions.unequipItem(mercId, slot); handleTurnConsumed(mercId); }}
                    isReadOnly={false} 
                />
            )}
        </div>
    );
};

export default DungeonCombatView;

import React, { useMemo } from 'react';
import { 
  Sword, Shield, Activity, Star, Zap, Brain, Target, Wind, 
  Plus, Minus, RotateCcw, Save, Heart, Sparkles, Wrench
} from 'lucide-react';
import { Mercenary } from '../../models/Mercenary';
import { DerivedStats, PrimaryStats } from '../../models/Stats';
import { SKILLS } from '../../data/skills';
import { StatDiff } from './StatDiff';
import { SfxButton } from '../common/ui/SfxButton';

interface MercenaryStatsPanelProps {
  mercenary: Mercenary;
  baseStats: DerivedStats;
  finalStats: DerivedStats;
  pendingAllocated: PrimaryStats;
  pendingPoints: number;
  equipmentStats: PrimaryStats;
  previewEquipmentStats: PrimaryStats | null;
  onModifyStat: (key: keyof PrimaryStats, delta: number) => void;
  onSave: () => void;
  onReset: () => void;
  isReadOnly?: boolean;
}

export const MercenaryStatsPanel: React.FC<MercenaryStatsPanelProps> = ({
  mercenary,
  baseStats,
  finalStats,
  pendingAllocated,
  pendingPoints,
  equipmentStats,
  previewEquipmentStats,
  onModifyStat,
  onSave,
  onReset,
  isReadOnly,
}) => {
  const xpPercent =
    mercenary.xpToNextLevel > 0
      ? Math.min(100, Math.max(0, (mercenary.currentXp / mercenary.xpToNextLevel) * 100))
      : 0;
  const hpPercent = finalStats.maxHp > 0 ? (mercenary.currentHp / finalStats.maxHp) * 100 : 0;
  const mpPercent = finalStats.maxMp > 0 ? (mercenary.currentMp / finalStats.maxMp) * 100 : 0;
  const staminaPercent = Math.min(100, Math.max(0, (mercenary.expeditionEnergy || 0)));

  const isModified = useMemo(() => {
    return (Object.keys(pendingAllocated) as Array<keyof PrimaryStats>).some(
        key => pendingAllocated[key] !== mercenary.allocatedStats[key]
    );
  }, [pendingAllocated, mercenary.allocatedStats]);

  // Combine learned skills and equipment-socketed skills
  // Fixed scoping issues and cast to any to allow access to socketedSkillId on unknown values
  const allAvailableSkills = useMemo(() => {
      const learnedSkills = (mercenary.skillIds || []).map(id => ({ id, source: 'LEARNED' as const }));

      const fromGear: { id: string, source: 'GEAR' as const }[] = [];
      (Object.values(mercenary.equipment) as (any | null)[]).forEach(item => {
          if (item?.socketedSkillId) {
              fromGear.push({ id: item.socketedSkillId, source: 'GEAR' as const });
          }
      });

      return [...learnedSkills, ...fromGear];
  }, [mercenary.skillIds, mercenary.equipment]);

  const renderStatRow = (icon: React.ReactNode, label: string, baseValue: number, nextValue: number, isPercent = false) => {
    return (
      <div className="bg-stone-950/40 p-1.5 md:p-3 rounded-lg border border-white/5 flex justify-between items-center h-8 md:h-12">
        <span className="text-[7px] md:text-xs text-stone-500 font-black uppercase flex items-center gap-1.5 md:gap-2">
          {icon}
          <span className="hidden md:inline">{label}</span>
          <span className="md:hidden truncate max-w-[40px]">
            {label === 'Physical Atk' ? 'P.Atk' : label === 'Physical Def' ? 'P.Def' : label === 'Magical Atk' ? 'M.Atk' : label === 'Magical Def' ? 'M.Def' : label === 'Crit Rate' ? 'Crit' : label === 'Evasion' ? 'Eva' : label}
          </span>
        </span>
        <div className="flex items-center gap-1 md:gap-2">
          <span className={`font-mono text-[9px] md:text-base font-black ${nextValue > baseValue ? 'text-emerald-400' : nextValue < baseValue ? 'text-red-400' : 'text-stone-300'}`}>
            {isPercent ? nextValue.toFixed(1) : Math.round(nextValue)}
            {isPercent ? '%' : ''}
          </span>
          <StatDiff current={baseValue} next={nextValue} isPercent={isPercent} />
        </div>
      </div>
    );
  };

  return (
    <div className="p-3 md:p-6 flex flex-col gap-4 md:gap-6 bg-stone-900/10 border-t border-white/5">
      <div className="bg-stone-950/40 p-3 md:p-5 rounded-xl border border-white/5 shadow-inner shrink-0">
        <div className="flex justify-between items-end mb-1 md:mb-2 leading-none">
          <span className="text-amber-500 font-black font-mono text-[10px] md:text-lg uppercase tracking-tight">
            XP PROGRESS
          </span>
          <span className="text-stone-500 text-[8px] md:text-sm font-mono font-bold">
            {mercenary.currentXp} / {mercenary.xpToNextLevel}
          </span>
        </div>
        <div className="w-full h-1 md:h-2 bg-stone-900 rounded-full overflow-hidden border border-white/5">
          <div className="h-full bg-gradient-to-r from-amber-800 to-amber-500 transition-all duration-700" style={{ width: `${xpPercent}%` }} />
        </div>
      </div>

      <div className="bg-stone-950/60 rounded-xl border border-stone-800 p-3 md:p-6 shrink-0 relative overflow-hidden">
        <div className="flex justify-between items-center mb-3 md:mb-4 px-1">
          <h4 className="text-[8px] md:text-xs font-black text-stone-500 uppercase tracking-widest flex items-center gap-1.5 md:gap-2">
            <Star className="w-3 h-3 text-amber-600" /> Attributes
          </h4>
          {!isReadOnly && (
            <span className={`text-[8px] md:text-xs font-black px-2 md:px-3 py-0.5 md:py-1 border rounded-full transition-all ${pendingPoints > 0 ? 'bg-amber-900/30 border-amber-500/30 text-amber-400 animate-pulse' : 'bg-stone-900 border-stone-700 text-stone-600'}`}>
              {pendingPoints} AP AVAILABLE
            </span>
          )}
        </div>

        <div className="grid grid-cols-5 gap-1.5 md:gap-4">
          {[
            { label: 'STR', key: 'str' as const, color: 'text-orange-400' },
            { label: 'INT', key: 'int' as const, color: 'text-blue-400' },
            { label: 'DEX', key: 'dex' as const, color: 'text-emerald-400' },
            { label: 'VIT', key: 'vit' as const, color: 'text-red-400' },
            { label: 'LUK', key: 'luk' as const, color: 'text-pink-400' },
          ].map((stat) => {
            const currentEquipBonus = equipmentStats[stat.key] || 0;
            const currentTotal = mercenary.stats[stat.key] + mercenary.allocatedStats[stat.key] + currentEquipBonus;

            const previewEquipBonus = previewEquipmentStats ? (previewEquipmentStats[stat.key] || 0) : currentEquipBonus;
            const previewTotal = mercenary.stats[stat.key] + pendingAllocated[stat.key] + previewEquipBonus;

            const isAllocatedModified = pendingAllocated[stat.key] > mercenary.allocatedStats[stat.key];
            const isPreviewing = previewEquipmentStats !== null;

            return (
              <div key={stat.key} className="flex flex-col gap-1 md:gap-2">
                <div
                  className={`bg-stone-900/80 border ${isAllocatedModified || (isPreviewing && previewTotal !== currentTotal) ? 'border-amber-500 shadow-glow-sm' : 'border-stone-800'} p-1 md:p-2 rounded-lg flex flex-col items-center justify-center h-14 md:h-20 transition-all relative`}
                >
                  <span className={`text-[6px] md:text-[8px] font-black ${stat.color} mb-0.5`}>{stat.label}</span>
                  <div className="flex items-center gap-0.5">
                    <span className={`text-[10px] md:text-lg font-mono font-black ${isPreviewing && previewTotal > currentTotal ? 'text-emerald-400' : isPreviewing && previewTotal < currentTotal ? 'text-red-400' : isAllocatedModified ? 'text-amber-400' : 'text-stone-400'}`}>
                      {previewTotal}
                    </span>
                  </div>
                  {previewEquipBonus > 0 && <span className="text-[6px] md:text-[8px] font-bold text-emerald-400 leading-none mt-0.5">+{previewEquipBonus}</span>}
                </div>

                {!isReadOnly && (
                  <div className="flex flex-col gap-1">
                    <SfxButton
                      onClick={() => onModifyStat(stat.key, 1)}
                      disabled={pendingPoints <= 0}
                      className="w-full h-4 md:h-7 bg-stone-800 hover:bg-amber-600 text-stone-500 hover:text-white rounded transition-all disabled:opacity-20 flex items-center justify-center shadow-sm"
                    >
                      <Plus className="w-2.5 h-2.5 md:w-3.5 md:h-3.5" />
                    </SfxButton>
                    <SfxButton
                      onClick={() => onModifyStat(stat.key, -1)}
                      disabled={pendingAllocated[stat.key] <= mercenary.allocatedStats[stat.key]}
                      className="w-full h-4 md:h-7 bg-stone-800 hover:bg-red-900 text-stone-500 hover:text-white rounded transition-all disabled:opacity-20 flex items-center justify-center shadow-sm"
                    >
                      <Minus className="w-2.5 h-2.5 md:w-3.5 md:h-3.5" />
                    </SfxButton>
                  </div>
                )}
              </div>
            );
          })}
        </div>
      </div>

      {isModified && !isReadOnly && (
          <div className="flex gap-2 animate-in slide-in-from-bottom-2 duration-300">
              <SfxButton 
                sfx="switch"
                onClick={onReset}
                className="flex-1 flex items-center justify-center gap-2 py-2.5 bg-stone-800 hover:bg-stone-750 text-stone-400 hover:text-stone-200 rounded-xl border border-stone-700 transition-all text-[10px] font-black uppercase tracking-widest"
              >
                  <RotateCcw className="w-3.5 h-3.5" /> Discard
              </SfxButton>
              <SfxButton 
                onClick={onSave}
                className="flex-[2] flex items-center justify-center gap-2 py-2.5 bg-amber-600 hover:bg-amber-500 text-white rounded-xl border-b-4 border-amber-800 shadow-xl transition-all active:translate-y-0.5 text-[10px] font-black uppercase tracking-widest"
              >
                  <Save className="w-3.5 h-3.5" /> Save Attributes
              </SfxButton>
          </div>
      )}

      <div className="grid grid-cols-1 sm:grid-cols-3 gap-2 md:gap-4 shrink-0">
        <div className="bg-stone-950/40 p-2 md:p-3 rounded-xl border border-white/5 flex items-center gap-2 md:gap-3 shadow-sm">
          <div className="p-1.5 md:p-2 bg-red-950/40 rounded-lg text-red-500 border border-red-900/30">
            <Heart className="w-3.5 h-3.5 md:w-5 md:h-5" />
          </div>
          <div className="flex-1 min-w-0">
            <div className="flex justify-between text-[7px] md:text-[10px] text-stone-500 font-black mb-0.5 md:mb-1">
              <span>HP</span>
              <span className="text-stone-300 font-mono">
                {Math.floor(mercenary.currentHp)}/{finalStats.maxHp}
              </span>
            </div>
            <div className="w-full h-1 md:h-1.5 bg-stone-900 rounded-full overflow-hidden shadow-inner">
              <div className="h-full bg-red-600 transition-all duration-500" style={{ width: `${hpPercent}%` }} />
            </div>
          </div>
        </div>

        <div className="bg-stone-950/40 p-2 md:p-3 rounded-xl border border-white/5 flex items-center gap-2 md:gap-3 shadow-sm">
          <div className="p-1.5 md:p-2 bg-blue-950/40 rounded-lg text-blue-400 border border-blue-900/30">
            <Activity className="w-3.5 h-3.5 md:w-5 md:h-5" />
          </div>
          <div className="flex-1 min-w-0">
            <div className="flex justify-between text-[7px] md:text-[10px] text-stone-500 font-black mb-0.5 md:mb-1">
              <span>MP</span>
              <span className="text-stone-300 font-mono">
                {Math.floor(mercenary.currentMp)}/{finalStats.maxMp}
              </span>
            </div>
            <div className="w-full h-1 md:h-1.5 bg-stone-900 rounded-full overflow-hidden shadow-inner">
              <div className="h-full bg-blue-600 transition-all duration-500" style={{ width: `${mpPercent}%` }} />
            </div>
          </div>
        </div>

        <div className="bg-stone-950/40 p-2 md:p-3 rounded-xl border border-white/5 flex items-center gap-2 md:gap-3 shadow-sm">
          <div className="p-1.5 md:p-2 bg-stone-800 rounded-lg text-stone-100 border border-white/10">
            <Zap className={`w-3.5 h-3.5 md:w-5 md:h-5 ${staminaPercent < 20 ? 'animate-pulse text-red-500' : 'text-stone-100'}`} />
          </div>
          <div className="flex-1 min-w-0">
            <div className="flex justify-between text-[7px] md:text-[10px] text-stone-500 font-black mb-0.5 md:mb-1">
              <span>STAMINA</span>
              <span className="text-stone-300 font-mono">
                {Math.floor(mercenary.expeditionEnergy || 0)}/100
              </span>
            </div>
            <div className="w-full h-1 md:h-1.5 bg-stone-900 rounded-full overflow-hidden shadow-inner">
              <div className={`h-full transition-all duration-500 ${staminaPercent < 20 ? 'bg-red-500 animate-pulse' : 'bg-stone-100'}`} style={{ width: `${staminaPercent}%` }} />
            </div>
          </div>
        </div>
      </div>

      <div className="space-y-2 md:space-y-3 pb-2 shrink-0">
        <h4 className="text-[8px] md:text-xs font-black text-stone-500 uppercase tracking-widest flex items-center gap-1.5 px-1">
          <Sword className="w-3 h-3" /> Battle Performance
        </h4>
        <div className="grid grid-cols-2 gap-1.5 md:gap-4">
          {renderStatRow(<Sword className="w-3 h-3 md:w-4 md:h-4 text-orange-500" />, 'Physical Atk', baseStats.physicalAttack, finalStats.physicalAttack)}
          {renderStatRow(<Shield className="w-3 h-3 md:w-4 md:h-4 text-blue-500" />, 'Physical Def', baseStats.physicalDefense, finalStats.physicalDefense)}
          {renderStatRow(<Zap className="w-3 h-3 md:w-4 md:h-4 text-blue-400" />, 'Magical Atk', baseStats.magicalAttack, finalStats.magicalAttack)}
          {renderStatRow(<Brain className="w-3 h-3 md:w-4 md:h-4 text-purple-400" />, 'Magical Def', baseStats.magicalDefense, finalStats.magicalDefense)}
          {renderStatRow(<Target className="w-3 h-3 md:w-4 md:h-4 text-red-500" />, 'Crit Rate', baseStats.critChance, finalStats.critChance, true)}
          {renderStatRow(<Wind className="w-3 h-3 md:w-4 md:h-4 text-emerald-400" />, 'Evasion', baseStats.evasion, finalStats.evasion)}
        </div>
      </div>

      <div className="space-y-2 md:space-y-3 pb-6 shrink-0">
        <h4 className="text-[8px] md:text-xs font-black text-stone-500 uppercase tracking-widest flex items-center gap-1.5 px-1">
          <Sparkles className="w-3 h-3 text-amber-600" /> Techniques & Skills
        </h4>

        {allAvailableSkills.length > 0 ? (
          <div className="space-y-1.5 md:space-y-3">
            {allAvailableSkills.map((skillRef, idx) => {
              const skill = SKILLS[skillRef.id];
              if (!skill) return null;
              const isGearSkill = skillRef.source === 'GEAR';

              return (
                <div
                  key={`${skillRef.id}-${idx}`}
                  className={`bg-stone-950/40 border rounded-xl p-3 md:p-4 flex justify-between items-center gap-3 hover:border-amber-900/40 transition-all ${isGearSkill ? 'border-indigo-500/30 bg-indigo-900/10' : 'border-stone-800'}`}
                >
                  <div className="flex items-center gap-3 min-w-0">
                    <div className={`p-2 rounded-lg border shrink-0 ${isGearSkill ? 'bg-indigo-900/30 border-indigo-500/50 text-indigo-400' : 'bg-amber-900/15 border-amber-600/20 text-amber-500'}`}>
                      {isGearSkill ? <Wrench className="w-3.5 h-3.5 md:w-4 md:h-4" /> : <Sword className="w-3.5 h-3.5 md:w-4 md:h-4" />}
                    </div>
                    <div className="min-w-0">
                      <div className="flex items-center gap-1.5">
                          <h5 className="text-[10px] md:text-xs font-black text-stone-200 uppercase truncate">{skill.name}</h5>
                          {isGearSkill && <span className="text-[6px] md:text-[8px] font-black bg-indigo-600 text-white px-1 py-0.5 rounded leading-none uppercase">Gear</span>}
                      </div>
                      <p className="text-[8px] md:text-[9px] text-stone-500 italic leading-tight line-clamp-1">
                        {skill.description}
                      </p>
                    </div>
                  </div>
                  <div className="text-right shrink-0">
                     <span className="text-[7px] md:text-[8px] font-black text-amber-500 uppercase tracking-tighter">
                        {Math.round((skill.multiplier || 0) * 100)}% {skill.damageType || 'EFF'}
                      </span>
                  </div>
                </div>
              );
            })}
          </div>
        ) : (
          <div className="py-4 md:py-6 text-center border-2 border-dashed border-stone-800 rounded-xl text-stone-600 text-[8px] md:text-[10px] font-bold uppercase tracking-widest">
            No available skills
          </div>
        )}
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import { Shield, Sword, Activity, Skull, Zap, LogOut, FastForward, Pause, Play, ChevronDown, ChevronUp, Sparkles, Target, Package, X, Check, RotateCcw, Wand2, ChevronRight } from 'lucide-react';
import { Mercenary } from '../../../models/Mercenary';
import { Monster } from '../../../models/Monster';
import { ManualDungeonSession } from '../../../types/game-state';
import { calculateCombatResult } from '../../../utils/combatLogic';
import { calculateDerivedStats, applyEquipmentBonuses, mergePrimaryStats } from '../../../models/Stats';
import { useGame } from '../../../context/GameContext';
import { SKILLS } from '../../../data/skills';
import { MercenaryPortrait } from '../../common/ui/MercenaryPortrait';
import { getAssetUrl } from '../../../utils';
import { InventoryItem, EquipmentSlotType } from '../../../types/inventory';
import { MercenaryDetailModal } from '../../modals/MercenaryDetailModal';
import { DUNGEONS } from '../../../data/dungeons';
import { SfxButton } from '../../common/ui/SfxButton';

const ACTION_THRESHOLD = 1000;

interface CombatLogEntry {
    msg: string;
    team: 'PLAYER' | 'ENEMY' | 'SYSTEM';
    isCrit?: boolean;
    isSkill?: boolean;
}

interface DamagePopup {
    id: number;
    value: number;
    targetId: string;
    isCrit: boolean;
    isSkill: boolean;
}

interface DungeonCombatViewProps {
    session: ManualDungeonSession;
    party: Mercenary[];
    enemies: Monster[];
    fleeChance: number;
    onFinish: (win: boolean, finalParty: any[]) => void;
    onFlee: (finalParty: any[]) => void;
}

const DungeonCombatView: React.FC<DungeonCombatViewProps> = ({ session, party, enemies, fleeChance, onFinish, onFlee }) => {
    const { state, actions } = useGame();
    const [orientation, setOrientation] = useState<'PORTRAIT' | 'LANDSCAPE'>(
        window.innerWidth > window.innerHeight ? 'LANDSCAPE' : 'PORTRAIT'
    );

    const dungeonInfo = useMemo(() => DUNGEONS.find(d => d.id === session.dungeonId), [session.dungeonId]);

    const [partyState, setPartyState] = useState(party.map(m => {
        const primary = mergePrimaryStats(m.stats, m.allocatedStats);
        const derived = applyEquipmentBonuses(calculateDerivedStats(primary, m.level), (Object.values(m.equipment) as any[]).map(e=>e?.stats).filter(Boolean) as any);
        return { ...m, derived, currentHp: m.currentHp, currentMp: m.currentMp, gauge: 0, lastDamaged: false };
    }));

    const [enemySquadState, setEnemySquadState] = useState(enemies.map((e, idx) => ({
        ...e,
        instanceId: `enemy_${idx}`,
        gauge: 0,
        lastDamaged: false,
        hasUsedRevival: false
    })));

    const [logs, setLogs] = useState<CombatLogEntry[]>([]);
    const [damagePopups, setDamagePopups] = useState<DamagePopup[]>([]);

    // --- PERSISTENCE: 설정 데이터 유지 ---
    const [isAuto, setIsAuto] = useState(() => {
        const saved = localStorage.getItem('dungeon_combat_auto');
        return saved === null ? true : saved === 'true';
    });

    const [battleSpeed, setBattleSpeed] = useState<1 | 2 | 4>(() => {
        const saved = localStorage.getItem('dungeon_combat_speed');
        const parsed = saved ? parseInt(saved) : 1; 
        if (parsed === 1 || parsed === 2 || parsed === 4) return parsed as 1 | 2 | 4;
        return 1;
    });

    useEffect(() => {
        localStorage.setItem('dungeon_combat_auto', isAuto.toString());
    }, [isAuto]);

    useEffect(() => {
        localStorage.setItem('dungeon_combat_speed', battleSpeed.toString());
    }, [battleSpeed]);

    const [isPaused, setIsPaused] = useState(false);
    const [activeActorId, setActiveActorId] = useState<string | null>(null); 
    const [attackingUnitId, setAttackingUnitId] = useState<string | null>(null);
    const [showLogs, setShowLogs] = useState(false);
    const [showSkillList, setShowSkillList] = useState(false);

    const [pendingAction, setPendingAction] = useState<{ type: 'ATTACK' | 'SKILL', skillId?: string } | null>(null);
    const [inspectedMercId, setInspectedMercId] = useState<string | null>(null);

    const battleInterval = useRef<ReturnType<typeof setInterval> | null>(null);
    const speedRef = useRef(1);

    useEffect(() => {
        speedRef.current = battleSpeed;
    }, [battleSpeed]);

    useEffect(() => {
        const handleResize = () => {
            setOrientation(window.innerWidth > window.innerHeight ? 'LANDSCAPE' : 'PORTRAIT');
        };
        window.addEventListener('resize', handleResize);
        return () => window.removeEventListener('resize', handleResize);
    }, []);

    const addLog = useCallback((msg: string, team: 'PLAYER' | 'ENEMY' | 'SYSTEM', isCrit = false, isSkill = false) => {
        setLogs(prev => [{ msg, team, isCrit, isSkill }, ...prev].slice(0, 50));
    }, []);

    const triggerDamagePopup = useCallback((targetId: string, value: number, isCrit: boolean, isSkill: boolean) => {
        const id = Date.now() + Math.random();
        setDamagePopups(prev => [...prev, { id, value, targetId, isCrit, isSkill }]);
        setTimeout(() => {
            setDamagePopups(prev => prev.filter(p => p.id !== id));
        }, 800 / speedRef.current);
    }, []);

    const executeAttack = useCallback((attacker: any, target: any, isPlayerAttacker: boolean, skillId?: string) => {
        setAttackingUnitId(isPlayerAttacker ? attacker.id : target.instanceId);

        setTimeout(() => {
            const skill = skillId ? SKILLS[skillId] : null;
            const multiplier = skill ? skill.multiplier : 1.0;
            const mpCost = skill?.mpCost ?? 0;

            const res = calculateCombatResult(
                isPlayerAttacker ? attacker.derived : attacker.stats,
                isPlayerAttacker ? target.stats : target.derived,
                isPlayerAttacker ? attacker.job : 'Fighter' as any,
                isPlayerAttacker ? (attacker.derived.magicalAttack > attacker.derived.physicalAttack ? 'MAGICAL' : 'PHYSICAL') : 'PHYSICAL',
                multiplier
            );

            // 명중/회피 시 효과음 출력
            if (res.isHit) {
                window.dispatchEvent(new CustomEvent('play-sfx', { detail: { file: 'battle_slash.mp3' } }));
            } else {
                window.dispatchEvent(new CustomEvent('play-sfx', { detail: { file: 'swing_miss.mp3' } }));
            }

            if (isPlayerAttacker) {
                setEnemySquadState(prev => prev.map(e => {
                    if (e.instanceId === target.instanceId) {
                        const next = { ...e, lastDamaged: res.isHit };
                        if (res.isHit) {
                            let nextHp = Math.max(0, next.currentHp - res.damage);
                            if (nextHp <= 0 && next.id === 'phoenix' && !next.hasUsedRevival) {
                                nextHp = next.stats.maxHp;
                                next.hasUsedRevival = true;
                                addLog("Phoenix rebirth triggered!", 'ENEMY', true, true);
                                triggerDamagePopup(target.instanceId, 0, true, true);
                            } else {
                                next.currentHp = nextHp;
                            }
                            triggerDamagePopup(target.instanceId, res.damage, res.isCrit, !!skill);
                        }
                        setTimeout(() => setEnemySquadState(curr => curr.map(currE => currE.instanceId === target.instanceId ? { ...currE, lastDamaged: false } : currE)), 200 / speedRef.current);
                        return next;
                    }
                    return e;
                }));

                if (skill) {
                    setPartyState(prev => prev.map(p => p.id === attacker.id ? { ...p, currentMp: Math.max(0, p.currentMp - mpCost) } : p));
                    addLog(`${attacker.name} used ${skill.name}!`, 'PLAYER', res.isCrit, true);
                } else {
                    addLog(`${attacker.name} hits ${target.name} for ${res.damage}`, 'PLAYER', res.isCrit);
                }
            } else {
                setPartyState(prev => prev.map(p => {
                    if (p.id === target.id) {
                        const next = { ...p, lastDamaged: res.isHit };
                        if (res.isHit) {
                            next.currentHp = Math.max(0, next.currentHp - res.damage);
                            triggerDamagePopup(p.id, res.damage, res.isCrit, false);
                        }
                        setTimeout(() => setPartyState(curr => curr.map(c => c.id === p.id ? { ...c, lastDamaged: false } : c)), 200 / speedRef.current);
                        return next;
                    }
                    return p;
                }));
                addLog(`${attacker.name} strikes ${target.name} for ${res.damage}`, 'ENEMY');
            }

            setTimeout(() => setAttackingUnitId(null), 150 / speedRef.current);
        }, 200 / speedRef.current);
    }, [addLog, triggerDamagePopup]);

    const processLoop = useCallback(() => {
        if (isPaused || activeActorId || attackingUnitId || inspectedMercId) return;

        const enemiesDefeated = enemySquadState.every(e => e.currentHp <= 0);
        const partyDefeated = partyState.every(p => p.currentHp <= 0);

        if (enemiesDefeated) {
            setIsPaused(true);
            setTimeout(() => onFinish(true, partyState), 800 / speedRef.current);
            return;
        }
        if (partyDefeated) {
            setIsPaused(true);
            setTimeout(() => onFinish(false, partyState), 800 / speedRef.current);
            return;
        }

        // --- SPEED BALANCING: 기초 게이지 충전량 0.2로 고정 ---
        setPartyState(prev => {
            const next = [...prev];
            let readyMerc = null;
            for (let p of next) {
                if (p.currentHp > 0) {
                    p.gauge += (p.derived.speed * 0.2 * speedRef.current); 
                    if (p.gauge >= ACTION_THRESHOLD && !readyMerc) readyMerc = p;
                }
            }
            if (readyMerc && !attackingUnitId) {
                const livingEnemies = enemySquadState.filter(e => e.currentHp > 0);
                if (livingEnemies.length > 0) {
                    if (isAuto) {
                        readyMerc.gauge -= ACTION_THRESHOLD;
                        const target = livingEnemies[Math.floor(Math.random() * livingEnemies.length)];
                        let sid = undefined;

                        // 자동 전투 시 스킬 사용 우선순위 로직
                        const availableSkillIds = [
                            ...(readyMerc.skillIds || []),
                            ...Object.values(readyMerc.equipment || {}).map(i => (i as any)?.socketedSkillId).filter(Boolean) as string[]
                        ];

                        if (availableSkillIds.length > 0) {
                            const skill = SKILLS[availableSkillIds[0]];
                            if (skill && readyMerc.currentMp >= (skill.mpCost ?? 0) && Math.random() < 0.3) sid = skill.id;
                        }
                        executeAttack(readyMerc, target, true, sid);
                    } else {
                        setActiveActorId(readyMerc.id);
                        setShowSkillList(false);
                        setPendingAction(null);
                    }
                }
            }
            return next;
        });

        setEnemySquadState(prev => {
            const next = [...prev];
            let readyEnemy = null;
            for (let e of next) {
                if (e.currentHp > 0) {
                    e.gauge += (e.stats.speed * 0.2 * speedRef.current); 
                    if (e.gauge >= ACTION_THRESHOLD && !readyEnemy) readyEnemy = e;
                }
            }
            if (readyEnemy && !activeActorId && !attackingUnitId) {
                readyEnemy.gauge -= ACTION_THRESHOLD;
                const livingPlayers = partyState.filter(p => p.currentHp > 0);
                if (livingPlayers.length > 0) {
                    const target = livingPlayers[Math.floor(Math.random() * livingPlayers.length)];
                    executeAttack(readyEnemy, target, false);
                }
            }
            return next;
        });
    }, [isPaused, isAuto, activeActorId, attackingUnitId, inspectedMercId, enemySquadState, partyState, executeAttack, onFinish]);

    useEffect(() => {
        battleInterval.current = setInterval(processLoop, 100);
        return () => { if (battleInterval.current) clearInterval(battleInterval.current); };
    }, [processLoop]);

    const handleTurnConsumed = useCallback((targetMercId: string) => {
        setTimeout(() => {
            const updatedMercFromContext = state.knownMercenaries.find(m => m.id === targetMercId);
            if (updatedMercFromContext) {
                setPartyState(prev => prev.map(p => {
                    if (p.id === targetMercId) {
                        const primary = mergePrimaryStats(updatedMercFromContext.stats, updatedMercFromContext.allocatedStats);
                        const derived = applyEquipmentBonuses(
                            calculateDerivedStats(primary, updatedMercFromContext.level), 
                            (Object.values(updatedMercFromContext.equipment) as any[]).map(e=>e?.stats).filter(Boolean) as any
                        );
                        return { 
                            ...p, 
                            ...updatedMercFromContext, 
                            derived,
                            currentHp: updatedMercFromContext.currentHp,
                            currentMp: updatedMercFromContext.currentMp,
                            gauge: Math.max(0, p.gauge - ACTION_THRESHOLD)
                        };
                    }
                    return p;
                }));
                setInspectedMercId(null);
                setActiveActorId(null);
            }
        }, 50);
    }, [state.knownMercenaries]);

    const handleManualAction = (e: React.MouseEvent, type: 'ATTACK' | 'SKILL', skillId?: string) => {
        e.stopPropagation(); 
        if (!activeActorId) return;

        if (type === 'SKILL' && !skillId) {
            setShowSkillList(true);
            return;
        }

        if (type === 'SKILL' && skillId) {
            const skill = SKILLS[skillId];
            const actor = partyState.find(p => p.id === activeActorId);
            if (!actor || actor.currentMp < (skill?.mpCost ?? 0)) {
                actions.showToast("Not enough MP!");
                return;
            }
            setShowSkillList(false);
        }

        setPendingAction({ type, skillId });
    };

    const handleEnemyClick = (target: any) => {
        if (!activeActorId || !pendingAction) return;
        if (target.currentHp <= 0) return;
        const actor = partyState.find(p => p.id === activeActorId);
        if (!actor) return;
        setPartyState(prev => prev.map(p => p.id === activeActorId ? { ...p, gauge: p.gauge - ACTION_THRESHOLD } : p));
        executeAttack(actor, target, true, pendingAction.skillId);
        setPendingAction(null);
        setActiveActorId(null);
    };

    const handleFlee = (e: React.MouseEvent) => {
        e.stopPropagation();
        if (Math.random() * 100 < fleeChance) {
            onFlee(partyState);
        } else {
            addLog("Escape failed!", 'SYSTEM');
            setActiveActorId(null);
            setPendingAction(null);
            setPartyState(prev => prev.map(p => p.id === activeActorId ? { ...p, gauge: 0 } : p));
        }
    };

    const getUnitStyle = (id: string, side: 'PLAYER' | 'ENEMY'): React.CSSProperties => {
        if (attackingUnitId !== id) return {};
        let transform = orientation === 'PORTRAIT' 
            ? (side === 'PLAYER' ? 'translateY(-120px) scale(1.1)' : 'translateY(120px) scale(1.1)')
            : (side === 'PLAYER' ? 'translateX(120px) scale(1.1)' : 'translateX(-120px) scale(1.1)');
        return { transform, zIndex: 100 };
    };

    const activeActor = useMemo(() => partyState.find(p => p.id === activeActorId), [partyState, activeActorId]);
    const activeActorSkills = useMemo(() => {
        if (!activeActor) return [];
        const learned = (activeActor.skillIds || []).map(id => ({ id, source: 'LEARNED' }));
        const fromGear = Object.values(activeActor.equipment || {}).map(i => (i as any)?.socketedSkillId).filter(Boolean).map(id => ({ id, source: 'GEAR' }));
        return [...learned, ...fromGear as any];
    }, [activeActor]);

    return (
        <div className="fixed inset-0 z-[150] flex flex-col bg-stone-950 animate-in fade-in duration-500 overflow-hidden font-sans pb-safe">
            <style>{`
                @keyframes damage-float { 0% { transform: translateY(0); opacity: 1; } 100% { transform: translateY(-60px); opacity: 0; } }
                .animate-damage { animation: damage-float 1s ease-out forwards; }
                @keyframes unit-shake { 0%, 100% { transform: translate(0,0); } 25% { transform: translate(-4px, 2px); } 50% { transform: translate(4px, -2px); } 75% { transform: translate(-2px, -4px); } }
                .animate-hit { animation: unit-shake 0.2s ease-in-out 3; }
                @keyframes target-pulse { 0% { transform: scale(1); box-shadow: 0 0 0 0 rgba(239, 68, 68, 0.7); } 70% { transform: scale(1.05); box-shadow: 0 0 0 10px rgba(239, 68, 68, 0); } 100% { transform: scale(1); } }
                .animate-target { animation: target-pulse 1.5s infinite; }
            `}</style>

            {/* Background Tile Layer */}
            {dungeonInfo?.tile && (
                <div className="absolute inset-0 z-0 overflow-hidden pointer-events-none">
                    <img 
                        src={getAssetUrl(dungeonInfo.tile, 'dungeons')} 
                        className="w-full h-full object-cover opacity-60 brightness-[0.6]" 
                        alt="Combat Background" 
                    />
                </div>
            )}

            {/* Top Bar */}
            <div className="p-3 bg-red-950/20 border-b border-red-900/30 flex justify-between items-center z-[200] backdrop-blur-sm">
                <div className="flex items-center gap-2">
                    <Skull className="w-4 h-4 text-red-50" />
                    <h2 className="text-white font-black uppercase text-[10px] md:text-sm tracking-widest font-mono">Combat Zone</h2>
                </div>
                <div className="flex items-center gap-3 bg-black/40 px-3 py-1 rounded-full border border-white/5">
                    <SfxButton sfx="switch" onClick={() => setIsPaused(!isPaused)} className={`p-1.5 rounded-full transition-all ${isPaused ? 'bg-amber-600 text-white' : 'bg-stone-800 text-stone-400'}`}>
                        {isPaused ? <Play size={14} /> : <Pause size={14} />}
                    </SfxButton>
                    <div className="flex items-center gap-1">
                        {[1, 2, 4].map(s => (
                            <SfxButton sfx="switch" key={s} onClick={() => setBattleSpeed(s as any)} className={`px-2 py-0.5 rounded font-mono text-[8px] md:text-[10px] font-black ${battleSpeed === s ? 'bg-indigo-600 text-white' : 'text-stone-600'}`}>{s}x</SfxButton>
                        ))}
                    </div>
                </div>
                <SfxButton sfx="switch" onClick={() => { setIsAuto(!isAuto); setPendingAction(null); setShowSkillList(false); }} className={`px-4 py-1.5 rounded-lg border font-black text-[9px] tracking-widest transition-all ${isAuto ? 'bg-amber-600 border-amber-400 text-white' : 'bg-stone-800 border-stone-600 text-stone-400'}`}>
                    {isAuto ? 'AUTO' : 'MANUAL'}
                </SfxButton>
            </div>

            {/* Combat Field */}
            <div className={`flex-1 flex relative transition-all duration-700 z-10 ${orientation === 'PORTRAIT' ? 'flex-col' : 'flex-row'}`}>
                {/* Enemies Area */}
                <div className={`flex flex-1 items-center justify-center p-4 gap-6 md:gap-12 ${orientation === 'PORTRAIT' ? 'order-1' : 'order-2'}`}>
                    {enemySquadState.map(e => (
                        <div key={e.instanceId} style={getUnitStyle(e.instanceId, 'ENEMY')} onClick={() => pendingAction && e.currentHp > 0 && handleEnemyClick(e)} className={`relative flex flex-col items-center transition-all ${e.currentHp <= 0 ? 'opacity-20 grayscale' : e.lastDamaged ? 'animate-hit' : ''}`}>
                            <div className={`w-24 h-24 md:w-48 md:h-48 bg-stone-900 rounded-2xl border-2 flex items-center justify-center relative shadow-2xl ${e.lastDamaged ? 'border-red-500 bg-red-950/20' : 'border-stone-800'} ${pendingAction && e.currentHp > 0 ? 'animate-target border-red-500 cursor-crosshair' : ''}`}>
                                <img src={getAssetUrl(e.sprite || '', 'monsters')} className="w-[80%] h-[80%] object-contain" alt={e.name} />
                                {pendingAction && e.currentHp > 0 && <div className="absolute inset-0 flex items-center justify-center"><Target className="w-12 h-12 text-red-500 opacity-50" /></div>}
                                <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
                                    {damagePopups.filter(p => p.targetId === e.instanceId).map(p => (
                                        <div key={p.id} className={`absolute font-black text-3xl md:text-5xl animate-damage ${p.isCrit ? 'text-amber-400 scale-125' : 'text-red-500'}`}>-{p.value}</div>
                                    ))}
                                </div>
                            </div>
                            {e.currentHp > 0 && (
                                <div className="mt-2 w-24 md:w-52 space-y-1">
                                    <div className="flex flex-col items-center leading-none mb-1">
                                        <span className="text-[9px] md:text-xs font-black text-stone-300 uppercase tracking-tighter truncate w-full text-center">{e.name}</span>
                                        <span className="text-[7px] md:text-[9px] font-bold text-stone-500 uppercase tracking-widest">Lv.{e.level}</span>
                                    </div>
                                    <div className="relative h-2.5 bg-black rounded-full overflow-hidden border border-white/5">
                                        <div className="h-full bg-red-600 transition-all duration-500" style={{ width: `${(e.currentHp/e.stats.maxHp)*100}%` }} />
                                        <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
                                            <span className="text-[7px] md:text-[10px] font-mono font-black text-white drop-shadow-sm">{Math.floor(e.currentHp)} / {e.stats.maxHp}</span>
                                        </div>
                                    </div>
                                    <div className="h-1 bg-black rounded-full overflow-hidden">
                                        <div className="h-full bg-amber-500 transition-all" style={{ width: `${(e.gauge/ACTION_THRESHOLD)*100}%` }} />
                                    </div>
                                </div>
                            )}
                        </div>
                    ))}
                </div>

                {/* Players Area */}
                <div className={`flex flex-1 items-center justify-center p-4 gap-6 md:gap-12 ${orientation === 'PORTRAIT' ? 'order-3 pt-0' : 'order-1'}`}>
                    {partyState.map(p => {
                        const isActive = activeActorId === p.id;
                        const hpPer = (p.currentHp / p.derived.maxHp) * 100;
                        const mpPer = (p.currentMp / (p.derived.maxMp || 1)) * 100;

                        return (
                            <div key={p.id} style={getUnitStyle(p.id, 'PLAYER')} className={`relative flex flex-col items-center transition-all ${p.currentHp <= 0 ? 'opacity-20 grayscale' : isActive ? '-translate-y-4' : ''} ${p.lastDamaged ? 'animate-hit' : ''}`}>
                                {/* Portrait Container */}
                                <div className={`w-24 h-24 md:w-48 md:h-48 bg-stone-900 rounded-2xl border-2 flex items-center justify-center relative shadow-2xl ${isActive ? 'border-amber-400 ring-4 ring-amber-500/20' : 'border-stone-800'}`}>
                                    <MercenaryPortrait mercenary={p} className="w-[85%] h-[85%] rounded-xl" />
                                    <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
                                        {damagePopups.filter(pop => pop.targetId === p.id).map(pop => (
                                            <div key={pop.id} className="absolute font-black text-3xl md:text-5xl animate-damage text-red-50">-{pop.value}</div>
                                        ))}
                                    </div>

                                    {/* Action indicator for targeting */}
                                    {pendingAction && isActive && (
                                        <div className="absolute -top-12 left-1/2 -translate-x-1/2 flex flex-col items-center animate-bounce">
                                            <div className="bg-amber-600 text-white px-3 py-1 rounded-full text-[10px] font-black uppercase shadow-lg border border-amber-400">
                                                {pendingAction.skillId ? SKILLS[pendingAction.skillId].name : 'Striking'}
                                            </div>
                                            <div className="w-0 h-0 border-l-[6px] border-l-transparent border-r-[6px] border-r-transparent border-t-[6px] border-t-amber-600"></div>
                                        </div>
                                    )}

                                    {isActive && !pendingAction && !isAuto && !showSkillList && (
                                        <div className="absolute -bottom-40 left-1/2 -translate-x-1/2 z-[300] bg-stone-900/95 border-2 border-amber-500 p-2.5 rounded-2xl grid grid-cols-2 gap-3 shadow-2xl animate-in slide-in-from-top-2 backdrop-blur-md w-40">
                                            <SfxButton onClick={(e) => handleManualAction(e, 'ATTACK')} className="p-3 bg-stone-800 hover:bg-stone-700 rounded-xl text-white transition-colors border border-white/5 flex flex-col items-center gap-1 group">
                                                <Sword size={20} className="group-hover:scale-110 transition-transform" />
                                                <span className="text-[8px] font-black uppercase">Atk</span>
                                            </SfxButton>
                                            <SfxButton onClick={(e) => handleManualAction(e, 'SKILL')} className="p-3 bg-indigo-900/40 hover:bg-indigo-800 rounded-xl text-indigo-100 transition-colors border border-indigo-500/30 flex flex-col items-center gap-1 group">
                                                <Wand2 size={20} className="group-hover:scale-110 transition-transform" />
                                                <span className="text-[8px] font-black uppercase">Skill</span>
                                            </SfxButton>
                                            <SfxButton sfx="switch" onClick={(e) => { e.stopPropagation(); setInspectedMercId(p.id); }} className="p-3 bg-stone-800 hover:bg-stone-750 rounded-xl text-stone-300 transition-colors border border-stone-700 flex flex-col items-center gap-1 group">
                                                <Package size={20} className="group-hover:scale-110 transition-transform" />
                                                <span className="text-[8px] font-black uppercase">Bag</span>
                                            </SfxButton>
                                            <SfxButton onClick={(e) => handleFlee(e)} className="p-3 bg-red-950/40 hover:bg-red-900 rounded-xl text-red-500 transition-colors border border-red-500/30 flex flex-col items-center gap-1 group">
                                                <LogOut size={20} className="group-hover:scale-110 transition-transform" />
                                                <span className="text-[8px] font-black uppercase">Flee</span>
                                            </SfxButton>
                                        </div>
                                    )}

                                    {/* Skill List Overlay */}
                                    {isActive && showSkillList && (
                                        <div className="absolute -bottom-52 left-1/2 -translate-x-1/2 z-[310] bg-stone-900/98 border-2 border-indigo-500 p-3 rounded-2xl shadow-2xl animate-in zoom-in-95 backdrop-blur-xl w-64 md:w-80">
                                            <div className="flex justify-between items-center mb-2 px-1">
                                                <span className="text-[10px] font-black text-indigo-400 uppercase tracking-widest">Available Skills</span>
                                                <SfxButton sfx="switch" onClick={() => setShowSkillList(false)} className="text-stone-500 hover:text-white"><X size={16} /></SfxButton>
                                            </div>
                                            <div className="space-y-1.5 max-h-48 overflow-y-auto custom-scrollbar pr-1">
                                                {activeActorSkills.map((ref, idx) => {
                                                    const skill = SKILLS[ref.id];
                                                    if (!skill) return null;
                                                    const canCast = activeActor.currentMp >= (skill.mpCost ?? 0);
                                                    return (
                                                        <button 
                                                            key={`${ref.id}-${idx}`}
                                                            disabled={!canCast}
                                                            onClick={(e) => handleManualAction(e, 'SKILL', ref.id)}
                                                            className={`w-full flex items-center justify-between p-2 rounded-xl border transition-all text-left group ${canCast ? 'bg-indigo-900/20 border-indigo-500/30 hover:bg-indigo-800/40 hover:border-indigo-400' : 'bg-stone-900 border-stone-800 opacity-50 grayscale cursor-not-allowed'}`}
                                                        >
                                                            <div className="flex items-center gap-2 min-w-0">
                                                                <div className={`p-1.5 rounded-lg border ${ref.source === 'GEAR' ? 'bg-purple-900/30 border-purple-500/50 text-purple-400' : 'bg-indigo-900/40 border-indigo-500/50 text-indigo-300'}`}>
                                                                    <Zap size={14} />
                                                                </div>
                                                                <div className="min-w-0 flex flex-col leading-tight">
                                                                    <span className="text-[10px] font-black text-stone-100 uppercase truncate">{skill.name}</span>
                                                                    <span className="text-[7px] text-stone-500 italic truncate">{skill.description}</span>
                                                                </div>
                                                            </div>
                                                            <div className="flex items-center gap-1.5 shrink-0 pl-2">
                                                                <span className="text-[9px] font-mono font-black text-blue-400">{skill.mpCost} MP</span>
                                                                <ChevronRight size={14} className="text-stone-700 group-hover:text-white transition-colors" />
                                                            </div>
                                                        </button>
                                                    );
                                                })}
                                                {activeActorSkills.length === 0 && (
                                                    <div className="py-8 text-center text-stone-600 text-[10px] font-black uppercase tracking-widest opacity-40 italic">No usable skills</div>
                                                )}
                                            </div>
                                            {pendingAction && (
                                                <div className="mt-3 pt-3 border-t border-indigo-500/30">
                                                    <SfxButton onClick={() => setPendingAction(null)} className="w-full py-2 bg-stone-800 hover:bg-stone-700 text-stone-400 text-[10px] font-black uppercase rounded-lg">Cancel Selection</SfxButton>
                                                </div>
                                            )}
                                        </div>
                                    )}
                                </div>

                                {p.currentHp > 0 && (
                                    <div className="mt-2 w-24 md:w-52 space-y-1">
                                        {/* Full Name, Job, Level */}
                                        <div className="flex flex-col items-center leading-none mb-1">
                                            <span className="text-[9px] md:text-xs font-black text-stone-100 uppercase tracking-tighter truncate w-full text-center">{p.name}</span>
                                            <span className="text-[7px] md:text-[10px] font-bold text-stone-500 uppercase tracking-widest mt-0.5">{p.job} • Lv.{p.level}</span>
                                        </div>

                                        {/* HP Bar & Value */}
                                        <div className="relative h-3 bg-black rounded-full overflow-hidden border border-white/5 shadow-inner">
                                            <div className={`h-full transition-all duration-500 ${hpPer < 30 ? 'bg-red-500 animate-pulse' : 'bg-red-600'}`} style={{ width: `${hpPer}%` }} />
                                            <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
                                                <span className="text-[7px] md:text-[11px] font-mono font-black text-white drop-shadow-sm">{Math.floor(p.currentHp)} / {p.derived.maxHp}</span>
                                            </div>
                                        </div>

                                        {/* MP Bar & Value */}
                                        <div className="relative h-2.5 bg-black rounded-full overflow-hidden border border-white/5 shadow-inner">
                                            <div className="h-full bg-blue-600 transition-all duration-500" style={{ width: `${mpPer}%` }} />
                                            <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
                                                <span className="text-[6px] md:text-[9px] font-mono font-black text-blue-100 drop-shadow-sm">{Math.floor(p.currentMp)} / {p.derived.maxMp}</span>
                                            </div>
                                        </div>

                                        {/* ATB Gauge */}
                                        <div className="h-1 bg-black rounded-full overflow-hidden">
                                            <div className="h-full bg-amber-500 transition-all" style={{ width: `${(p.gauge/ACTION_THRESHOLD)*100}%` }} />
                                        </div>
                                    </div>
                                )}
                            </div>
                        );
                    })}
                </div>
            </div>

            {/* Tactical Feed */}
            <div className={`bg-stone-900 border-t border-stone-800 flex flex-col shrink-0 transition-all z-10 ${showLogs ? 'h-48' : 'h-18'}`}>
                <button onClick={() => setShowLogs(!showLogs)} className="w-full h-10 flex items-center justify-between px-4 bg-black/20 hover:bg-black/40 transition-colors shrink-0">
                    <div className="flex items-center gap-2">
                        <Activity className={`w-3.5 h-3.5 ${isPaused ? 'text-stone-600' : 'text-amber-500 animate-pulse'}`} />
                        <span className="text-[9px] font-black text-stone-500 uppercase tracking-widest">Engagement Feed</span>
                    </div>
                    {showLogs ? <ChevronDown size={14} /> : <ChevronUp size={14} />}
                </button>
                <div className={`flex-1 ${showLogs ? 'overflow-y-auto' : 'overflow-hidden'} p-2 space-y-1 font-mono text-[9px] custom-scrollbar`}>
                    {(showLogs ? logs : logs.slice(0, 1)).map((log, i) => (
                        <div key={i} className={`p-1.5 border-l-2 ${log.team === 'PLAYER' ? 'border-blue-500 text-blue-100' : log.team === 'ENEMY' ? 'border-red-500 text-red-100' : 'border-stone-700 text-stone-400'} ${log.isCrit ? 'bg-white/5 font-black' : ''}`}>
                            <span className="opacity-30 mr-2">[{new Date().toLocaleTimeString([], { hour12: false, minute: '2-digit', second: '2-digit' })}]</span>
                            {log.msg}
                        </div>
                    ))}
                </div>
            </div>

            {/* Modals */}
            {inspectedMercId && (
                <MercenaryDetailModal 
                    mercenary={partyState.find(p => p.id === inspectedMercId) || null}
                    onClose={() => setInspectedMercId(null)}
                    onEquip={(mercId, itemId) => { actions.equipItem(mercId, itemId); handleTurnConsumed(mercId); }}
                    onConsume={(mercId, itemId) => { actions.useItem(itemId, mercId); handleTurnConsumed(mercId); }}
                    onUnequip={(mercId, slot) => { actions.unequipItem(mercId, slot); handleTurnConsumed(mercId); }}
                    isReadOnly={false} 
                />
            )}
        </div>
    );
};

export default DungeonCombatView;

import React, { useMemo } from 'react';
import { 
  Sword, Shield, Activity, Star, Zap, Brain, Target, Wind, 
  Plus, Minus, RotateCcw, Save, Heart, Sparkles, Wrench
} from 'lucide-react';
import { Mercenary } from '../../models/Mercenary';
import { DerivedStats, PrimaryStats } from '../../models/Stats';
import { SKILLS } from '../../data/skills';
import { StatDiff } from './StatDiff';
import { SfxButton } from '../common/ui/SfxButton';

interface MercenaryStatsPanelProps {
  mercenary: Mercenary;
  baseStats: DerivedStats;
  finalStats: DerivedStats;
  pendingAllocated: PrimaryStats;
  pendingPoints: number;
  equipmentStats: PrimaryStats;
  previewEquipmentStats: PrimaryStats | null;
  onModifyStat: (key: keyof PrimaryStats, delta: number) => void;
  onSave: () => void;
  onReset: () => void;
  isReadOnly?: boolean;
}

export const MercenaryStatsPanel: React.FC<MercenaryStatsPanelProps> = ({
  mercenary,
  baseStats,
  finalStats,
  pendingAllocated,
  pendingPoints,
  equipmentStats,
  previewEquipmentStats,
  onModifyStat,
  onSave,
  onReset,
  isReadOnly,
}) => {
  const xpPercent =
    mercenary.xpToNextLevel > 0
      ? Math.min(100, Math.max(0, (mercenary.currentXp / mercenary.xpToNextLevel) * 100))
      : 0;
  const hpPercent = finalStats.maxHp > 0 ? (mercenary.currentHp / finalStats.maxHp) * 100 : 0;
  const mpPercent = finalStats.maxMp > 0 ? (mercenary.currentMp / finalStats.maxMp) * 100 : 0;
  const staminaPercent = Math.min(100, Math.max(0, (mercenary.expeditionEnergy || 0)));

  const isModified = useMemo(() => {
    return (Object.keys(pendingAllocated) as Array<keyof PrimaryStats>).some(
        key => pendingAllocated[key] !== mercenary.allocatedStats[key]
    );
  }, [pendingAllocated, mercenary.allocatedStats]);

  // Combine learned skills and equipment-socketed skills
  const allAvailableSkills = useMemo(() => {
      const learnedSkills = (mercenary.skillIds || []).map(id => ({ id, source: 'LEARNED' as const }));

      const fromGear: { id: string, source: 'GEAR' as const }[] = [];
      (Object.values(mercenary.equipment) as (any | null)[]).forEach(item => {
          if (item?.socketedSkillId) {
              fromGear.push({ id: item.socketedSkillId, source: 'GEAR' as const });
          }
      });

      return [...learnedSkills, ...fromGear];
  }, [mercenary.skillIds, mercenary.equipment]);

  const renderStatRow = (icon: React.ReactNode, label: string, baseValue: number, nextValue: number, isPercent = false) => {
    return (
      <div className="bg-stone-950/40 p-1.5 md:p-3 rounded-lg border border-white/5 flex justify-between items-center h-8 md:h-12">
        <span className="text-[7px] md:text-xs text-stone-500 font-black uppercase flex items-center gap-1.5 md:gap-2">
          {icon}
          <span className="hidden md:inline">{label}</span>
          <span className="md:hidden truncate max-w-[40px]">
            {label === 'Physical Atk' ? 'P.Atk' : label === 'Physical Def' ? 'P.Def' : label === 'Magical Atk' ? 'M.Atk' : label === 'Magical Def' ? 'M.Def' : label === 'Crit Rate' ? 'Crit' : label === 'Evasion' ? 'Eva' : label}
          </span>
        </span>
        <div className="flex items-center gap-1 md:gap-2">
          <span className={`font-mono text-[9px] md:text-base font-black ${nextValue > baseValue ? 'text-emerald-400' : nextValue < baseValue ? 'text-red-400' : 'text-stone-300'}`}>
            {isPercent ? nextValue.toFixed(1) : Math.round(nextValue)}
            {isPercent ? '%' : ''}
          </span>
          <StatDiff current={baseValue} next={nextValue} isPercent={isPercent} />
        </div>
      </div>
    );
  };

  return (
    <div className="p-3 md:p-6 flex flex-col gap-4 md:gap-6 bg-stone-900/10 border-t border-white/5">
