                  </div>
                </div>
              );
            })}
          </div>
        ) : (
          <div className="py-4 md:py-6 text-center border-2 border-dashed border-stone-800 rounded-xl text-stone-600 text-[8px] md:text-[10px] font-bold uppercase tracking-widest">
            No available skills
