                                                    <SfxButton onClick={() => setPendingAction(null)} className="w-full py-2 bg-stone-800 hover:bg-stone-700 text-stone-400 text-[10px] font-black uppercase rounded-lg">Cancel Selection</SfxButton>
                                                </div>
                                            )}
                                        </div>
                                    )}
                                </div>

                                {p.currentHp > 0 && (
                                    <div className="mt-2 w-24 md:w-52 space-y-1">
                                        <div className="flex flex-col items-center leading-none mb-1">
                                            <span className="text-[9px] md:text-xs font-black text-stone-100 uppercase tracking-tighter truncate w-full text-center">{p.name}</span>
                                            <span className="text-[7px] md:text-[10px] font-bold text-stone-500 uppercase tracking-widest mt-0.5">{p.job} • Lv.{p.level}</span>
                                        </div>
                                        <div className="relative h-3 bg-black rounded-full overflow-hidden border border-white/5 shadow-inner">
                                            <div className={`h-full transition-all duration-500 ${hpPer < 30 ? 'bg-red-500 animate-pulse' : 'bg-red-600'}`} style={{ width: `${hpPer}%` }} />
                                            <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
                                                <span className="text-[7px] md:text-[11px] font-mono font-black text-white drop-shadow-sm">{Math.floor(p.currentHp)} / {p.derived.maxHp}</span>
                                            </div>
                                        </div>
                                        <div className="relative h-2.5 bg-black rounded-full overflow-hidden border border-white/5 shadow-inner">
                                            <div className="h-full bg-blue-600 transition-all duration-500" style={{ width: `${mpPer}%` }} />
                                            <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
                                                <span className="text-[6px] md:text-[9px] font-mono font-black text-blue-100 drop-shadow-sm">{Math.floor(p.currentMp)} / {p.derived.maxMp}</span>
                                            </div>
                                        </div>
                                        <div className="h-1 bg-black rounded-full overflow-hidden">
                                            <div className="h-full bg-amber-500 transition-all" style={{ width: `${(p.gauge/ACTION_THRESHOLD)*100}%` }} />
                                        </div>
                                    </div>
                                )}
                            </div>
                        );
                    })}
                </div>
            </div>

            {/* Tactical Feed */}
            <div className={`bg-stone-900 border-t border-stone-800 flex flex-col shrink-0 transition-all z-10 ${showLogs ? 'h-48' : 'h-18'}`}>
                <button onClick={() => setShowLogs(!showLogs)} className="w-full h-10 flex items-center justify-between px-4 bg-black/20 hover:bg-black/40 transition-colors shrink-0">
                    <div className="flex items-center gap-2">
                        <Activity className={`w-3.5 h-3.5 ${isPaused ? 'text-stone-600' : 'text-amber-500 animate-pulse'}`} />
                        <span className="text-[9px] font-black text-stone-500 uppercase tracking-widest">Engagement Feed</span>
                    </div>
                    {showLogs ? <ChevronDown size={14} /> : <ChevronUp size={14} />}
                </button>
                <div className={`flex-1 ${showLogs ? 'overflow-y-auto' : 'overflow-hidden'} p-2 space-y-1 font-mono text-[9px] custom-scrollbar`}>
                    {(showLogs ? logs : logs.slice(0, 1)).map((log, i) => (
                        <div key={i} className={`p-1.5 border-l-2 ${log.team === 'PLAYER' ? (log.isHeal ? 'border-emerald-500 text-emerald-100' : 'border-blue-500 text-blue-100') : log.team === 'ENEMY' ? 'border-red-500 text-red-100' : 'border-stone-700 text-stone-400'} ${log.isCrit ? 'bg-white/5 font-black' : ''}`}>
                            <span className="opacity-30 mr-2">[{new Date().toLocaleTimeString([], { hour12: false, minute: '2-digit', second: '2-digit' })}]</span>
                            {log.msg}
                        </div>
                    ))}
                </div>
            </div>

            {/* Modals */}
            {inspectedMercId && (
                <MercenaryDetailModal 
                    mercenary={partyState.find(p => p.id === inspectedMercId) || null}
                    onClose={() => setInspectedMercId(null)}
                    onEquip={(mercId, itemId) => { actions.equipItem(mercId, itemId); handleTurnConsumed(mercId); }}
                    onConsume={(mercId, itemId) => { actions.useItem(itemId, mercId); handleTurnConsumed(mercId); }}
                    onUnequip={(mercId, slot) => { actions.unequipItem(mercId, slot); handleTurnConsumed(mercId); }}
                    isReadOnly={false} 
                />
            )}
        </div>
    );
};

export default DungeonCombatView;

import React, { useState, useMemo, useEffect } from 'react';
import { useGame } from '../context/GameContext';
import { 
    Package, Sword, Shield, Coins, Info, Zap, Wrench, ShieldAlert, AlertCircle, 
    Brain, Lock, Unlock, Star, Sparkles, X, Minus, Plus, ChevronRight, Wand2
} from 'lucide-react';
import { InventoryItem } from '../types/index';
import { getAssetUrl } from '../utils';
import ConfirmationModal from './modals/ConfirmationModal';
import { SKILLS } from '../data/skills';

const RomanTierOverlay = ({ id }: { id: string }) => {
    if (id === 'scroll_t2') return <div className="absolute inset-0 flex items-center justify-center pointer-events-none"><span className="text-amber-500 font-serif font-black text-xs md:text-xl drop-shadow-[0_2px_2px_rgba(0,0,0,0.8)] translate-y-1">II</span></div>;
    if (id === 'scroll_t3') return <div className="absolute inset-0 flex items-center justify-center pointer-events-none"><span className="text-amber-500 font-serif font-black text-xs md:text-xl drop-shadow-[0_2px_2px_rgba(0,0,0,0.8)] translate-y-1">III</span></div>;
    if (id === 'scroll_t4') return <div className="absolute inset-0 flex items-center justify-center pointer-events-none"><span className="text-amber-500 font-serif font-black text-xs md:text-xl drop-shadow-[0_2px_2px_rgba(0,0,0,0.8)] translate-y-1">IV</span></div>;
    return null;
};

const AdaptiveInventoryImage = ({ item, className }: { item: InventoryItem, className?: string }) => {
    const isEquip = item.type === 'EQUIPMENT';
    const isSkill = item.type === 'SKILL_BOOK' || item.type === 'SKILL_SCROLL';
    const folder = isSkill ? 'skills' : (isEquip ? 'equipments' : 'materials');

    const baseId = (isEquip && item.equipmentData?.recipeId) 
        ? item.equipmentData.recipeId 
        : item.id;

    const [imgSrc, setImgSrc] = useState(getAssetUrl(`${baseId}.png`, folder));

    useEffect(() => {
        const targetFolder = (item.type === 'SKILL_BOOK' || item.type === 'SKILL_SCROLL') ? 'skills' : (item.type === 'EQUIPMENT' ? 'equipments' : 'materials');
        const targetFile = item.image || (isEquip && item.equipmentData?.recipeId ? `${item.equipmentData.recipeId}.png` : `${item.id}.png`);
        setImgSrc(getAssetUrl(targetFile, targetFolder));
    }, [item.id, item.image, item.type, isEquip, item.equipmentData?.recipeId]);

    const handleImgError = () => {
        const fallbackPath = item.image || item.equipmentData?.image;
        if (fallbackPath && imgSrc !== getAssetUrl(fallbackPath, folder)) {
            setImgSrc(getAssetUrl(fallbackPath, folder));
        }
    };

    return <img src={imgSrc} onError={handleImgError} className={className} alt={item.name} />;
};

export const InventoryDisplay = () => {
    const { state, actions } = useGame();
    const [selectedItemId, setSelectedItemId] = useState<string | null>(null);
    const [isSellModalOpen, setIsSellModalOpen] = useState(false);
    const [sellQuantity, setSellQuantity] = useState(1);

    // 인챈트(스크롤 부여) 관련 상태
    const [enchantingScroll, setEnchantingScroll] = useState<InventoryItem | null>(null);
    const [confirmEnchantTarget, setConfirmEnchantTarget] = useState<InventoryItem | null>(null);

    const currentSelectedItem = useMemo(() => 
        state.inventory.find(i => i.id === selectedItemId) || null
    , [state.inventory, selectedItemId]);

    const handleSelect = (item: InventoryItem) => {
        if (enchantingScroll) {
            if (item.type === 'EQUIPMENT') {
                if (item.isLocked) {
                    actions.showToast("Cannot enchant a locked item.");
                    return;
                }
                setConfirmEnchantTarget(item);
            }
            return;
        }
        setSelectedItemId(item.id);
    };

    const handleOpenSellModal = () => {
        if (!currentSelectedItem || currentSelectedItem.isLocked) return;
        setSellQuantity(1);
        setIsSellModalOpen(true);
    };

    const handleConfirmBulkSell = () => {
        if (!currentSelectedItem) return;
        const sellPricePerItem = Math.floor(currentSelectedItem.baseValue * 0.5);
        const totalPrice = sellPricePerItem * sellQuantity;

        actions.sellItem(
            currentSelectedItem.id, 
            sellQuantity, 
            totalPrice, 
            currentSelectedItem.type === 'EQUIPMENT' ? currentSelectedItem.id : undefined
        );

        setIsSellModalOpen(false);
        if (currentSelectedItem.quantity <= sellQuantity) {
            setSelectedItemId(null);
        }
    };

    const handleUseScroll = () => {
        if (!currentSelectedItem || currentSelectedItem.type !== 'SKILL_SCROLL') return;
        setEnchantingScroll(currentSelectedItem);
    };

    const handleConfirmEnchant = () => {
        if (enchantingScroll && confirmEnchantTarget) {
            actions.applySkillScroll(enchantingScroll.id, confirmEnchantTarget.id);
            setEnchantingScroll(null);
            setConfirmEnchantTarget(null);
            actions.showToast("Equipment enchanted successfully!");
        }
    };

    const handleConsume = () => {
        if (!currentSelectedItem) return;
        if (currentSelectedItem.type === 'SKILL_SCROLL') {
            handleUseScroll();
            return;
        }
        actions.useItem(currentSelectedItem.id);
        if (currentSelectedItem.quantity <= 1) setSelectedItemId(null);
    };

    const getQualityLabel = (q: number): string => {
        if (q >= 110) return 'MASTERWORK';
        if (q >= 100) return 'PRISTINE';
        if (q >= 90) return 'SUPERIOR';
        if (q >= 80) return 'FINE';
        if (q >= 70) return 'STANDARD';
        if (q >= 60) return 'RUSTIC';
        return 'CRUDE';
    };

    const getRarityClasses = (rarity?: string) => {
        switch (rarity) {
            case 'Legendary': return 'text-amber-400 border-amber-500/50 bg-amber-950/40';
            case 'Epic': return 'text-purple-400 border-purple-500/50 bg-purple-950/40';
            case 'Rare': return 'text-blue-400 border-blue-500/50 bg-blue-950/40';
            case 'Uncommon': return 'text-emerald-400 border-emerald-500/50 bg-emerald-950/40';
            default: return 'text-stone-400 border-stone-700/50 bg-stone-900/40';
        }
    };

    const renderEquipmentStats = (item: InventoryItem) => {
        if (!item.equipmentData?.stats) return null;
        const s = item.equipmentData.stats;
        const isMagical = s.magicalAttack > s.physicalAttack || s.magicalDefense > s.physicalDefense;
        const atkLabel = isMagical ? "M.ATK" : "P.ATK";
        const defLabel = isMagical ? "M.DEF" : "P.DEF";
        const atkValue = isMagical ? s.magicalAttack : s.physicalAttack;
        const defValue = isMagical ? s.magicalDefense : s.physicalDefense;

        const socketedSkill = item.equipmentData.socketedSkillId ? SKILLS[item.equipmentData.socketedSkillId] : null;

        return (
            <div className="mb-4 space-y-2 shrink-0">
                <div className="grid grid-cols-2 gap-1.5">
                    <div className="flex justify-between bg-stone-900 p-1.5 rounded border border-stone-800 text-[9px] md:text-[10px]">
                        <span className="text-stone-500 uppercase flex items-center gap-1">
                            {isMagical ? <Zap className="w-2 h-2 text-blue-400" /> : <Sword className="w-2 h-2 text-stone-500" />}
                            {atkLabel}
                        </span>
                        <span className="font-mono text-stone-200 font-bold">{atkValue}</span>
                    </div>
                    <div className="flex justify-between bg-stone-900 p-1.5 rounded border border-stone-800 text-[9px] md:text-[10px]">
                        <span className="text-stone-500 uppercase flex items-center gap-1">
                            {isMagical ? <Brain className="w-2 h-2 text-purple-400" /> : <Shield className="w-2 h-2 text-stone-500" />}
                            {defLabel}
                        </span>
                        <span className="font-mono text-stone-200 font-bold">{defValue}</span>
                    </div>
                </div>
                {item.equipmentData.quality && (
                     <div className="flex justify-between bg-stone-900 p-1.5 rounded border border-stone-800 text-[9px] md:text-[10px]">
                        <span className="text-stone-500 uppercase flex items-center gap-1">
                            <Sparkles className="w-2 h-2 text-amber-500" /> Quality
                        </span>
                        <span className="font-black text-amber-500 uppercase tracking-tighter">{getQualityLabel(item.equipmentData.quality)}</span>
                    </div>
                )}
                {socketedSkill && (
                    <div className="bg-indigo-900/30 border border-indigo-500/30 p-2 rounded-lg mt-2 animate-in fade-in slide-in-from-bottom-2 duration-500">
                        <div className="flex items-center gap-2 mb-1">
                            <Wand2 className="w-3 h-3 text-indigo-400" />
                            <span className="text-[10px] font-black text-indigo-200 uppercase tracking-widest">Imbued Skill</span>
                        </div>
                        <div className="text-xs font-bold text-white">{socketedSkill.name}</div>
                        <p className="text-[9px] text-stone-400 italic leading-tight mt-1">{socketedSkill.description}</p>
                    </div>
                )}
            </div>
        );
    };

    return (
        <div className="flex flex-row h-full w-full max-w-7xl mx-auto p-2 md:p-4 gap-2 md:gap-4 overflow-hidden relative">

            {/* Storage List Section */}
            <div className="flex-[1.5] md:flex-[2.5] bg-slate-900 rounded-xl border border-slate-700 overflow-hidden flex flex-col min-w-0 relative">
                <div className={`bg-slate-800/50 p-2 md:p-3 border-b border-slate-700 flex items-center justify-between shrink-0 transition-colors duration-500 ${enchantingScroll ? 'bg-amber-900/60' : ''}`}>
                    <div className="flex items-center gap-2">
                        <Package className="w-3.5 h-3.5 md:w-4 md:h-4 text-amber-50" />
                        <h3 className="text-slate-200 text-xs md:text-sm uppercase tracking-wider font-bold">
                            {enchantingScroll ? 'Select Equipment to Imbue' : 'Storage'}
                        </h3>
                    </div>
                    {enchantingScroll ? (
                        <button onClick={() => setEnchantingScroll(null)} className="px-3 py-1 bg-red-600 hover:bg-red-500 rounded-full text-[9px] md:text-[10px] font-black uppercase text-white shadow-lg transition-all flex items-center gap-1 active:scale-95">
                            <X className="w-3 h-3" /> Cancel
                        </button>
                    ) : (
                        <span className="text-[10px] text-slate-500 font-mono">{state.inventory.length}</span>
                    )}
                </div>

                {enchantingScroll && (
                    <div className="bg-amber-600 px-3 py-1.5 border-b border-amber-400/50 text-[9px] md:text-[11px] text-white font-black uppercase tracking-widest flex items-center justify-center gap-2 animate-in slide-in-from-top-2 duration-300">
                        <Sparkles className="w-3 h-3 animate-spin-slow" />
                        Targeting: {enchantingScroll.name}
                    </div>
                )}

                <div className="p-2 overflow-y-auto flex-1 custom-scrollbar min-h-0 bg-stone-950/20">
                    {state.inventory.length === 0 ? (
                        <div className="text-slate-500 text-center py-12 italic text-xs">Empty</div>
                    ) : (
                        <div className="grid grid-cols-2 xs:grid-cols-3 sm:grid-cols-4 lg:grid-cols-5 gap-2 pb-8">
                            {state.inventory.map(item => {
                                const isSelected = selectedItemId === item.id;
                                const isEnchantTarget = enchantingScroll && item.type === 'EQUIPMENT';
                                const isEnchantRestricted = enchantingScroll && item.type !== 'EQUIPMENT';

                                return (
                                    <button
                                        key={item.id} onClick={() => handleSelect(item)}
                                        disabled={!!isEnchantRestricted}
                                        className={`relative flex flex-col items-center p-2 rounded-lg border transition-all h-20 md:h-28 justify-between ${
                                            isSelected && !enchantingScroll ? 'bg-amber-900/20 border-amber-500 shadow-md ring-1 ring-amber-500/50' : 
                                            isEnchantTarget ? 'bg-amber-500/10 border-amber-500 ring-4 ring-amber-500/40 animate-pulse shadow-[0_0_20px_rgba(245,158,11,0.3)] z-10' :
                                            isEnchantRestricted ? 'opacity-20 grayscale cursor-not-allowed border-transparent' :
                                            'bg-slate-800/50 border-slate-700/50 hover:bg-slate-800 hover:border-slate-600'
                                        }`}
                                    >
                                        <div className="absolute top-1 right-1 bg-slate-950/80 px-1 rounded text-[8px] md:text-[10px] text-slate-400 font-mono flex items-center gap-1 z-20">
                                            {item.isLocked && <Lock className="w-2 h-2 md:w-2.5 md:h-2.5 text-amber-500" />}
                                            x{item.quantity}
                                        </div>
                                        <div className="flex-1 flex items-center justify-center relative">
                                             <AdaptiveInventoryImage item={item} className="w-6 h-6 md:w-10 md:h-10 object-contain drop-shadow-lg" />
                                             <RomanTierOverlay id={item.id} />
                                        </div>
                                        <div className="text-[9px] md:text-xs text-center font-bold text-slate-300 w-full truncate px-1">{item.name}</div>
                                    </button>
                                );
                            })}
                        </div>
                    )}
                </div>
            </div>

            {/* Details Section */}
            <div className="flex-1 md:w-96 bg-black rounded-xl border border-stone-800 overflow-hidden flex flex-col min-w-0 transition-opacity duration-300" style={{ opacity: enchantingScroll ? 0.4 : 1 }}>
                <div className="bg-stone-900/50 p-2 md:p-3 border-b border-stone-800 flex items-center justify-between shrink-0">
                    <div className="flex items-center gap-2">
                        <Info className="w-3.5 h-3.5 md:w-4 md:h-4 text-stone-500" />
                        <h3 className="text-stone-400 text-[10px] md:text-xs uppercase tracking-wider font-bold">Details</h3>
                    </div>
                    {currentSelectedItem && (
                         <button 
                            onClick={() => actions.toggleLockItem(currentSelectedItem.id)}
                            className={`p-1.5 rounded-lg border transition-all ${currentSelectedItem.isLocked ? 'bg-amber-950/40 border-amber-600/50 text-amber-500' : 'bg-stone-900 border-stone-800 text-stone-600 hover:text-stone-300'}`}
                            title={currentSelectedItem.isLocked ? 'Unlock Item' : 'Lock Item'}
                         >
                            {currentSelectedItem.isLocked ? <Lock className="w-3.5 h-3.5" /> : <Unlock className="w-3.5 h-3.5" />}
                         </button>
                    )}
                </div>
                {currentSelectedItem ? (
                    <div className="flex-1 p-3 md:p-5 flex flex-col animate-in fade-in duration-300 overflow-y-auto custom-scrollbar min-h-0">
                        <div className="flex flex-col items-center text-center mb-4 shrink-0">
                            <div className={`w-12 h-12 md:w-20 md:h-20 bg-stone-900 rounded-full border-2 flex items-center justify-center mb-2 shadow-lg relative ${currentSelectedItem.equipmentData ? getRarityClasses(currentSelectedItem.equipmentData.rarity) : 'border-stone-700'}`}>
                                <AdaptiveInventoryImage item={currentSelectedItem} className="w-8 h-8 md:w-12 md:h-12 object-contain" />
                                <RomanTierOverlay id={currentSelectedItem.id} />
                                {currentSelectedItem.isLocked && (
                                    <div className="absolute -top-1 -right-1 bg-amber-600 text-white p-1 rounded-full border border-stone-900 shadow-lg z-30">
                                        <Lock className="w-2.5 h-2.5 md:w-3.5 md:h-3.5" />
                                    </div>
                                )}
                            </div>
                            <h2 className="text-sm md:text-lg font-bold text-amber-500 font-serif leading-tight">{currentSelectedItem.name}</h2>
                            <div className="flex flex-wrap items-center justify-center gap-1.5 mt-1.5">
                                <span className="text-[7px] md:text-[9px] bg-stone-800 px-1.5 py-0.5 rounded text-stone-400 font-mono uppercase border border-white/5">{currentSelectedItem.type}</span>
                                {currentSelectedItem.equipmentData && (
                                    <span className={`text-[7px] md:text-[9px] px-1.5 py-0.5 rounded font-black uppercase border leading-none shadow-sm ${getRarityClasses(currentSelectedItem.equipmentData.rarity)}`}>
                                        {currentSelectedItem.equipmentData.rarity}
                                    </span>
                                )}
                            </div>
                        </div>

                        <p className="text-stone-400 text-[10px] md:text-xs italic leading-tight text-center mb-4 px-1 shrink-0">"{currentSelectedItem.description}"</p>

                        <div className="flex-1 overflow-y-auto custom-scrollbar min-h-0 pr-1">
                            {renderEquipmentStats(currentSelectedItem)}
                        </div>

                        <div className="mt-4 space-y-2 pt-2 shrink-0">
                            {(currentSelectedItem.type === 'CONSUMABLE' || currentSelectedItem.type === 'SCROLL' || currentSelectedItem.type === 'SKILL_BOOK' || currentSelectedItem.type === 'SKILL_SCROLL') && (
                                <button onClick={handleConsume} className="w-full py-2 bg-emerald-800 hover:bg-emerald-700 text-emerald-100 rounded text-[10px] md:text-sm font-bold transition-all shadow-lg active:scale-[0.98]">
                                    {currentSelectedItem.type === 'SCROLL' ? 'Study Scroll' : 
                                     currentSelectedItem.type === 'SKILL_BOOK' ? 'Study Manual' : 
                                     currentSelectedItem.type === 'SKILL_SCROLL' ? 'Imbue Equipment' :
                                     'Use Item'}
                                </button>
                            )}
                            {currentSelectedItem.baseValue > 0 && currentSelectedItem.type !== 'KEY_ITEM' && (
                                <button 
                                    onClick={handleOpenSellModal} 
                                    disabled={currentSelectedItem.isLocked}
                                    className={`w-full py-2 rounded text-[10px] md:text-sm font-bold border transition-all ${currentSelectedItem.isLocked ? 'bg-stone-900 border-stone-800 text-stone-700 cursor-not-allowed' : 'bg-stone-800 hover:bg-red-900/30 text-stone-300 border-stone-700'}`}
                                >
                                    {currentSelectedItem.isLocked ? <span className="flex items-center justify-center gap-1"><Lock className="w-3 h-3" /> Item Locked</span> : `Sell (${Math.floor(currentSelectedItem.baseValue * 0.5)}G)`}
                                </button>
                            )}
                        </div>
                    </div>
                ) : (
                    <div className="flex-1 flex flex-col items-center justify-center text-stone-600 p-4 text-center">
                        <Package className="w-6 h-6 md:w-8 md:h-8 opacity-20 mb-2" />
                        <p className="text-[10px] md:text-xs">Select an item</p>
                    </div>
                )}
            </div>

            {/* Bulk Sell Modal */}
            {isSellModalOpen && currentSelectedItem && (
                <div className="fixed inset-0 z-[1000] flex items-center justify-center bg-black/80 backdrop-blur-md p-4 animate-in fade-in duration-200">
                    <div className="bg-stone-900 border-2 border-stone-700 rounded-3xl w-full max-w-sm overflow-hidden flex flex-col shadow-2xl animate-in zoom-in-95">
                        <div className="p-4 border-b border-stone-800 bg-stone-850 flex justify-between items-center shrink-0">
                            <h3 className="font-bold text-stone-200 font-serif uppercase tracking-widest text-sm">Sell Inventory</h3>
                            <button onClick={() => setIsSellModalOpen(false)} className="p-1.5 hover:bg-stone-800 rounded-full text-stone-500"><X className="w-5 h-5" /></button>
                        </div>

                        <div className="p-6 flex flex-col items-center gap-6">
                            <div className="flex items-center gap-4 w-full">
                                <div className="w-16 h-16 bg-stone-950 rounded-xl border border-stone-800 flex items-center justify-center shrink-0">
                                    <AdaptiveInventoryImage item={currentSelectedItem} className="w-10 h-10 object-contain" />
                                </div>
                                <div className="flex-1 min-w-0">
                                    <h4 className="text-stone-100 font-black text-sm truncate uppercase">{currentSelectedItem.name}</h4>
                                    <p className="text-stone-500 text-[10px] font-bold">Price per unit: <span className="text-amber-500">{Math.floor(currentSelectedItem.baseValue * 0.5)}G</span></p>
                                </div>
                            </div>

                            <div className="w-full bg-stone-950/50 p-4 rounded-2xl border border-stone-800 flex flex-col items-center gap-3">
                                <span className="text-[8px] font-black text-stone-600 uppercase tracking-[0.2em]">Select Quantity</span>
                                <div className="flex items-center gap-4">
                                    <button 
                                        onClick={() => setSellQuantity(Math.max(1, sellQuantity - 1))}
                                        className="w-10 h-10 bg-stone-800 hover:bg-stone-700 rounded-full flex items-center justify-center text-stone-400 transition-colors border border-stone-700"
                                    >
                                        <Minus className="w-5 h-5" />
                                    </button>
                                    <div className="flex flex-col items-center min-w-[80px]">
                                        <span className="text-3xl font-mono font-black text-stone-100 leading-none">{sellQuantity}</span>
                                        <span className="text-[10px] font-bold text-stone-600 uppercase mt-1">/ {currentSelectedItem.quantity}</span>
                                    </div>
                                    <button 
                                        onClick={() => setSellQuantity(Math.min(currentSelectedItem.quantity, sellQuantity + 1))}
                                        className="w-10 h-10 bg-stone-800 hover:bg-stone-700 rounded-full flex items-center justify-center text-stone-400 transition-colors border border-stone-700"
                                    >
                                        <Plus className="w-5 h-5" />
                                    </button>
                                </div>
                                <div className="flex gap-2 w-full mt-2">
                                    <button 
                                        onClick={() => setSellQuantity(1)}
                                        className="flex-1 py-1.5 bg-stone-900 hover:bg-stone-800 rounded-lg text-[9px] font-black text-stone-500 uppercase border border-stone-800 transition-all"
                                    >
                                        Min
                                    </button>
                                    <button 
                                        onClick={() => setSellQuantity(currentSelectedItem.quantity)}
                                        className="flex-1 py-1.5 bg-stone-900 hover:bg-stone-800 rounded-lg text-[9px] font-black text-amber-500/80 uppercase border border-stone-800 transition-all"
                                    >
                                        Max
                                    </button>
                                </div>
                            </div>

                            <div className="w-full flex justify-between items-center px-2 py-3 border-t border-stone-800">
                                <span className="text-[10px] font-black text-stone-500 uppercase tracking-widest">Total Payout</span>
                                <div className="flex items-center gap-1.5">
                                    <Coins className="w-5 h-5 text-amber-500" />
                                    <span className="text-2xl font-mono font-black text-emerald-400">
                                        {(sellQuantity * Math.floor(currentSelectedItem.baseValue * 0.5)).toLocaleString()} G
                                    </span>
                                </div>
                            </div>
                        </div>

                        <div className="p-4 bg-stone-850 border-t border-stone-800 flex gap-3">
                            <button 
                                onClick={() => setIsSellModalOpen(false)}
                                className="flex-1 py-3 bg-stone-800 hover:bg-stone-700 text-stone-400 font-black rounded-xl text-xs uppercase tracking-widest transition-all"
                            >
                                Cancel
                            </button>
                            <button 
                                onClick={handleConfirmBulkSell}
                                className="flex-[2] py-3 bg-emerald-600 hover:bg-emerald-500 text-white font-black rounded-xl text-xs uppercase tracking-widest transition-all shadow-lg shadow-emerald-900/20 border-b-4 border-emerald-800 active:translate-y-0.5"
                            >
                                Confirm Sale
                            </button>
                        </div>
                    </div>
                </div>
            )}

            {/* Enchant Confirmation Modal */}
            <ConfirmationModal 
                isOpen={!!confirmEnchantTarget}
                title="Apply Skill Scroll"
                message={`Do you want to imbue ${confirmEnchantTarget?.name} with ${enchantingScroll?.skillId ? SKILLS[enchantingScroll.skillId]?.name : 'this skill'}? This scroll will be consumed to permanently add an ability to the gear.`}
                confirmLabel="Confirm Imbuement"
                cancelLabel="Cancel"
                onConfirm={handleConfirmEnchant}
                onCancel={() => setConfirmEnchantTarget(null)}
            />
        </div>
    );
};

import React, { useState, useMemo } from 'react';
import { 
  Box, Sword, Shield, Sparkles, FlaskConical, Package, 
  ChevronRight, AlertCircle, Check, X, BookOpen 
} from 'lucide-react';
import { InventoryItem, EquipmentSlotType } from '../../types/inventory';
import { Mercenary } from '../../models/Mercenary';
import { PrimaryStats, mergePrimaryStats } from '../../models/Stats';
import { getAssetUrl } from '../../utils';
import { SfxButton } from '../common/ui/SfxButton';

type CategoryFilter = 'ALL' | 'WEAPON' | 'ARMOR' | 'ACCESSORY' | 'CONSUMABLE' | 'SKILL';

interface EquipmentInventoryListProps {
  inventory: InventoryItem[];
  selectedItemId: string | null;
  onSelect: (itemId: string) => void;
  onEquip: (itemId: string) => void;
  onConsume: (itemId: string) => void;
  selectedSlotFilter: EquipmentSlotType | null;
  mercenary: Mercenary;
  isReadOnly?: boolean;
  onToggleInventory: () => void;
}

const getRarityClasses = (rarity?: string) => {
  switch (rarity) {
    case 'Legendary':
      return 'text-amber-400 border-amber-500/50 bg-amber-950/40';
    case 'Epic':
      return 'text-purple-400 border-purple-500/50 bg-purple-950/40';
    case 'Rare':
      return 'text-blue-400 border-blue-500/50 bg-blue-950/40';
    case 'Uncommon':
      return 'text-emerald-400 border-emerald-500/50 bg-emerald-950/40';
    default:
      return 'text-stone-400 border-stone-700/50 bg-stone-900/40';
  }
};

const getQualityLabel = (q: number): string => {
  if (q >= 110) return 'MASTERWORK';
  if (q >= 100) return 'PRISTINE';
  if (q >= 90) return 'SUPERIOR';
  if (q >= 80) return 'FINE';
  if (q >= 70) return 'STANDARD';
  if (q >= 60) return 'RUSTIC';
  return 'CRUDE';
};

export const EquipmentInventoryList: React.FC<EquipmentInventoryListProps> = ({
  inventory,
  selectedItemId,
  onSelect,
  onEquip,
  onConsume,
  selectedSlotFilter,
  mercenary,
  isReadOnly,
  onToggleInventory,
}) => {
  const [activeFilter, setActiveFilter] = useState<CategoryFilter>('ALL');

  const displayInventory = useMemo(() => {
    let filtered = inventory;

    if (selectedSlotFilter) {
      return filtered.filter((item) => item.equipmentData?.slotType === selectedSlotFilter);
    }

    if (activeFilter === 'WEAPON') {
      return filtered.filter((item) => item.equipmentData?.slotType === 'MAIN_HAND');
    }
    if (activeFilter === 'ARMOR') {
      return filtered.filter((item) => 
        ['HEAD', 'BODY', 'LEGS', 'HANDS', 'FEET', 'OFF_HAND'].includes(item.equipmentData?.slotType || '')
      );
    }
    if (activeFilter === 'ACCESSORY') {
      return filtered.filter((item) => ['ACCESSORY', 'WAIST'].includes(item.equipmentData?.slotType || ''));
    }
    if (activeFilter === 'CONSUMABLE') {
      return filtered.filter((item) => item.type === 'CONSUMABLE' || item.type === 'SKILL_BOOK');
    }
    if (activeFilter === 'SKILL') {
      return filtered.filter((item) => item.type === 'SKILL_BOOK');
    }

    return filtered;
  }, [inventory, selectedSlotFilter, activeFilter]);

  const filterChips: { id: CategoryFilter; label: string; icon: React.ReactNode }[] = [
    { id: 'ALL', label: 'All', icon: <Box className="w-3 h-3" /> },
    { id: 'WEAPON', label: 'Weapons', icon: <Sword className="w-3 h-3" /> },
    { id: 'ARMOR', label: 'Armor', icon: <Shield className="w-3 h-3" /> },
    { id: 'ACCESSORY', label: 'Accessory', icon: <Sparkles className="w-3 h-3" /> },
    { id: 'CONSUMABLE', label: 'Items', icon: <FlaskConical className="w-3 h-3" /> },
    { id: 'SKILL', label: 'Manuals', icon: <BookOpen className="w-3 h-3" /> },
  ];

  return (
    <div className="flex-1 flex flex-col min-h-0">
      <div 
        onClick={onToggleInventory}
        className="p-4 md:p-6 bg-stone-950 border-b border-white/5 flex justify-between items-center shrink-0 z-10 backdrop-blur-md cursor-pointer hover:bg-stone-900 transition-colors group"
      >
        <div className="flex flex-col">
            <h3 className="text-[10px] md:text-sm font-black text-stone-100 uppercase tracking-widest flex items-center gap-2 group-hover:text-amber-500 transition-colors">
            <Package className="w-4 h-4 text-amber-600" />
            <span>{selectedSlotFilter ? `Filtering: ${selectedSlotFilter}` : 'Squad Inventory'}</span>
            </h3>
            <span className="text-[7px] md:text-[10px] text-stone-500 font-mono mt-0.5 uppercase">Click Header to Close</span>
        </div>
        <div className="flex items-center gap-3">
          <span className="text-[8px] md:text-xs text-stone-600 font-mono bg-stone-900 px-2 py-0.5 rounded border border-stone-800">{displayInventory.length} ITEMS</span>
          <ChevronRight className="w-4 h-4 text-stone-700 group-hover:text-amber-500 group-hover:translate-x-0.5 transition-all" />
        </div>
      </div>

      {!selectedSlotFilter && (
        <div className="px-3 md:px-6 py-2 md:py-3 bg-stone-950/40 border-b border-white/5 flex gap-2 overflow-x-auto no-scrollbar shrink-0">
          {filterChips.map((chip) => (
            <SfxButton
              key={chip.id}
              sfx="switch"
              onClick={() => setActiveFilter(chip.id)}
              className={`flex items-center gap-1.5 px-3 py-1.5 rounded-full border text-[9px] md:text-[10px] font-black uppercase tracking-tighter transition-all whitespace-nowrap ${
                activeFilter === chip.id
                  ? 'bg-amber-600 border-amber-400 text-white shadow-glow-sm'
                  : 'bg-stone-800 border-stone-700 text-stone-500 hover:text-stone-300'
              }`}
            >
              {chip.icon}
              {chip.label}
            </SfxButton>
          ))}
        </div>
      )}

      <div className="flex-1 overflow-y-auto custom-scrollbar p-3 md:p-6 space-y-2 md:space-y-3">
        {displayInventory.length === 0 ? (
          <div className="h-full flex flex-col items-center justify-center text-stone-800 italic p-12 text-center bg-stone-950/20 m-4 rounded-xl border-2 border-dashed border-stone-800">
            <Box className="w-12 h-12 opacity-10 mb-2" />
            <p className="text-xs">No suitable items found.</p>
            {selectedSlotFilter && (
              <SfxButton 
                sfx="switch"
                onClick={onToggleInventory}
                className="mt-4 px-4 py-2 bg-stone-800 text-stone-400 rounded-lg text-[10px] uppercase font-bold hover:text-stone-200"
              >
                Back to View All
              </SfxButton>
            )}
          </div>
        ) : (
          displayInventory.map((item) => {
            const isConsumable = item.type === 'CONSUMABLE' || item.type === 'SKILL_BOOK';
            const isSkillBook = item.type === 'SKILL_BOOK';
            const isSkillScroll = item.type === 'SKILL_SCROLL';
            const isSelected = selectedItemId === item.id;

            const minLevel = item.equipmentData?.minLevel || 1;
            const canEquip = isConsumable || (mercenary.level >= minLevel);

            const rarityClasses = (isConsumable || isSkillScroll) ? 'text-stone-400 border-stone-700 bg-stone-900/40' : getRarityClasses(item.equipmentData?.rarity);

            // Fix: Identify skill folder correctly
            const isSkillAny = isSkillBook || isSkillScroll;
            const folder = isSkillAny ? 'skills' : (item.type === 'EQUIPMENT' ? 'equipments' : 'materials');
            const targetFile = item.image || (item.type === 'EQUIPMENT' && item.equipmentData?.recipeId ? `${item.equipmentData.recipeId}.png` : `${item.id}.png`);
            const imageUrl = getAssetUrl(targetFile, folder);

            return (
              <div
                key={item.id}
                onClick={() => !isSelected && onSelect(item.id)}
                className={`flex flex-col gap-2 p-3 md:p-5 rounded-xl border transition-all ${
                  isSelected ? 'border-amber-500 bg-stone-900/80 shadow-inner' : 'border-stone-800 bg-stone-900/30'
                } cursor-pointer group relative overflow-hidden ${!isConsumable && !canEquip ? 'opacity-60' : ''}`}
              >
                <div className="flex items-center gap-3 md:gap-4">
                  <div className={`w-10 h-10 md:w-16 md:h-16 bg-stone-950 rounded-lg border-2 flex items-center justify-center shrink-0 ${rarityClasses}`}>
                    <img src={imageUrl} className="w-8 h-8 md:w-12 md:h-12 object-contain" alt={item.name} />
                  </div>

                  <div className="flex-1 min-w-0">
                    <div className="text-[11px] md:text-lg font-black truncate text-stone-200">{item.name}</div>
                    <div className="flex wrap items-center gap-2 mt-1">
                      <span className={`text-[7px] md:text-[9px] px-1.5 py-0.5 rounded font-black uppercase border leading-none ${rarityClasses}`}>
                        {isSkillBook ? 'MANUAL' : isSkillScroll ? 'SCROLL' : isConsumable ? 'CONSUMABLE' : item.equipmentData?.rarity}
                      </span>
                      {item.quantity > 1 && (
                        <span className="text-[7px] md:text-[9px] text-stone-500 font-mono font-bold">
                          QTY: {item.quantity}
                        </span>
                      )}
                    </div>
                  </div>

                  {!isReadOnly && isSelected && !isConsumable && canEquip && (
                    <SfxButton
                      onClick={(e) => {
                        e.stopPropagation();
                        onEquip(item.id);
                      }}
                      className="shrink-0 px-3 md:px-8 py-1.5 md:py-3 bg-amber-700 hover:bg-amber-600 text-white text-[9px] md:text-xs font-black uppercase rounded shadow-lg transition-all"
                    >
                      Equip
                    </SfxButton>
                  )}

                  {!isReadOnly && isSelected && isConsumable && (
                    <div className="absolute top-0 right-0 h-full w-24 md:w-32 bg-stone-900/95 border-l border-amber-600/30 flex flex-col animate-in slide-in-from-right-full duration-200 z-30">
                        <SfxButton 
                            onClick={(e) => { e.stopPropagation(); onConsume(item.id); }}
                            className="flex-1 flex flex-col items-center justify-center gap-1 hover:bg-emerald-900/40 text-emerald-400 transition-colors"
                        >
                            <Check className="w-4 h-4" />
                            <span className="text-[8px] md:text-[10px] font-black uppercase">{isSkillBook ? 'Study Manual' : 'Consume'}</span>
                        </SfxButton>
                        <div className="h-px w-full bg-amber-600/10" />
                        <SfxButton 
                            sfx="switch"
                            onClick={(e) => { e.stopPropagation(); onSelect(""); }}
                            className="flex-1 flex flex-col items-center justify-center gap-1 hover:bg-red-900/40 text-stone-500 hover:text-red-400 transition-colors"
                        >
                            <X className="w-4 h-4" />
                            <span className="text-[8px] md:text-[10px] font-black uppercase">Cancel</span>
                        </SfxButton>
                    </div>
                  )}
                </div>

                {!isConsumable && !canEquip && isSelected && (
                  <div className="bg-red-950/20 border border-red-900/30 rounded-lg p-2 flex items-center gap-2 text-[8px] md:text-[10px] text-red-400 font-bold uppercase tracking-tight">
                    <AlertCircle className="w-3 h-3 shrink-0" />
                    Requires Level {minLevel} (Current: {mercenary.level})
                  </div>
                )}

                <div className="flex justify-between items-center border-t border-white/5 pt-2">
                   <div className="flex items-center gap-2">
                        {isConsumable ? (
                             <span className="text-[7px] md:text-[9px] text-stone-500 italic truncate max-w-[150px]">
                                {item.description}
                             </span>
                        ) : (
                            <div className="flex items-center gap-2">
                                <span className="text-[7px] md:text-[9px] text-amber-600 font-black uppercase tracking-tighter bg-amber-950/20 px-1.5 py-0.5 rounded border border-amber-900/20">
                                {getQualityLabel(item.equipmentData?.quality || 100)}
                                </span>
                                <span className={`text-[7px] md:text-[9px] font-black uppercase px-1.5 py-0.5 rounded border ${mercenary.level >= minLevel ? 'text-stone-500 border-stone-800' : 'text-red-500 border-red-900/30 bg-red-900/10'}`}>
                                    Req. Lv.{minLevel}
                                </span>
                            </div>
                        )}
                    </div>
                    {!isConsumable && item.equipmentData && (
                        <div className="flex items-center gap-2 text-[8px] md:xs text-stone-600 font-mono">
                            {(item.equipmentData.stats.physicalAttack > 0 || item.equipmentData.stats.magicalAttack > 0) && (
                                <span className="flex items-center gap-1"><Sword className="w-2.5 h-2.5" /> {item.equipmentData.stats.physicalAttack || item.equipmentData.stats.magicalAttack}</span>
                            )}
                            {(item.equipmentData.stats.physicalDefense > 0 || item.equipmentData.stats.magicalDefense > 0) && (
                                <span className="flex items-center gap-1"><Shield className="w-2.5 h-2.5" /> {item.equipmentData.stats.physicalDefense || item.equipmentData.stats.magicalDefense}</span>
                            )}
                        </div>
                    )}
                </div>
              </div>
            );
          })
        )}
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import { Shield, Sword, Activity, Skull, Zap, LogOut, FastForward, Pause, Play, ChevronDown, ChevronUp, Sparkles, Target, Package, X, Check, RotateCcw, Wand2, ChevronRight, Heart } from 'lucide-react';
import { Mercenary } from '../../../models/Mercenary';
import { Monster } from '../../../models/Monster';
import { ManualDungeonSession } from '../../../types/game-state';
import { calculateCombatResult } from '../../../utils/combatLogic';
import { calculateDerivedStats, applyEquipmentBonuses, mergePrimaryStats } from '../../../models/Stats';
import { useGame } from '../../../context/GameContext';
import { SKILLS } from '../../../data/skills';
import { MercenaryPortrait } from '../../common/ui/MercenaryPortrait';
import { getAssetUrl } from '../../../utils';
import { InventoryItem, EquipmentSlotType } from '../../../types/inventory';
import { MercenaryDetailModal } from '../../modals/MercenaryDetailModal';
import { DUNGEONS } from '../../../data/dungeons';
import { SfxButton } from '../../common/ui/SfxButton';

const ACTION_THRESHOLD = 1000;

interface CombatLogEntry {
    msg: string;
    team: 'PLAYER' | 'ENEMY' | 'SYSTEM';
    isCrit?: boolean;
    isSkill?: boolean;
    isHeal?: boolean;
}

interface DamagePopup {
    id: number;
    value: number;
    targetId: string;
    isCrit: boolean;
    isSkill: boolean;
    isHeal?: boolean;
}

interface DungeonCombatViewProps {
    session: ManualDungeonSession;
    party: Mercenary[];
    enemies: Monster[];
    fleeChance: number;
    onFinish: (win: boolean, finalParty: any[]) => void;
    onFlee: (finalParty: any[]) => void;
}

const DungeonCombatView: React.FC<DungeonCombatViewProps> = ({ session, party, enemies, fleeChance, onFinish, onFlee }) => {
    const { state, actions } = useGame();
    const [orientation, setOrientation] = useState<'PORTRAIT' | 'LANDSCAPE'>(
        window.innerWidth > window.innerHeight ? 'LANDSCAPE' : 'PORTRAIT'
    );

    const dungeonInfo = useMemo(() => DUNGEONS.find(d => d.id === session.dungeonId), [session.dungeonId]);

    const [partyState, setPartyState] = useState(party.map(m => {
        const primary = mergePrimaryStats(m.stats, m.allocatedStats);
        const derived = applyEquipmentBonuses(calculateDerivedStats(primary, m.level), (Object.values(m.equipment) as any[]).map(e=>e?.stats).filter(Boolean) as any);
        return { ...m, derived, currentHp: m.currentHp, currentMp: m.currentMp, gauge: 0, lastDamaged: false };
    }));

    const [enemySquadState, setEnemySquadState] = useState(enemies.map((e, idx) => ({
        ...e,
        instanceId: `enemy_${idx}`,
        gauge: 0,
        lastDamaged: false,
        hasUsedRevival: false
    })));

    const [logs, setLogs] = useState<CombatLogEntry[]>([]);
    const [damagePopups, setDamagePopups] = useState<DamagePopup[]>([]);

    const [isAuto, setIsAuto] = useState(() => {
        const saved = localStorage.getItem('dungeon_combat_auto');
        return saved === null ? true : saved === 'true';
    });

    const [battleSpeed, setBattleSpeed] = useState<1 | 2 | 4>(() => {
        const saved = localStorage.getItem('dungeon_combat_speed');
        const parsed = saved ? parseInt(saved) : 1; 
        if (parsed === 1 || parsed === 2 || parsed === 4) return parsed as 1 | 2 | 4;
        return 1;
    });

    useEffect(() => {
        localStorage.setItem('dungeon_combat_auto', isAuto.toString());
    }, [isAuto]);

    useEffect(() => {
        localStorage.setItem('dungeon_combat_speed', battleSpeed.toString());
    }, [battleSpeed]);

    const [isPaused, setIsPaused] = useState(false);
    const [activeActorId, setActiveActorId] = useState<string | null>(null); 
    const [attackingUnitId, setAttackingUnitId] = useState<string | null>(null);
    const [showLogs, setShowLogs] = useState(false);
    const [showSkillList, setShowSkillList] = useState(false);

    const [pendingAction, setPendingAction] = useState<{ type: 'ATTACK' | 'SKILL', skillId?: string } | null>(null);
    const [inspectedMercId, setInspectedMercId] = useState<string | null>(null);

    const battleInterval = useRef<ReturnType<typeof setInterval> | null>(null);
    const speedRef = useRef(1);

    useEffect(() => {
        speedRef.current = battleSpeed;
    }, [battleSpeed]);

    useEffect(() => {
        const handleResize = () => {
            setOrientation(window.innerWidth > window.innerHeight ? 'LANDSCAPE' : 'PORTRAIT');
        };
        window.addEventListener('resize', handleResize);
        return () => window.removeEventListener('resize', handleResize);
    }, []);

    const addLog = useCallback((msg: string, team: 'PLAYER' | 'ENEMY' | 'SYSTEM', isCrit = false, isSkill = false, isHeal = false) => {
        setLogs(prev => [{ msg, team, isCrit, isSkill, isHeal }, ...prev].slice(0, 50));
    }, []);

    const triggerDamagePopup = useCallback((targetId: string, value: number, isCrit: boolean, isSkill: boolean, isHeal = false) => {
        const id = Date.now() + Math.random();
        setDamagePopups(prev => [...prev, { id, value, targetId, isCrit, isSkill, isHeal }]);
        setTimeout(() => {
            setDamagePopups(prev => prev.filter(p => p.id !== id));
        }, 800 / speedRef.current);
    }, []);

    /**
     * executeAction: 전투의 핵심 Use Case 처리기
     * 스킬의 태그에 따른 동작 정의(Use Case)를 타겟에 적용합니다.
     */
    const executeAction = useCallback((attacker: any, target: any, isPlayerSide: boolean, skillId?: string) => {
        if (!attacker || !target) return;

        // 공격자 식별 아이디 (연출용)
        setAttackingUnitId(isPlayerSide ? attacker.id : attacker.instanceId);

        setTimeout(() => {
            const skill = skillId ? SKILLS[skillId] : null;
            const multiplier = skill?.multiplier ?? 1.0; 
            const mpCost = skill?.mpCost ?? 0;
            const isHealUseCase = skill?.tags.includes('HEAL') || false;

            // USE CASE: HEALING
            if (isHealUseCase) {
                const baseHeal = Math.round((attacker.derived?.magicalAttack || attacker.stats.magicalAttack || 10) * multiplier);
                const isCrit = Math.random() * 100 <= (attacker.derived?.critChance || 0);
                const finalHeal = isCrit ? Math.round(baseHeal * 1.5) : baseHeal;

                window.dispatchEvent(new CustomEvent('play-sfx', { detail: { file: 'click_light.wav' } }));

                if (isPlayerSide) {
                    setPartyState(prev => prev.map(p => {
                        if (p.id === target.id) {
                            const nextHp = Math.min(p.derived.maxHp, p.currentHp + finalHeal);
                            triggerDamagePopup(p.id, finalHeal, isCrit, true, true);
                            return { ...p, currentHp: nextHp };
                        }
                        if (p.id === attacker.id) {
                            return { ...p, currentMp: Math.max(0, p.currentMp - mpCost) };
                        }
                        return p;
                    }));
                    addLog(`${attacker.name} used ${skill!.name} on ${target.name} for ${finalHeal} HP!`, 'PLAYER', isCrit, true, true);
                } else {
                    setEnemySquadState(prev => prev.map(e => {
                        if (e.instanceId === target.instanceId) {
                            const nextHp = Math.min(e.stats.maxHp, e.currentHp + finalHeal);
                            triggerDamagePopup(e.instanceId, finalHeal, isCrit, true, true);
                            return { ...e, currentHp: nextHp };
                        }
                        return e;
                    }));
                    addLog(`${attacker.name} healed ${target.name} for ${finalHeal}!`, 'ENEMY', isCrit, true, true);
                }
            } 
            // USE CASE: DAMAGE (Standard Strike or Attack Skill)
            else {
                const res = calculateCombatResult(
                    isPlayerSide ? attacker.derived : attacker.stats,
                    isPlayerSide ? target.stats : target.derived,
                    isPlayerSide ? attacker.job : 'Fighter' as any,
                    isPlayerSide ? (attacker.derived.magicalAttack > attacker.derived.physicalAttack ? 'MAGICAL' : 'PHYSICAL') : 'PHYSICAL',
                    multiplier
                );

                if (res.isHit) {
                    window.dispatchEvent(new CustomEvent('play-sfx', { detail: { file: 'battle_slash.mp3' } }));
                } else {
                    window.dispatchEvent(new CustomEvent('play-sfx', { detail: { file: 'swing_miss.mp3' } }));
                }

                if (isPlayerSide) {
                    setEnemySquadState(prev => prev.map(e => {
                        if (e.instanceId === target.instanceId) {
                            const next = { ...e, lastDamaged: res.isHit };
                            if (res.isHit) {
                                let nextHp = Math.max(0, next.currentHp - res.damage);
                                // Boss Phoenix Special Mechanic
                                if (nextHp <= 0 && next.id === 'phoenix' && !next.hasUsedRevival) {
                                    nextHp = next.stats.maxHp;
                                    next.hasUsedRevival = true;
                                    addLog("Phoenix rebirth triggered!", 'ENEMY', true, true);
                                    triggerDamagePopup(target.instanceId, 0, true, true);
                                } else {
                                    next.currentHp = nextHp;
                                }
                                triggerDamagePopup(target.instanceId, res.damage, res.isCrit, !!skill);
                            }
                            setTimeout(() => setEnemySquadState(curr => curr.map(currE => currE.instanceId === target.instanceId ? { ...currE, lastDamaged: false } : currE)), 200 / speedRef.current);
                            return next;
                        }
                        return e;
                    }));

                    setPartyState(prev => prev.map(p => p.id === attacker.id ? { ...p, currentMp: Math.max(0, p.currentMp - mpCost) } : p));

                    if (skill) {
                        addLog(`${attacker.name} used ${skill.name}!`, 'PLAYER', res.isCrit, true);
                    } else {
                        addLog(`${attacker.name} hits ${target.name} for ${res.damage}`, 'PLAYER', res.isCrit);
                    }
                } else {
                    setPartyState(prev => prev.map(p => {
                        if (p.id === target.id) {
                            const next = { ...p, lastDamaged: res.isHit };
                            if (res.isHit) {
                                next.currentHp = Math.max(0, next.currentHp - res.damage);
                                triggerDamagePopup(p.id, res.damage, res.isCrit, false);
                            }
                            setTimeout(() => setPartyState(curr => curr.map(c => c.id === p.id ? { ...c, lastDamaged: false } : c)), 200 / speedRef.current);
                            return next;
                        }
                        return p;
                    }));
                    addLog(`${attacker.name} strikes ${target.name} for ${res.damage}`, 'ENEMY');
                }
            }

            setTimeout(() => setAttackingUnitId(null), 150 / speedRef.current);
        }, 200 / speedRef.current);
    }, [addLog, triggerDamagePopup]);

    const processLoop = useCallback(() => {
        if (isPaused || activeActorId || attackingUnitId || inspectedMercId) {
            // Auto-transition logic: if isAuto is enabled while activeActorId is set, clear activeActorId and let AI act.
            if (isAuto && activeActorId && !attackingUnitId) {
                setActiveActorId(null);
                setPendingAction(null);
            }
            return;
        }

        const enemiesDefeated = enemySquadState.every(e => e.currentHp <= 0);
        const partyDefeated = partyState.every(p => p.currentHp <= 0);

        if (enemiesDefeated) {
            setIsPaused(true);
            setTimeout(() => onFinish(true, partyState), 800 / speedRef.current);
            return;
        }
        if (partyDefeated) {
            setIsPaused(true);
            setTimeout(() => onFinish(false, partyState), 800 / speedRef.current);
            return;
        }

        setPartyState(prev => {
            const next = [...prev];
            let readyMerc = null;
            for (let p of next) {
                if (p.currentHp > 0) {
                    p.gauge += (p.derived.speed * 0.2 * speedRef.current); 
                    if (p.gauge >= ACTION_THRESHOLD && !readyMerc) readyMerc = p;
                }
            }
            if (readyMerc && !attackingUnitId) {
                if (isAuto) {
                    readyMerc.gauge -= ACTION_THRESHOLD;
                    const livingEnemies = enemySquadState.filter(e => e.currentHp > 0);
                    const livingAllies = next.filter(p => p.currentHp > 0);

                    const availableSkillIds = [
                        ...(readyMerc.skillIds || []),
                        ...Object.values(readyMerc.equipment || {}).map(i => (i as any)?.socketedSkillId).filter(Boolean) as string[]
                    ];

                    let sid = undefined;
                    let target: any = livingEnemies[Math.floor(Math.random() * livingEnemies.length)];

                    if (availableSkillIds.length > 0) {
                        const skillId = availableSkillIds[0];
                        const skill = SKILLS[skillId];
                        if (skill && readyMerc.currentMp >= (skill.mpCost ?? 0) && Math.random() < 0.3) {
                            sid = skillId;
                            if (skill.tags.includes('HEAL')) {
                                target = [...livingAllies].sort((a,b) => (a.currentHp/a.derived.maxHp) - (b.currentHp/b.derived.maxHp))[0];
                            }
                        }
                    }
                    executeAction(readyMerc, target, true, sid);
                } else {
                    setActiveActorId(readyMerc.id);
                    setShowSkillList(false);
                    setPendingAction(null);
                }
            }
            return next;
        });

        setEnemySquadState(prev => {
            const next = [...prev];
            let readyEnemy = null;
            for (let e of next) {
                if (e.currentHp > 0) {
                    e.gauge += (e.stats.speed * 0.2 * speedRef.current); 
                    if (e.gauge >= ACTION_THRESHOLD && !readyEnemy) readyEnemy = e;
                }
            }
            if (readyEnemy && !activeActorId && !attackingUnitId) {
                readyEnemy.gauge -= ACTION_THRESHOLD;
                const livingPlayers = partyState.filter(p => p.currentHp > 0);
                if (livingPlayers.length > 0) {
                    const target = livingPlayers[Math.floor(Math.random() * livingPlayers.length)];
                    executeAction(readyEnemy, target, false);
                }
            }
            return next;
        });
    }, [isPaused, isAuto, activeActorId, attackingUnitId, inspectedMercId, enemySquadState, partyState, executeAction, onFinish]);

    useEffect(() => {
        battleInterval.current = setInterval(processLoop, 100);
        return () => { if (battleInterval.current) clearInterval(battleInterval.current); };
    }, [processLoop]);

    const handleTurnConsumed = useCallback((targetMercId: string) => {
        setTimeout(() => {
            const updatedMercFromContext = state.knownMercenaries.find(m => m.id === targetMercId);
            if (updatedMercFromContext) {
                setPartyState(prev => prev.map(p => {
                    if (p.id === targetMercId) {
                        const primary = mergePrimaryStats(updatedMercFromContext.stats, updatedMercFromContext.allocatedStats);
                        const derived = applyEquipmentBonuses(
                            calculateDerivedStats(primary, updatedMercFromContext.level), 
                            (Object.values(updatedMercFromContext.equipment) as any[]).map(e=>e?.stats).filter(Boolean) as any
                        );
                        return { 
                            ...p, 
                            ...updatedMercFromContext, 
                            derived,
                            currentHp: updatedMercFromContext.currentHp,
                            currentMp: updatedMercFromContext.currentMp,
                            gauge: Math.max(0, p.gauge - ACTION_THRESHOLD),
                            lastDamaged: false 
                        };
                    }
                    return p;
                }));
                setInspectedMercId(null);
                setActiveActorId(null);
            }
        }, 50);
    }, [state.knownMercenaries]);

    const handleManualAction = (e: React.MouseEvent, type: 'ATTACK' | 'SKILL', skillId?: string) => {
        e.stopPropagation(); 
        if (!activeActorId) return;

        if (type === 'SKILL' && !skillId) {
            setShowSkillList(true);
            return;
        }

        if (type === 'SKILL' && skillId) {
            const skill = SKILLS[skillId];
            const actor = partyState.find(p => p.id === activeActorId);
            if (!actor || actor.currentMp < (skill?.mpCost ?? 0)) {
                actions.showToast("Not enough MP!");
                return;
            }
            setShowSkillList(false);
        }

        setPendingAction({ type, skillId });
    };

    const handleTargetClick = (target: any, side: 'PLAYER' | 'ENEMY') => {
        if (!activeActorId || !pendingAction) return;
        if (target.currentHp <= 0 && side === 'ENEMY') return;

        const skill = pendingAction.skillId ? SKILLS[pendingAction.skillId] : null;
        const isSupportive = skill?.tags.includes('HEAL') || skill?.tags.includes('BUFF');

        if (!isSupportive && side === 'PLAYER' && pendingAction.type === 'ATTACK') return;
        if (!isSupportive && side === 'PLAYER' && skill && !skill.tags.includes('DAMAGE')) return;
        if (isSupportive && side === 'ENEMY') return;

        const actor = partyState.find(p => p.id === activeActorId);
        if (!actor) return;

        setPartyState(prev => prev.map(p => p.id === activeActorId ? { ...p, gauge: p.gauge - ACTION_THRESHOLD } : p));
        executeAction(actor, target, true, pendingAction.skillId);
        setPendingAction(null);
        setActiveActorId(null);
    };

    const handleFlee = (e: React.MouseEvent) => {
        e.stopPropagation();
        if (Math.random() * 100 < fleeChance) {
            onFlee(partyState);
        } else {
            addLog("Escape failed!", 'SYSTEM');
            setActiveActorId(null);
            setPendingAction(null);
            const actor = partyState.find(p => p.id === activeActorId);
            if (actor) {
                setPartyState(prev => prev.map(p => p.id === actor.id ? { ...p, gauge: 0 } : p));
            }
        }
    };

    const getUnitStyle = (id: string, side: 'PLAYER' | 'ENEMY'): React.CSSProperties => {
        if (attackingUnitId !== id) return {};
        let transform = orientation === 'PORTRAIT' 
            ? (side === 'PLAYER' ? 'translateY(-120px) scale(1.1)' : 'translateY(120px) scale(1.1)')
            : (side === 'PLAYER' ? 'translateX(120px) scale(1.1)' : 'translateX(-120px) scale(1.1)');
        return { transform, zIndex: 100 };
    };

    const activeActor = useMemo(() => partyState.find(p => p.id === activeActorId), [partyState, activeActorId]);

    const activeActorSkills = useMemo(() => {
        if (!activeActor) return [];
        const learned = (activeActor.skillIds || []).map(id => ({ id, source: 'LEARNED' }));
        const fromGear = Object.values(activeActor.equipment || {}).map(i => (i as any)?.socketedSkillId).filter(Boolean).map(id => ({ id, source: 'GEAR' }));
        return [...learned, ...fromGear as any];
    }, [activeActor]);

    const isSupportiveAction = useMemo(() => {
        if (!pendingAction || pendingAction.type === 'ATTACK') return false;
        if (!pendingAction.skillId) return false;
        const skill = SKILLS[pendingAction.skillId];
        return skill.tags.includes('HEAL') || skill.tags.includes('BUFF');
    }, [pendingAction]);

    return (
        <div className="fixed inset-0 z-[150] flex flex-col bg-stone-950 animate-in fade-in duration-500 overflow-hidden font-sans pb-safe">
            <style>{`
                @keyframes damage-float { 0% { transform: translateY(0); opacity: 1; } 100% { transform: translateY(-60px); opacity: 0; } }
                .animate-damage { animation: damage-float 1s ease-out forwards; }
                @keyframes heal-float { 0% { transform: translateY(0); opacity: 1; } 100% { transform: translateY(-60px); opacity: 0; } }
                .animate-heal { animation: heal-float 1s ease-out forwards; }
                @keyframes unit-shake { 0%, 100% { transform: translate(0,0); } 25% { transform: translate(-4px, 2px); } 50% { transform: translate(4px, -2px); } 75% { transform: translate(-2px, -4px); } }
                .animate-hit { animation: unit-shake 0.2s ease-in-out 3; }
                @keyframes target-pulse { 0% { transform: scale(1); box-shadow: 0 0 0 0 rgba(239, 68, 68, 0.7); } 70% { transform: scale(1.05); box-shadow: 0 0 0 10px rgba(239, 68, 68, 0); } 100% { transform: scale(1); } }
                .animate-target { animation: target-pulse 1.5s infinite; }
                @keyframes heal-target-pulse { 0% { transform: scale(1); box-shadow: 0 0 0 0 rgba(34, 197, 94, 0.7); } 70% { transform: scale(1.05); box-shadow: 0 0 0 10px rgba(34, 197, 94, 0); } 100% { transform: scale(1); } }
                .animate-heal-target { animation: heal-target-pulse 1.5s infinite; }
            `}</style>

            {/* Background Tile Layer */}
            {dungeonInfo?.tile && (
                <div className="absolute inset-0 z-0 overflow-hidden pointer-events-none">
                    <img 
                        src={getAssetUrl(dungeonInfo.tile, 'dungeons')} 
                        className="w-full h-full object-cover opacity-60 brightness-[0.6]" 
                        alt="Combat Background" 
                    />
                </div>
            )}

            {/* Top Bar */}
            <div className="p-3 bg-red-950/20 border-b border-red-900/30 flex justify-between items-center z-[200] backdrop-blur-sm">
                <div className="flex items-center gap-2">
                    <Skull className="w-4 h-4 text-red-50" />
                    <h2 className="text-white font-black uppercase text-[10px] md:text-sm tracking-widest font-mono">Combat Zone</h2>
                </div>
                <div className="flex items-center gap-3 bg-black/40 px-3 py-1 rounded-full border border-white/5">
                    <SfxButton sfx="switch" onClick={() => setIsPaused(!isPaused)} className={`p-1.5 rounded-full transition-all ${isPaused ? 'bg-amber-600 text-white' : 'bg-stone-800 text-stone-400'}`}>
                        {isPaused ? <Play size={14} /> : <Pause size={14} />}
